/* 版本比较 */
function versionCmp(verLeft, verRight)
{
    var verLeftList = verLeft.split('.');
    var verRightList = verRight.split('.');
    var length = Math.min(verLeftList.length, verRightList.length);
    var verLeftItem;
    var verRightItem;

    if (verLeft === "" && verRight === "") {
        return 0;
    } else if (verLeft === "") {
        return -1;
    } else if (verRight === "") {
        return 1;
    }

    for (var i = 0; i < length; i++) {
        verLeftItem = parseInt(verLeftList[i]);
        verRightItem = parseInt(verRightList[i]);
        if (!isNaN(verLeftItem) && !isNaN(verRightItem)) {
            if (verLeftItem > verRightItem) {
                return 1;
            } else if (verLeftItem < verRightItem) {
                return -1;
            }
        } else {
            break;
        }
    }

    return 0;
}

/* 更新当前A2B预设源配置 */
function refreshCurrentA2BPredefinedData(version, predefined, model_groups, view_size, translate_table)
{
    CurrentA2BPredefinedVersion = version;
    CurrentA2BPredefinedData = predefined;
    CurrentA2BCarMainModelGroups = model_groups;
    CurrentA2BCarModelViewSize = view_size;
    CurrentA2BTranslateTable = translate_table;
}

/* 适配当前车型的A2B预设源配置 */
function adaptCarModelA2BPredefinedData()
{
    if (isDebug || isDemoMode()) {
        switch (getDeviceType()) {
        case AB212:
            A2BMainModelID = 6;
            if (A2BSubModelID == -1) {
                A2BSubModelID = 1;
            }
            break;
        case AB216_D9:
            A2BMainModelID = 2;
            if (A2BSubModelID == -1) {
                A2BSubModelID = 1;
            }
            break;
        case AB216_M9:
            A2BMainModelID = 4;
            if (A2BSubModelID == -1) {
                A2BSubModelID = 3;
            }
            break;
        case AB216_U:
        case AB218:
            A2BMainModelID = 9;
            if (A2BSubModelID == -1) {
                A2BSubModelID = 1;
            }
            break;
        case AB218_TANK:
            A2BMainModelID = 5;
            if (A2BSubModelID == -1) {
                A2BSubModelID = 1;
            }
            break;
        }
        A2BVersionInfo = "";
        A2BFirmwareVersion = "";
    }

    if (CurrentA2BTranslateTable == null) {
        CurrentA2BTranslateTable = DefaultA2BTranslateTable; //使用默认翻译对照表避免或减少未翻译内容
    }

    var i;
    var curA2BPredefinedData = CurrentA2BPredefinedData;
    var subModelList = null; //用于获取子车型列表

    CurrentCarMainModelA2BPredefinedData = null;
    CurrentCarSubModelA2BPredefinedData = null;

    if (curA2BPredefinedData == null) {
        switch (getDeviceType()) {
        case AB212:
            curA2BPredefinedData = AB212_PredefinedData;
            break;
        case AB216_D9:
            curA2BPredefinedData = AB216_D9_PredefinedData;
            break;
        case AB216_M9:
            curA2BPredefinedData = AB216_M9_PredefinedData;
            break;
        case AB216_U:
        case AB218:
            if (getDeviceType() === AB218 && versionCmp(readDeviceVersion(), "1.3.x") >= 0) {
                curA2BPredefinedData = AB218_HW1_3_x_PredefinedData;
            } else {
                curA2BPredefinedData = AB218_PredefinedData;
            }
            break;
        case AB218_TANK:
            curA2BPredefinedData = AB218_TANK_PredefinedData;
            break;
        default:
            return false;
        }
    }

    if (curA2BPredefinedData != null) {
        for (i = 0; i < curA2BPredefinedData.length; i++) {
            if (curA2BPredefinedData[i].main_model.id == A2BMainModelID) {
                CurrentCarMainModelA2BPredefinedData = curA2BPredefinedData[i].main_model;
                subModelList = curA2BPredefinedData[i].sub_model;
                break;
            }
        }

        if (subModelList != null) {
            for (i = 0; i < subModelList.length; i++) {
                if (subModelList[i].id == null || subModelList[i].id == A2BSubModelID) {
                    if (subModelList[i].versions != null && subModelList[i].versions.length > 0) {
                        for (var j = 0; j < subModelList[i].versions.length; j++) {
                            if (subModelList[i].versions[j] == getA2BSubModelVersion()) {
                                break;
                            }
                        }
                        if (j == subModelList[i].versions.length) {
                            continue;
                        }
                    }

                    CurrentCarSubModelA2BPredefinedData = subModelList[i];
                    break;
                }
            }
        }
    }

    return true;
}

/* 获取A2B相关文本的译文 */
function getA2BTranslateString(str, lang)
{
    if (lang == "cn") {
        return str;
    }

    if (CurrentA2BTranslateTable != null) {
        for (var i = 0; i < CurrentA2BTranslateTable.length; i++) {
            if (str == CurrentA2BTranslateTable[i].cn) {
            if (lang != "cn" && CurrentA2BTranslateTable[i].en != null && CurrentA2BTranslateTable[i].en.length > 0) {
                    return CurrentA2BTranslateTable[i].en;
                }
            }
        }
    }

    return str;
}

/* 获取子车型ID、名称列表 */
function getCarSubModelList(mainModelID, lang)
{
    var list = [];
    var i;
    var curA2BPredefinedData = CurrentA2BPredefinedData;
    var subModelList = null; //用于获取子车型列表

    if (curA2BPredefinedData == null) {
        switch (getDeviceType()) {
        case AB212:
            curA2BPredefinedData = AB212_PredefinedData;
            break;
        case AB216_D9:
            curA2BPredefinedData = AB216_D9_PredefinedData;
            break;
        case AB216_M9:
            curA2BPredefinedData = AB216_M9_PredefinedData;
            break;
        case AB216_U:
        case AB218:
            if (getDeviceType() === AB218 && versionCmp(readDeviceVersion(), "1.3.x") >= 0) {
                curA2BPredefinedData = AB218_HW1_3_x_PredefinedData;
            } else {
                curA2BPredefinedData = AB218_PredefinedData;
            }
            break;
        case AB218_TANK:
            curA2BPredefinedData = AB218_TANK_PredefinedData;
            break;
        default:
            return list;
        }
    }

    if (curA2BPredefinedData != null) {
        for (i = 0; i < curA2BPredefinedData.length; i++) {
            if (curA2BPredefinedData[i].main_model.id == mainModelID) {
                subModelList = curA2BPredefinedData[i].sub_model;
                break;
            }
        }

        if (subModelList != null) {
            for (i = 0; i < subModelList.length; i++) {
//                /* 已存在同id车型则不添加 */
//                for (var j = 0; j < list.length; j++) {
//                    if (list[j].id == subModelList[i].id) {
//                        //list[j].versions = subModelList[i].versions;
//                        //list[j].name = getA2BTranslateString(subModelList[i].name, lang);
//                        break;
//                    }
//                }
//                if (j < list.length) {
//                    continue;
//                }

//                var version = 0;
//                if (subModelList[i].versions != null && subModelList[i].versions.length > 0) {
//                    version = subModelList[i].versions[subModelList[i].versions.length - 1];
//                }

                list.push({id: subModelList[i].id, group: subModelList[i].group, versions: subModelList[i].versions, name:getA2BTranslateString(subModelList[i].name, lang)/* + (version > 0 ? (" V" + version) : "")*/});
            }
        }
    }

    //console.log("getCarSubModelList: list = " + JSON.stringify(list));
    return list;
}

/* 获取当前主车型名称 */
function getCarMainModelName(lang)
{
    if (CurrentCarMainModelA2BPredefinedData != null) {
        return getA2BTranslateString(CurrentCarMainModelA2BPredefinedData.name, lang);
    }

    return "";
}

/* 获取当前子车型名称 */
function getCarSubModelName(lang)
{
    if (CurrentCarSubModelA2BPredefinedData != null) {
        return getA2BTranslateString(CurrentCarSubModelA2BPredefinedData.name, lang);
    }

    return "";
}

/* 获取A2B源名称 */
function getCarModelA2BSrcName(realSrc, lang, isLimitedSpace)
{
    if (CurrentCarSubModelA2BPredefinedData != null) {
        for (var i = 0; i < CurrentCarSubModelA2BPredefinedData.sources.length; i++) {
            if (CurrentCarSubModelA2BPredefinedData.sources[i].src === realSrc) {
                var name = CurrentCarSubModelA2BPredefinedData.sources[i].name;
                if (isLimitedSpace != undefined && isLimitedSpace) {
                    if (CurrentCarSubModelA2BPredefinedData.sources[i].abbr != undefined) {
                        name = CurrentCarSubModelA2BPredefinedData.sources[i].abbr;
                    }
                }
                return getA2BTranslateString(name, lang);
            }
        }
    }

    return "";
}

/* 获取A2B源是否为可调音量的源 */
function getCarModelA2BSrcAdjustable(realSrc)
{
    if (CurrentCarSubModelA2BPredefinedData != null) {
        for (var i = 0; i < CurrentCarSubModelA2BPredefinedData.sources.length; i++) {
            if (CurrentCarSubModelA2BPredefinedData.sources[i].src === realSrc) {
                return CurrentCarSubModelA2BPredefinedData.sources[i].adj_vol;
            }
        }
    }

    return 0;
}

/* 以界面源下标获取A2B源(的未添加模拟源路数)的实际源下标 */
function getCarModelA2BRealSrcByViewSrc(viewSrc)
{
    var desIdx = viewSrc;

    if (CurrentCarSubModelA2BPredefinedData != null) {
        if (viewSrc > -1 && viewSrc < CurrentCarSubModelA2BPredefinedData.sources.length) {
            desIdx = CurrentCarSubModelA2BPredefinedData.sources[viewSrc].src;
        }
    }

    //console.log("getCarModelA2BRealSrcByViewSrc: viewSrc = " + viewSrc + ", desIdx = " + desIdx);
    return desIdx;
}

/* 以(未添加模拟源路数的)实际源下标获取A2B源的界面源下标 */
function getCarModelA2BViewSrcByRealSrc(realSrc)
{
    var desIdx = realSrc;

    if (CurrentCarSubModelA2BPredefinedData != null) {
        for (var i = 0; i < CurrentCarSubModelA2BPredefinedData.sources.length; i++) {
            if (CurrentCarSubModelA2BPredefinedData.sources[i].src === realSrc) {
                desIdx = i;
                break;
            }
        }
    }

    //console.log("getCarModelA2BViewSrcByRealSrc: realSrc = " + realSrc + ", desIdx = " + desIdx);
    return desIdx;
}

/* 获取与预设源配置匹配的车型的A2B源长度 */
function getCarModelA2BSrcLength(allSrcLength)
{
    if (CurrentCarSubModelA2BPredefinedData != null) {
        var desLength = CurrentCarSubModelA2BPredefinedData.sources.length
        for (var i = 0; i < CurrentCarSubModelA2BPredefinedData.sources.length; i++) {
            if (CurrentCarSubModelA2BPredefinedData.sources[i].src >= allSrcLength) {
                desLength--; //避免预设源配置中有头枕通道，但实际显示页面无头枕通道时返回错误的通道数
            }
        }
        return desLength;
    }

    return 0;
}

/* 获取主车型分组列表 */
function getCarMainModelGroups(mainModelID, lang)
{
    var list = [];
    var curA2BCarMainModelGroups = CurrentA2BCarMainModelGroups;

    if (curA2BCarMainModelGroups == null) {
        switch (getDeviceType()) {
//        case AB212:
//            curA2BCarMainModelGroups = AB212_CarMainModelGroups;
//            break;
//        case AB216_D9:
//            curA2BCarMainModelGroups = AB216_D9_CarMainModelGroups;
//            break;
//        case AB216_M9:
//            curA2BCarMainModelGroups = AB216_M9_CarMainModelGroups;
//            break;
        case AB216_U:
        case AB218:
            if (getDeviceType() === AB218 && versionCmp(readDeviceVersion(), "1.3.x") >= 0) {
                curA2BCarMainModelGroups = AB218_HW1_3_x_CarMainModelGroups;
            } else {
                curA2BCarMainModelGroups = AB218_CarMainModelGroups;
            }
            break;
//        case AB218_TANK:
//            curA2BCarMainModelGroups = AB218_TANK_CarMainModelGroups;
//            break;
        default:
            return list;
        }
    }

    if (curA2BCarMainModelGroups != null) {
        for (var i = 0; i < curA2BCarMainModelGroups.length; i++) {
            if (curA2BCarMainModelGroups[i].id == mainModelID) {
                var carMainModelGroups = curA2BCarMainModelGroups[i].groups;
                for (var j = 0; j < carMainModelGroups.length; j++) {
                    list.push({group: carMainModelGroups[j].group, name: getA2BTranslateString(carMainModelGroups[j].name, lang)});
                }
                break;
            }
        }
    }

    //console.log("getCarMainModelGroups: list = " + JSON.stringify(list));
    return list;
}

/* 获取车型列表显示宽度 */
function getCarModelViewSize(lang)
{
    var result = {};
    var curA2BCarModelViewSize = CurrentA2BCarModelViewSize;

    if (curA2BCarModelViewSize == null) {
        switch (getDeviceType()) {
//        case AB212:
//            curA2BCarModelViewSize = AB212_CarModelViewSize;
//            break;
//        case AB216_D9:
//            curA2BCarModelViewSize = AB216_D9_CarModelViewSize;
//            break;
//        case AB216_M9:
//            curA2BCarModelViewSize = AB216_M9_CarModelViewSize;
//            break;
        case AB216_U:
        case AB218:
            curA2BCarModelViewSize = AB218_CarModelViewSize;
            break;
//        case AB218_TANK:
//            curA2BCarModelViewSize = AB218_TANK_CarModelViewSize;
//            break;
        default:
            return result;
        }
    }

    if (curA2BCarModelViewSize != null) {
        if (curA2BCarModelViewSize.main_model != null) {
            if (lang != "cn") {
                result.main_model = {width: curA2BCarModelViewSize.main_model.width.en};
            } else {
                result.main_model = {width: curA2BCarModelViewSize.main_model.width.cn};
            }
        }
        if (curA2BCarModelViewSize.sub_model != null) {
            if (lang != "cn") {
                result.sub_model = {width: curA2BCarModelViewSize.sub_model.width.en};
            } else {
                result.sub_model = {width: curA2BCarModelViewSize.sub_model.width.cn};
            }
        }
    }

    //console.log("getCarModelViewSize: result = " + JSON.stringify(result));
    return result;
}

