function isNeedGetBluetoothVersion()
{
    if (getDeviceType() === GDT42 && versionCmp(readDeviceVersion(), "2.0.x") <= 0) {
        if (versionCmp(readDeviceVersion(), "2.0.x") == 0 && versionCmp(readFirmwareVersion(), "2.0.1") >=0) {
            return true;
        } else if (versionCmp(readDeviceVersion(), "1.0.x") == 0 && versionCmp(readFirmwareVersion(), "1.2.1") >=0) {
            return true;
        }
    } else {
        return isHasBluetoothModule();
    }

    return false;
}

