function getDynamicAllBaseSrcLength(isStatic) {
    /* 蓝牙/光纤/同轴/主机输入源合并为数字源，只需其中一组存在即认为有2个数字源 */
    var dynamicLength = 0;
    if (isHasBluetoothModule() || (isStatic != null && isStatic)) {
        dynamicLength += 2;
    }

    if (isHasSoundCardRoute() || (isStatic != null && isStatic)) {
        dynamicLength += 2;
    }

    if (isHasA2BRoute() || (isStatic != null && isStatic)) {
        dynamicLength += getA2BSrcLength(); //此处仅需处理实体A2B源通道，即不包含两路头枕
    }

    if (isVSRxGxHasSpdifRoute() || (isStatic != null && isStatic)) {
        dynamicLength += 2;
    }

    if (isHasDigitalRoute() || (isStatic != null && isStatic)) {
        dynamicLength += 2;
    }

    return (getAnalogSrcLength() + dynamicLength);
}

