function isOldFirmwareVersion()
{
    var devType = getDeviceType();
    var devVersion = readDeviceVersion();
    var devFirmwareVersion = readFirmwareVersion();

    if (isForIndonesia()) {
        switch (devType) {
        case G2_PRO:
            if (versionCmp(devVersion, "1.0.x") == 0 && (versionCmp(devFirmwareVersion, "1.1.1") <= 0 || versionCmp(devFirmwareVersion, "11.1.x") == 0)) {
                return true;
            }
            break;
        case A5:
            if (versionCmp(devVersion, "3.0.x") == 0 && (versionCmp(devFirmwareVersion, "1.6.1") <= 0 || versionCmp(devFirmwareVersion, "11.6.x") == 0)) {
                return true;
            }
            break;
        case GDT216:
            if (versionCmp(devVersion, "1.1.x") == 0 && (versionCmp(devFirmwareVersion, "1.1.10") <= 0 || versionCmp(devFirmwareVersion, "11.1.x") == 0)) {
                return true;
            }
            break;
        case GDT212:
            if (versionCmp(devVersion, "1.0.x") == 0 && (versionCmp(devFirmwareVersion, "1.0.3") <= 0 || versionCmp(devFirmwareVersion, "11.0.x") == 0)) {
                return true;
            }
            break;
        case GDT28:
            if (versionCmp(devVersion, "2.2.x") == 0 && (versionCmp(devFirmwareVersion, "1.3.3") <= 0 || versionCmp(devFirmwareVersion, "11.3.x") == 0)) {
                return true;
            }
            break;
        case GDT68PRO:
            if (versionCmp(devVersion, "1.0.0") == 0 && (versionCmp(devFirmwareVersion, "1.0.2") <= 0 || versionCmp(devFirmwareVersion, "11.0.x") == 0)) {
                return true;
            }
            break;
        }
    } else if (isForColombia()) {
        switch (devType) {
        case GDT216:
            if (versionCmp(devVersion, "1.1.x") == 0 && versionCmp(devFirmwareVersion, "1.1.10") <= 0) {
                return true;
            }
            break;
        case GDT212:
            if (versionCmp(devVersion, "1.0.x") == 0 && versionCmp(devFirmwareVersion, "1.0.1") <= 0) {
                return true;
            }
            break;
        case GDT28:
            if (versionCmp(devVersion, "2.2.x") == 0 && versionCmp(devFirmwareVersion, "1.3.3") <= 0) {
                return true;
            }
            break;
        case GDT68PRO:
            if (versionCmp(devVersion, "1.0.0") == 0 && versionCmp(devFirmwareVersion, "1.0.2") <= 0) {
                return true;
            }
            break;
        case GDT42:
            if (versionCmp(devVersion, "2.0.32") == 0 && versionCmp(devFirmwareVersion, "2.0.600") <= 0) {
                return true;
            }
            break;
//        case GDT06:
//            if (versionCmp(devVersion, "1.0.0") == 0 && versionCmp(devFirmwareVersion, "1.0.1") <= 0) {
//                return true;
//            }
//            break;
        }
    } else if (isForInternational()) { //歌航国际版兼容哥伦比亚旧版固件
        switch (devType) {
        case G2_PRO:
            if (versionCmp(devVersion, "1.0.1") == 0 && versionCmp(devFirmwareVersion, "11.1.x") == 0) {
                return true;
            }
            break;
        case A5:
            if (versionCmp(devVersion, "3.0.x") == 0 && versionCmp(devFirmwareVersion, "11.6.x") == 0) {
                return true;
            }
            break;
        case GDT216:
            if (versionCmp(devVersion, "1.1.x") == 0 && versionCmp(devFirmwareVersion, "11.1.x") == 0) {
                return true;
            }
            break;
        case GDT212:
            if (versionCmp(devVersion, "1.0.x") == 0 && versionCmp(devFirmwareVersion, "11.0.x") == 0) {
                return true;
            }
            break;
        case GDT28:
            if (versionCmp(devVersion, "2.2.x") == 0 && versionCmp(devFirmwareVersion, "11.3.x") == 0) {
                return true;
            }
            break;
        case GDT68PRO:
            if (versionCmp(devVersion, "1.0.0") == 0 && versionCmp(devFirmwareVersion, "11.0.x") == 0) {
                return true;
            }
            break;
        case GDT42:
            if (versionCmp(devVersion, "2.0.32") == 0 && versionCmp(devFirmwareVersion, "12.0.x") == 0) {
                return true;
            }
            break;
        case GDT06:
            if (versionCmp(devVersion, "1.0.0") == 0 && versionCmp(devFirmwareVersion, "11.0.x") == 0) {
                return true;
            }
            break;
        }
    } else if (isForCDT()) {
        switch (devType) {
        case A5:
            if (versionCmp(devVersion, "3.0.x") == 0 && versionCmp(devFirmwareVersion, "1.5.x") == 0) {
                return true;
            }
            break;
        case A10:
            if (versionCmp(devVersion, "1.0.x") == 0 && versionCmp(devFirmwareVersion, "1.1.x") == 0) {
                return true;
            }
            break;
        case GDT216:
            if ((versionCmp(devVersion, "1.0.x") == 0 || versionCmp(devVersion, "1.1.x") == 0) && versionCmp(devFirmwareVersion, "1.2.x") == 0) {
                return true;
            }
            break;
        case GDT212:
            if (versionCmp(devVersion, "1.0.x") == 0 && versionCmp(devFirmwareVersion, "21.0.x") == 0) {
                return true;
            }
            break;
        case GDT28:
            if (versionCmp(devVersion, "2.2.x") == 0 && versionCmp(devFirmwareVersion, "1.2.x") == 0) {
                return true;
            }
            break;
        case GDT68PRO:
            if (versionCmp(devVersion, "1.0.0") == 0 && versionCmp(devFirmwareVersion, "1.1.x") == 0) {
                return true;
            }
            break;
        case GDT68:
            if (versionCmp(devVersion, "2.1.x") == 0 && versionCmp(devFirmwareVersion, "2.2.x") == 0) {
                return true;
            }
            break;
        case GDT42:
            if (versionCmp(devVersion, "2.0.x") == 0 && versionCmp(devFirmwareVersion, "2.1.x") == 0) {
                return true;
            }
            break;
        case GDT06:
            if (versionCmp(devVersion, "1.0.x") == 0 && versionCmp(devFirmwareVersion, "1.0.x") == 0) {
                return true;
            }
            break;
        }
    }

    return false;
}

