function getOutputsLength()
{
    var desLength = getUniversalOutputsLength();
    switch (getCurrentOutputsTypeGroup()) {
    case AMP_OUTPUTS_GROUP_1:
        desLength = (getAmpOutputsLength() > 16 ? 16 : getAmpOutputsLength());
        break;
    case AMP_OUTPUTS_GROUP_2:
        desLength = getAmpOutputsLength() - 16;
        break;
    }

    return desLength;
}

function getSharedChannelsLength()
{
    return sharedChannels.length;
}

var needThrowException = false;
function getOutputCmdLineIdxByViewIdx(idx/*, needThrowException*/) //由于MSVC2015编译器限制，needThrowException不能直接做为参数，否则程序会闪退
{
    if (getCurrentActiveCallbackFunsFlag() === OUTPUTS_GROUPS) {
        var sharedLength = getSharedChannelsLength();
        var desIdx;
        switch (getCurrentOutputsTypeGroup()) {
        case AMP_OUTPUTS_GROUP_1:
            if (sharedLength > 0) {
                var realIdx = (getDeviceType() == AB212 ? (idx - 2) : idx); //因AB212丝印错误，进行适配
                if (sharedChannels.some(function(item) { return realIdx === item; })) {
                    return realIdx;
                }

                if (realIdx < sharedChannels[0]) {
                    idx += getUniversalOutputsLength();
                } else if (realIdx > sharedChannels[sharedLength - 1]) {
                    desIdx = idx + getUniversalOutputsLength() - sharedLength;
                    if (desIdx < getAllIndepOutputsLength()) {
                        idx = desIdx;
                    }
                }
            } else {
                idx += getUniversalOutputsLength();
            }
            break;
        case AMP_OUTPUTS_GROUP_2:
            desIdx = idx + getUniversalOutputsLength() + 16 - sharedLength;
            if (desIdx < getAllIndepOutputsLength()) {
                idx = desIdx;
            } else {
                //console.log("!!!--getOutputCmdLineIdxByViewIdx Error: desIdx = " + desIdx + ", needThrowException = " + needThrowException);
                if (needThrowException) {
                    throw ("Error: desIdx = " + desIdx);
                }
            }
            break;
        }
    }

    return idx;
}

function getOutputViewIdxByCmdLineIdx(idx)
{
    if (getCurrentActiveCallbackFunsFlag() === OUTPUTS_GROUPS) {
        var sharedLength = getSharedChannelsLength();
        switch (getCurrentOutputsTypeGroup()) {
        case AMP_OUTPUTS_GROUP_1:
            if (sharedLength > 0) {
                if (sharedChannels.some(function(item) { return idx === item; })) {
                    var realIdx = (getDeviceType() == AB212 ? (idx + 2) : idx); //因AB212丝印错误，进行适配
                    return realIdx;
                }

                if (idx >= getUniversalOutputsLength()) {
                    idx -= getUniversalOutputsLength();
                    if (idx > sharedChannels[sharedLength - 1]) {
                        idx += sharedLength;
                    }
                }
            } else if (idx >= getUniversalOutputsLength()) {
                idx -= getUniversalOutputsLength();
            }
            break;
        case AMP_OUTPUTS_GROUP_2:
            var preLength = getUniversalOutputsLength() + 16 - sharedLength;
            if (idx >= preLength) {
                idx -= preLength;
            }
            break;
        }
    }

    return idx;
}

function isInSharedChannels(ch) {
    var realIdx = ((getDeviceType() == AB212 && getCurrentOutputsTypeGroup() >= AMP_OUTPUTS_GROUP_1) ? (ch - 2) : ch); //因AB212丝印错误，进行适配
    if (sharedChannels.some(function(item) { return realIdx === item; })) {
        return true;
    }

    return false;
}

function isInBridgeJointChannels(ch) {
    var realIdx = ((getDeviceType() == AB212 && getCurrentOutputsTypeGroup() >= AMP_OUTPUTS_GROUP_1) ? (ch - 2) : ch); //因AB212丝印错误，进行适配
    if (bridgeJointChannels.some(function(item) { return realIdx === item; })) {
        return true;
    }

    return false;
}

