/* 设置当前输入的类型分组：ANALOG_INPUTS_GROUP_1 或 DIGITAL */
function setCurrentInputsTypeGroup(grp)
{
    CurrentInputsTypeGroup = grp;
}

/* 获取当前输入的类型分组：ANALOG 或 DIGITAL */
function getCurrentInputsTypeGroup()
{
    return CurrentInputsTypeGroup;
}

/* 获取当前输入类型分组下的输入源数量 */
function getInputsLength(){
    var A2BSrcLength;
    var carModelA2BSrcLength;
    if (getCurrentInputsTypeGroup() === ANALOG_INPUTS_GROUP_1) {
        if (getAnalogSrcLength() > 16) {
            return 16;
        } else {
            return getAnalogSrcLength();
        }
    } else if (getCurrentInputsTypeGroup() === ANALOG_INPUTS_GROUP_2) {
        if (getAnalogSrcLength() > 16) {
            return getAnalogSrcLength() - 16;
        } else {
            return 0;
        }
    } else if (getCurrentInputsTypeGroup() === A2B_INPUTS_GROUP_1) {
        A2BSrcLength = getA2BSrcLength();
        carModelA2BSrcLength = Math.min(getCarModelA2BSrcLength(A2BSrcLength), A2BSrcLength);
        if (carModelA2BSrcLength) {
            A2BSrcLength = carModelA2BSrcLength;
        }
        if (A2BSrcLength > 16) {
            return 16;
        } else {
            return A2BSrcLength;
        }
    } else if (getCurrentInputsTypeGroup() === A2B_INPUTS_GROUP_2) {
        A2BSrcLength = getA2BSrcLength();
        carModelA2BSrcLength = Math.min(getCarModelA2BSrcLength(A2BSrcLength), A2BSrcLength);
        if (carModelA2BSrcLength) {
            A2BSrcLength = carModelA2BSrcLength;
        }
        if (A2BSrcLength > 16) {
            return A2BSrcLength - 16;
        } else {
            return 0;
        }
    } else {
        return getDynamicAllBaseSrcLength() - (isHasA2BRoute() ? getA2BSrcLength() : 0) - getAnalogSrcLength();
    }
}

/* 以界面上的通道索引获取标准模式输入源（即外接输入源）在指令中的索引，报文中的输入源排序为：模拟 + A2B + 蓝牙 + USB + 独立于DSD主机的SPDIF + 数字/DSD主机 */
function getInputCmdLineIdxByViewIdx(idx)
{
    if (getCurrentActiveCallbackFunsFlag() === STANDARD_INPUTS_GROUPS) {
        switch (getCurrentInputsTypeGroup()) {
        case DIGITAL_INPUTS_GROUP:
            if (idx < getAnalogSrcLength() + (isHasA2BRoute() ? getA2BSrcLength() : 0)) {
                return (getAnalogSrcLength() + (isHasA2BRoute() ? getA2BSrcLength() : 0) + idx);
            }
            break;
        case ANALOG_INPUTS_GROUP_1:
            break;
        case ANALOG_INPUTS_GROUP_2:
            return 16 + idx;
        case A2B_INPUTS_GROUP_1:
            return getCarModelA2BRealSrcByViewSrc(idx) + getAnalogSrcLength();
        case A2B_INPUTS_GROUP_2:
            return getCarModelA2BRealSrcByViewSrc(16 + idx) + getAnalogSrcLength();
        }
    }

    return idx;
}

/* 以报文中的通道索引获取标准模式输入源（即外接输入源）在界面上的索引，报文中的输入源排序为：模拟 + A2B + 蓝牙 + USB + 独立于DSD主机的SPDIF + 数字/DSD主机 */
function getInputViewIdxByCmdLineIdx(idx)
{
    if (getCurrentActiveCallbackFunsFlag() === STANDARD_INPUTS_GROUPS) {
        switch (getCurrentInputsTypeGroup()) {
        case DIGITAL_INPUTS_GROUP:
            if (idx >= getAnalogSrcLength() + (isHasA2BRoute() ? getA2BSrcLength() : 0)) {
                return (idx - getAnalogSrcLength() - (isHasA2BRoute() ? getA2BSrcLength() : 0));
            }
            break;
        case ANALOG_INPUTS_GROUP_1:
            break;
        case ANALOG_INPUTS_GROUP_2:
            if (idx >= 16) {
                return idx - 16;
            }
            break;
        case A2B_INPUTS_GROUP_1:
            return getCarModelA2BViewSrcByRealSrc(idx - getAnalogSrcLength());
        case A2B_INPUTS_GROUP_2:
            //if (idx >= (16 + getAnalogSrcLength())) {
                return getCarModelA2BViewSrcByRealSrc(idx - getAnalogSrcLength()) - 16;
            //}
        }
    }

    return idx;
}

