/* 获取当前仅数字与模拟路由混合状态 */
function isDARoutingMixed()
{
    if ((getDeviceType() === GDT28 && versionCmp(readFirmwareVersion(), "1.1.0") >= 0) ||
            (getDeviceType() === GDT42 && versionCmp(readFirmwareVersion(), "1.2.0") >= 0) || (getDeviceType() === GDT46 && versionCmp(readFirmwareVersion(), "1.1.0") >= 0)) {
        return false;
    } else {
        return (DARoutingMixed || getDeviceType() === GDT28 || getDeviceType() === GDT42 || getDeviceType() === GDT46);
    }
}

/* 从传入的数据库中获取DSP基础输入源（即外接输入源）的配置 */
function getBaseInputsCfgDataByDB(seq, routingIdx, dataBase)
{
    if (routingIdx === ANALOG) {
        return dataBase.Analog[seq];
    } else if (routingIdx === A2B) {
        return dataBase.A2B[seq];
    } else if (routingIdx === DIGITAL) {
        return dataBase.Digital[seq];
    } else if (routingIdx === BLUETOOTH) {
        return dataBase.Bluetooth[seq];
    } else if (routingIdx === SOUNDCARD) {
        return dataBase.SoundCard[seq];
    } else if (routingIdx === SPDIF) {
        return dataBase.Spdif[seq];
    } else {
        return null;
    }
}

