/* 由输入源在报文中的通道索引获取DSP标准模式输入源（即外接输入源）EQ的数据库配置 */
function getStandardInputEqCfgDataByChannelIdxByDB(seq, dataBase)
{
    var routing = getStandardInputRoutingByChannelIdx(seq);
    var dbIdx = getStandardInputDbIndexByChannelIdx(seq);

    try {
        if (routing === ANALOG) {
            return dataBase.Analog[dbIdx].standardEq;
        } else if (routing === A2B) {
            return dataBase.A2B[dbIdx].standardEq;
        } else if (routing === BLUETOOTH) {
            return dataBase.Bluetooth[dbIdx].standardEq;
        } else if (routing === SOUNDCARD) {
            return dataBase.SoundCard[dbIdx].standardEq;
        } else if (routing === DIGITAL) {
            return dataBase.Digital[dbIdx].standardEq;
        } else if (routing === SPDIF) {
            return dataBase.Spdif[dbIdx].standardEq;
        } else {
            return null;
        }
    } catch (e) {
        console.log("seq = " + seq + ", routing = " + routing + ", dbIdx = " + dbIdx);
        console.trace();
        throw e;
    }
}

