/*
convert cursor position into gain and freq
增益值-15dB~+15dB,最小步进0.1dB
频率范围:20~20000
step:interval between frequencys.
*/
function cursor2Frq( x,step)
{
    var bands=parseInt((x)/step);//step 是小数，需要x增加一个补偿接近时候非整数问题。
    // console.log("-------x:"+x+" band:"+bands+" step:"+step);
    var i=position_calibrate.indexOf(x);//不能用bands去索引，因为传入的x已经被舍去小数，这样算出的bands也是不准确的
    if(i!=-1)
    {
        return  frq_31_bands[i];
    }
    var offset=x%step;
    var f=frq_31_bands[bands];
    //console.log("b:"+bands+" off:"+offset+" f:"+f);
    if(bands<(frq_31_bands.length-1))
    {
        f+=offset*(frq_31_bands[bands+1]-frq_31_bands[bands])/step;
    }
    return parseInt(f);
}

/*
由于整型误差会导致数据不一致，需要标定一下。
比如调用一次频率转坐标，转换后的小数会被画图程序舍去，然后画图程序把舍去小数的坐标回传回来会导致计算的出的频率和传入的有误差，为了
视觉上的一致，基准点采用定点标定.
*/
var position_calibrate=new Array(frq_31_bands.length);
/*
frq: range from(include) 20Hz to 20000Hz.
*/
function frq2Cursor(frq,step)
{
    var item;
    if(frq<frq_31_bands[0])frq=frq_31_bands[0];
    if(frq>frq_31_bands[frq_31_bands.length-1])frq=frq_31_bands[frq_31_bands.length-1];
    for(item=0;item<frq_31_bands.length;item++)
    {
        if(frq<frq_31_bands[item])break;
    }
    var bands=item-1;
    var offset=frq-frq_31_bands[bands];
    if(offset)
        offset=offset*step/(frq_31_bands[item]-frq_31_bands[bands]);
    var pos=bands*step+offset;
   // console.log("frq:"+frq+" offset:"+offset+" step:"+step+" pos:"+pos);
    if(offset==0) //没有偏差，更新标定值
    {
        position_calibrate[bands]=parseInt(pos);
        //console.log("frq:"+frq+"------cal:"+bands+" "+position_calibrate[bands]);
        // console.log("pos:"+pos);
    }
    //console.log("bands:"+bands+"  offset:"+offset);
    //console.log("frq:"+frq+" calculated:"+cursor2Frq( pos,step));
    return parseInt(pos);
}
