/*
    获取某通道的EQ类型
*/
function getEqTypes(arr)
{
    return deepCopy((getCurRoutingCfgData(arr).type !== undefined ? getCurRoutingCfgData(arr).type : 0));
}

/*
    设置某通道指定频点的EQ类型
*/
function setEqTypes(cb,arr,idx,types)
{
    var grp=getGroup(arr);// here arr should equal to grp
    var grp_members=getGroupMembers(grp);
    var parm_list_type = [];
    var parm_list_eqSlope = [];
    var parm_list_q = [];
    var parm_list_freq = [];
    var parm_list_gain = [];
    var is_set_eqType = false; //是否设置了从通道的EQ类型为当前通道EQ类型
    var is_set_freq = false; //是否设置了从通道的频率值为当前通道的频率值
    var is_set_eqSlope = false; //是否设置了从通道的Slope值为当前通道Slope值
    var is_set_q = false; //是否设置了从通道的Q值为当前通道Q值
    var is_set_gain = false; //是否设置了从通道的EQ为当前通道的EQ值
    var pairedCh;
    var curEqSlopes = getEqSlopeVal(arr);
    var curQs = getQVal(arr);

    switch(getEqCorrMode())
    {
    case "bal":
    case "rel":
    case "abs":
        for(var j=0;j<grp_members.length;j++)
        {
            /* 当主通道EQ类型改变时，从通道的Q绝对同步至主通道 */
            if (grp_members[j] !== arr) {
                pairedCh = getPairedBridgeJointChannel(grp_members[j]);
                if (pairedCh === arr) {
                    continue;
                }

                is_set_eqType = false;
                if (getCurRoutingCfgData(grp_members[j]).type[idx] !== types[idx]) {
                    getCurRoutingCfgData(grp_members[j]).type[idx] = types[idx];
                    if (pairedCh > -1) {
                        getCurRoutingCfgData(pairedCh).type[idx] = getCurRoutingCfgData(grp_members[j]).type[idx];
                    }
                    is_set_eqType = true;
                }
                if (is_set_eqType) {
                    parm_list_type.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).type});
                    if (pairedCh > -1) {
                        parm_list_type.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).type});
                    }
                }

                if (types[idx] === 1 || types[idx] === 2) {
                    is_set_eqSlope = false;
                    if (Number(getCurRoutingCfgData(grp_members[j]).S[idx]).toFixed(1) !== Number(curEqSlopes[idx]).toFixed(1)) {
                        getCurRoutingCfgData(grp_members[j]).S[idx] = curEqSlopes[idx];
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).S[idx] = curEqSlopes[idx];
                        }
                        is_set_eqSlope = true;
                    }
                    if (is_set_eqSlope) {
                        parm_list_eqSlope.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).S});
                        if (pairedCh > -1) {
                            parm_list_eqSlope.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).S});
                        }
                    }
                } else {
                    is_set_q = false;
                    if (Number(getCurRoutingCfgData(grp_members[j]).Q[idx]).toFixed(1) !== Number(curQs[idx]).toFixed(1)) {
                        getCurRoutingCfgData(grp_members[j]).Q[idx] = curQs[idx];
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).Q[idx] = curQs[idx];
                        }
                        is_set_q = true;
                    }
                    if (is_set_q) {
                        parm_list_q.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).Q});
                        if (pairedCh > -1) {
                            parm_list_q.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).Q});
                        }
                    }
                }

                if (getEqCorrMode() == "abs") {
                    /* 当主通道EQ类型改变时，从通道的频率、EQ都绝对同步至主通道 */
                    is_set_freq = false;
                    if (getCurRoutingCfgData(grp_members[j]).shift_freq[idx] != getCurRoutingCfgData(arr).shift_freq[idx]) {
                        getCurRoutingCfgData(grp_members[j]).shift_freq[idx] = getCurRoutingCfgData(arr).shift_freq[idx];
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).shift_freq[idx] = getCurRoutingCfgData(arr).shift_freq[idx];
                        }
                        is_set_freq = true;
                    }
                    is_set_gain = false;
                    if (/*getEqCorrMode() != "bal" && */Number(getCurRoutingCfgData(grp_members[j]).gain[idx], 'f', 1).toFixed(1) != Number(getCurRoutingCfgData(arr).gain[idx], 'f', 1).toFixed(1)) {
                        getCurRoutingCfgData(grp_members[j]).gain[idx] = getCurRoutingCfgData(arr).gain[idx];
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).gain[idx] = getCurRoutingCfgData(arr).gain[idx];
                        }
                        is_set_gain = true;
                    }

                    if (is_set_freq) {
                        var freqs = [];
                        for (var m = 0; m < getCurRoutingCfgData(grp_members[j]).shift_freq.length; m++) {
                            freqs.push(parseInt(getCurRoutingCfgData(grp_members[j]).shift_freq[m]) + parseInt(frq_bands[m]));
                        }
                        parm_list_freq.push({key:grp_members[j], val:freqs});
                        if (pairedCh > -1) {
                            parm_list_freq.push({key:pairedCh, val:freqs});
                        }
                    }
                    if (is_set_gain) {
                        parm_list_gain.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).gain});
                        if (pairedCh > -1) {
                            parm_list_gain.push({key:pairedCh, val:getCurRoutingCfgData(grp_members[j]).gain});
                        }
                    }
                }
            }

            if (parm_list_eqSlope.length > 0) {
                devSetMutiChEqSlope(cb, null, parm_list_eqSlope);
            }

            if (parm_list_q.length > 0) {
                devSetMutiChQ(cb, null, parm_list_q);
            }

            if (parm_list_freq.length > 0) {
                devSetMutiChFreq(cb, null, parm_list_freq);
            }
            if (parm_list_gain.length > 0) {
                devSetMutiChEQ(cb, null, parm_list_gain);
            }
        }
        break;
    case "non":
    }

    getCurRoutingCfgData(arr).type=deepCopy(types);
    parm_list_type.push({key:arr, val:types});

    pairedCh = getPairedBridgeJointChannel(arr);
    if (pairedCh > -1) {
        getCurRoutingCfgData(pairedCh).type=deepCopy(types);
        parm_list_type.push({key:pairedCh, val:types});
    }

    devSetMutiChEqType(cb, getCurrentRouting(), parm_list_type);
}

/* 联动复位通道EQ类型 */
function resetChEqTypes(cb, arr) {
    var output_list = [];

    if(getEqCorrMode()!="non") {//不管是相对还是绝对，必须要把频率值对齐，
        var grp=getGroup(arr);// here i should equal to grp
        var grp_members=getGroupMembers(grp);
        output_list = grp_members;
    } else {
        output_list.push(arr);
    }
    resetAllEqTypes(cb, output_list);
}

/* 复位指定通道列表的EQ类型 */
function resetAllEqTypes(cb, output_list)
{
    var pairedCh;
    var parm_list = [];
    var exclude_list = [];

    for(var i=0;i<output_list.length;i++)
    {
        if (exclude_list.some(function(item) { return output_list[i] === item; })) {
            continue;
        }

        pairedCh = getPairedBridgeJointChannel(output_list[i]);

        var cur_frq_bands = getFreqBands(getCurRoutingCfgData(output_list[i]).shift_freq.length);
        getCurRoutingCfgData(output_list[i]).type = [];
        if (pairedCh > -1) {
            getCurRoutingCfgData(pairedCh).type = [];
        }
        for(var j=0;j<cur_frq_bands.length;j++)
        {
            getCurRoutingCfgData(output_list[i]).type.push(0);

            if (pairedCh > -1) {
                getCurRoutingCfgData(pairedCh).type.push(0);
            }
        }
        parm_list.push({key:output_list[i], val:getCurRoutingCfgData(output_list[i]).type});

        if (pairedCh > -1) {
            parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).type});
            exclude_list.push(pairedCh);
        }
    }

    return devSetMutiChEqType(cb, getCurrentRouting(), parm_list);
}

function getMaxFreq() {
    if (getDeviceType() === G5 || (getDeviceType() === GD16 && versionCmp(readDeviceVersion(), "1.0.1") >= 0) || (getDeviceType() === G2_PRO && versionCmp(readDeviceVersion(), "2.0.0") >= 0)) {
        return 40000;
    } else {
        return 20000;
    }
}

function getFreqBands(count)
{
    switch(count) {
    case 5:
        return frq_5_bands;
    case 9:
        return frq_9_bands;
    case 10:
        return frq_10_bands;
    case 15:
        return frq_15_bands
    case 30:
        return frq_30_bands
    default:
        return frq_31_bands;
    }
}

/*
获取指定组的各段频率值,总共5/10/15/31段
arr:输出组序号，从0开始，不要超过DspCfgData的长度
*/
function getFreqsVal(arr)
{
    var tmp_frqs=deepCopy(getFreqBands(getCurRoutingCfgData(arr).shift_freq.length));
    if(arr>(getAllMembersLength()-1))
    {
        console.log("error:arr out of range");
        return tmp_frqs;
    }
    //iterate the array of DspCfgData, merge the base vale and offset.
    for(var item=0;item<tmp_frqs.length;item++)
    {
        tmp_frqs[item]+=getCurRoutingCfgData(arr).shift_freq[item];
        //  console.log("frqs["+item+"]="+tmp_frqs[item]);
    }
    return tmp_frqs;
}

/*
修改指定组的频率组为指定值
arr: 组号，用于索引DspCfgData下标。
idx: 频点下标索引，用于索引当前操作的频点下标
freqs: 31段频率值,需要按照索引顺序而非从大到小顺序排列。
*/
function setFreqsVal(cb,arr,idx,freqs)
{
//    console.assert(31>arr>=0,"group sequence out of range");

    var curTypes = getEqTypes(arr);
    var parm_list_eqType = [];
    var parm_list_freq = [];
    var parm_list_q = [];
    var parm_list_gain = [];
    var is_set_eqType = false; //是否设置了从通道的EQ类型为当前通道EQ类型
    var is_set_freq = false; //是否设置了从通道的频率值为当前通道的频率值
    var is_set_q = false; //是否设置了从通道的Q值为当前通道Q值
    var is_set_gain = false; //是否设置了从通道的EQ为当前通道的EQ值
    var pairedCh;
    var cur_frq_bands = getFreqBands(getCurRoutingCfgData(arr).shift_freq.length);
    var shift_freq = freqs[idx] - cur_frq_bands[idx];
    var delta = shift_freq - getCurRoutingCfgData(arr).shift_freq[idx];
    var desFreq;

//    for(var i=0;i<freqs.length;i++)
//    {
        getCurRoutingCfgData(arr).shift_freq[idx]=shift_freq;
//    }
    parm_list_freq.push({key:arr, val:freqs});

    pairedCh = getPairedBridgeJointChannel(arr);
    if (pairedCh > -1) {
//        for(var i=0;i<freqs.length;i++)
//        {
            getCurRoutingCfgData(pairedCh).shift_freq[idx]=getCurRoutingCfgData(arr).shift_freq[idx];
//        }
        parm_list_freq.push({key:pairedCh, val:freqs});
    }

    if(getEqCorrMode()!="non") //不管是相对还是绝对，必须要把频率对齐，
    {
        var grp=getGroup(arr);
        var grp_members=getGroupMembers(grp);
        for(var j=0;j<grp_members.length;j++)
        {
            /* 当主通道频率值改变时，从通道的频率、Q、EQ都绝对同步至主通道 */
            if(grp_members[j]!=arr) {
                pairedCh = getPairedBridgeJointChannel(grp_members[j]);
                if (pairedCh === arr) {
                    continue;
                }

                is_set_eqType = false;
                if (getCurRoutingCfgData(grp_members[j]).type[idx] != curTypes[idx]) {
                    if (getEqCorrMode() == "abs") {
                        getCurRoutingCfgData(grp_members[j]).type[idx] = curTypes[idx];
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).type[idx] = curTypes[idx];
                        }
                        is_set_eqType = true;
                    } else {
                        continue;
                    }
                }
                if (is_set_eqType) {
                    parm_list_eqType.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).type});
                    if (pairedCh > -1) {
                        parm_list_eqType.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).type});
                    }
                }

                is_set_freq = false;
                if (getEqCorrMode() == "abs") {
                    if (getCurRoutingCfgData(grp_members[j]).shift_freq[idx] != getCurRoutingCfgData(arr).shift_freq[idx]) { //如果频率不对应，则将频率Q值、EQ对齐
                        getCurRoutingCfgData(grp_members[j]).shift_freq[idx] = getCurRoutingCfgData(arr).shift_freq[idx];
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).shift_freq[idx] = getCurRoutingCfgData(arr).shift_freq[idx];
                        }
                        is_set_freq = true;
                    }
                } else {
                    desFreq = getCurRoutingCfgData(grp_members[j]).shift_freq[idx] + delta + cur_frq_bands[idx];
                    if (desFreq < frq_31_bands[0]) {
                        desFreq = frq_31_bands[0];
                    } else if (desFreq > frq_31_bands[frq_31_bands.length - 1]) {
                        desFreq = frq_31_bands[frq_31_bands.length - 1];
                    }
                    getCurRoutingCfgData(grp_members[j]).shift_freq[idx] = desFreq - cur_frq_bands[idx];
                    if (pairedCh > -1) {
                        getCurRoutingCfgData(pairedCh).shift_freq[idx] = getCurRoutingCfgData(arr).shift_freq[idx];
                    }
                    is_set_freq = true;
                }
                if (is_set_freq) {
                    var member_freqs = [];
                    for (var m = 0; m < getCurRoutingCfgData(grp_members[j]).shift_freq.length; m++) {
                        member_freqs.push(parseInt(getCurRoutingCfgData(grp_members[j]).shift_freq[m]) + parseInt(cur_frq_bands[m]));
                    }
                    parm_list_freq.push({key:grp_members[j], val:member_freqs});
                    if (pairedCh > -1) {
                        parm_list_freq.push({key:pairedCh, val:member_freqs});
                    }
                    //console.log("setFreqsVal: set slave freq");
                }

                if (getEqCorrMode() == "abs") {
                    is_set_q = false;
                    if (curTypes[idx] === 1 || curTypes[idx] === 2) {
                        if (Number(getCurRoutingCfgData(grp_members[j]).S[idx], 'f', 1).toFixed(1) != Number(getCurRoutingCfgData(arr).S[idx], 'f', 1).toFixed(1)) {
                            getCurRoutingCfgData(grp_members[j]).S[idx] = getCurRoutingCfgData(arr).S[idx];
                            if (pairedCh > -1) {
                                getCurRoutingCfgData(pairedCh).S[idx]= getCurRoutingCfgData(arr).S[idx];
                            }
                            is_set_q = true;
                        }
                    } else {
                        if (Number(getCurRoutingCfgData(grp_members[j]).Q[idx], 'f', 1).toFixed(1) != Number(getCurRoutingCfgData(arr).Q[idx], 'f', 1).toFixed(1)) {
                            getCurRoutingCfgData(grp_members[j]).Q[idx] = getCurRoutingCfgData(arr).Q[idx];
                            if (pairedCh > -1) {
                                getCurRoutingCfgData(pairedCh).Q[idx]= getCurRoutingCfgData(arr).Q[idx];
                            }
                            is_set_q = true;
                        }
                    }
                    if (is_set_q) {
                        if (curTypes[idx] === 1 || curTypes[idx] === 2) {
                            parm_list_q.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).S});
                            if (pairedCh > -1) {
                                parm_list_q.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).S});
                            }
                        } else {
                            parm_list_q.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).Q});
                            if (pairedCh > -1) {
                                parm_list_q.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).Q});
                            }
                        }
                        //console.log("setFreqsVal: set slave Q");
                    }

                    is_set_gain = false;
                    if (Number(getCurRoutingCfgData(grp_members[j]).gain[idx], 'f', 1).toFixed(1) != Number(getCurRoutingCfgData(arr).gain[idx], 'f', 1).toFixed(1)) {
                        getCurRoutingCfgData(grp_members[j]).gain[idx] = getCurRoutingCfgData(arr).gain[idx];
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).gain[idx] = getCurRoutingCfgData(arr).gain[idx];
                        }
                        is_set_gain = true;
                    }
                    if (is_set_gain) {
                        parm_list_gain.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).gain});
                        if (pairedCh > -1) {
                            parm_list_gain.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).gain});
                        }
                        //console.log("setFreqsVal: set slave EQ");
                    }
                }
            }
        }

        if (parm_list_eqType.length > 0) {
            devSetMutiChEqType(cb, getCurrentRouting(), parm_list_eqType);
        }
        if (parm_list_q.length > 0) {
            if (curTypes[idx] === 1 || curTypes[idx] === 2) {
                devSetMutiChEqSlope(cb, getCurrentRouting(), parm_list_q);
            } else {
                devSetMutiChQ(cb, getCurrentRouting(), parm_list_q);
            }
        }
        if (parm_list_gain.length > 0) {
            devSetMutiChEQ(cb, getCurrentRouting(), parm_list_gain);
        }
    }

    devSetMutiChFreq(cb, getCurrentRouting(), parm_list_freq);
}

/* 复位通道频点 */
function resetChFreqs(cb, arr) {
    var output_list = [];

    if(getEqCorrMode()!="non") {//不管是相对还是绝对，必须要把频率值对齐，
        var grp=getGroup(arr);// here i should equal to grp
        var grp_members=getGroupMembers(grp);
        output_list = grp_members;
    } else {
        output_list.push(arr);
    }
    resetAllFreqs(cb, output_list);
}

function resetAllFreqs(cb, output_list)
{
    var pairedCh;
    var parm_list = [];
    var exclude_list = [];

    for(var j=0;j<output_list.length;j++)
    {
        if (exclude_list.some(function(item) { return output_list[j] === item; })) {
            continue;
        }

        pairedCh = getPairedBridgeJointChannel(output_list[j]);

        var cur_frq_bands = getFreqBands(getCurRoutingCfgData(output_list[j]).shift_freq.length);
        //console.log("output_list[j] = " + output_list[j] + ", cur_frq_bands: " + JSON.stringify(cur_frq_bands));
        getCurRoutingCfgData(output_list[j]).shift_freq = [];
        if (pairedCh > -1) {
            getCurRoutingCfgData(pairedCh).shift_freq = [];
        }
        for(var i=0;i<cur_frq_bands.length;i++)
        {
            getCurRoutingCfgData(output_list[j]).shift_freq.push(0);

            if (pairedCh > -1) {
                getCurRoutingCfgData(pairedCh).shift_freq.push(0);
            }
        }

        parm_list.push({key:output_list[j], val:cur_frq_bands});

        if (pairedCh > -1) {
            parm_list.push({key:pairedCh, val:cur_frq_bands});
            exclude_list.push(pairedCh);
        }
    }

    return devSetMutiChFreq(cb, getCurrentRouting(), parm_list);
}

function getGainVal(arr)
{
    console.assert(getAllMembersLength()>arr>=0,"getGainVal group sequence out of range");
    return deepCopy(getCurRoutingCfgData(arr).gain);
}

function getQVal(arr)
{
    return deepCopy(getCurRoutingCfgData(arr).Q);
}

function resetChQs(cb, arr)
{
    var output_list = [];

    if(getEqCorrMode()!="non") {//不管是相对还是绝对，必须要把频率值对齐，
        var grp=getGroup(arr);// here i should equal to grp
        var grp_members=getGroupMembers(grp);
        output_list = grp_members;
    } else {
        output_list.push(arr);
    }
    resetAllQs(cb, output_list);
}

function resetAllQs(cb, output_list)
{
    var pairedCh;
    var parm_list = [];
    var exclude_list = [];

    for(var i=0;i<output_list.length;i++)
    {
        if (exclude_list.some(function(item) { return output_list[i] === item; })) {
            continue;
        }

        pairedCh = getPairedBridgeJointChannel(output_list[i]);

        var cur_frq_bands = getFreqBands(getCurRoutingCfgData(output_list[i]).shift_freq.length);
        getCurRoutingCfgData(output_list[i]).Q = [];
        if (pairedCh > -1) {
            getCurRoutingCfgData(pairedCh).Q = [];
        }
        for(var j=0;j<cur_frq_bands.length;j++)
        {
            getCurRoutingCfgData(output_list[i]).Q.push(4.0);

            if (pairedCh > -1) {
                getCurRoutingCfgData(pairedCh).Q.push(4.0);
            }
        }

        parm_list.push({key:output_list[i], val:getCurRoutingCfgData(output_list[i]).Q});

        if (pairedCh > -1) {
            parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).Q});
            exclude_list.push(pairedCh);
        }
    }

    return devSetMutiChQ(cb, getCurrentRouting(), parm_list);
}
function setQVal(cb,arr,idx,new_val)
{
    var curTypes = getEqTypes(arr);
    var grp=getGroup(arr);// here i should equal to grp
    var grp_members=getGroupMembers(grp);
    var parm_list_eqType = [];
    var parm_list_freq = [];
    var parm_list_q = [];
    var parm_list_gain = [];
    var is_set_eqType = false; //是否设置了从通道的EQ类型为当前通道EQ类型
    var is_set_freq = false; //是否设置了从通道的频率值为当前通道的频率值
    var is_set_q = false; //是否设置了从通道的Q值为当前通道Q值
    var is_set_gain = false; //是否设置了从通道的EQ为当前通道的EQ值
    var pairedCh;
    var delta = Number(new_val[idx], 'f', 1) - Number(getCurRoutingCfgData(arr).Q[idx], 'f', 1);
    var desQ;

    if(getEqCorrMode()!="non") //不管是相对还是绝对，必须要把Q值对齐，
    {
        for(var j=0;j<grp_members.length;j++)
        {
            if(grp_members[j]!=arr) {
                pairedCh = getPairedBridgeJointChannel(grp_members[j]);
                if (pairedCh === arr) {
                    continue;
                }

                is_set_eqType = false;
                if (getCurRoutingCfgData(grp_members[j]).type[idx] != curTypes[idx]) {
                    if (getEqCorrMode() == "abs") {
                        getCurRoutingCfgData(grp_members[j]).type[idx] = curTypes[idx];
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).type[idx] = curTypes[idx];
                        }
                        is_set_eqType = true;
                    } else {
                        continue;
                    }
                }
                if (is_set_eqType) {
                    parm_list_eqType.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).type});
                    if (pairedCh > -1) {
                        parm_list_eqType.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).type});
                    }
                }

                is_set_q = false;
                if (getEqCorrMode() == "abs") {
                    if (Number(getCurRoutingCfgData(grp_members[j]).Q[idx], 'f', 1).toFixed(1) != Number(new_val[idx], 'f', 1).toFixed(1)) {
                        getCurRoutingCfgData(grp_members[j]).Q[idx] = new_val[idx];
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).Q[idx] = new_val[idx];
                        }
                        is_set_q = true;
                    }
                } else {
                    desQ = Number(getCurRoutingCfgData(grp_members[j]).Q[idx], 'f', 1) + delta;
                    if (desQ < 0.5) {
                        desQ = 0.5
                    } else if (desQ > 15.0) {
                        desQ = 15.0;
                    }
                    getCurRoutingCfgData(grp_members[j]).Q[idx] = desQ;
                    if (pairedCh > -1) {
                        getCurRoutingCfgData(pairedCh).Q[idx] = desQ;
                    }
                    is_set_q = true;
                }
                if (is_set_q) {
                    parm_list_q.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).Q});
                    if (pairedCh > -1) {
                        parm_list_q.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).Q});
                    }
                    //console.log("setQVal: set slave Q");
                }

                if (getEqCorrMode() == "abs") {
                    /* 当主通道Q值改变时，从通道的频率、Q、EQ都绝对同步至主通道 */
                    is_set_freq = false;
                    if (getCurRoutingCfgData(grp_members[j]).shift_freq[idx] != getCurRoutingCfgData(arr).shift_freq[idx]) {
                        getCurRoutingCfgData(grp_members[j]).shift_freq[idx] = getCurRoutingCfgData(arr).shift_freq[idx];
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).shift_freq[idx] = getCurRoutingCfgData(arr).shift_freq[idx];
                        }
                        is_set_freq = true;
                    }
                    if (is_set_freq) {
                        var freqs = [];
                        for (var m = 0; m < getCurRoutingCfgData(grp_members[j]).shift_freq.length; m++) {
                            freqs.push(parseInt(getCurRoutingCfgData(grp_members[j]).shift_freq[m]) + parseInt(getFreqBands(getCurRoutingCfgData(grp_members[j]).shift_freq.length)[m]));
                        }
                        parm_list_freq.push({key:grp_members[j], val:freqs});
                        if (pairedCh > -1) {
                            parm_list_freq.push({key:pairedCh, val:freqs});
                        }
                        //console.log("setQVal: set slave freq");
                    }

                    is_set_gain = false;
                    if (/*getEqCorrMode() != "bal" && */Number(getCurRoutingCfgData(grp_members[j]).gain[idx], 'f', 1).toFixed(1) != Number(getCurRoutingCfgData(arr).gain[idx], 'f', 1).toFixed(1)) {
                        getCurRoutingCfgData(grp_members[j]).gain[idx] = getCurRoutingCfgData(arr).gain[idx];
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).gain[idx] = getCurRoutingCfgData(arr).gain[idx];
                        }
                        is_set_gain = true;
                    }
                    if (is_set_gain) {
                        parm_list_gain.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).gain});
                        if (pairedCh > -1) {
                            parm_list_gain.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).gain});
                        }
                        //console.log("setQVal: set slave EQ");
                    }
                }
            }
        }
        if (parm_list_eqType.length > 0) {
            devSetMutiChEqType(cb, getCurrentRouting(), parm_list_eqType);
        }
        if (parm_list_freq.length > 0) {
            devSetMutiChFreq(cb, getCurrentRouting(), parm_list_freq);
        }
        if (parm_list_gain.length > 0) {
            devSetMutiChEQ(cb, getCurrentRouting(), parm_list_gain);
        }
    }

//    for(var i=0;i<new_val.length;i++) {
        getCurRoutingCfgData(arr).Q[idx]=new_val[idx];
//    }
    parm_list_q.push({key:arr, val:getCurRoutingCfgData(arr).Q});

    pairedCh = getPairedBridgeJointChannel(arr);
    if (pairedCh > -1) {
//    for(var i=0;i<new_val.length;i++) {
            getCurRoutingCfgData(pairedCh).Q[idx]=new_val[idx];
//    }
        parm_list_q.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).Q});
    }

    devSetMutiChQ(cb, getCurrentRouting(), parm_list_q);
}

function getEqSlopeVal(arr)
{
    return deepCopy(getCurRoutingCfgData(arr).S);
}

function resetChEqSlopes(cb, arr)
{
    var output_list = [];

    if(getEqCorrMode()!="non") {//不管是相对还是绝对，必须要把频率值对齐，
        var grp=getGroup(arr);// here i should equal to grp
        var grp_members=getGroupMembers(grp);
        output_list = grp_members;
    } else {
        output_list.push(arr);
    }
    resetAllEqSlopes(cb, output_list);
}

function resetAllEqSlopes(cb, output_list)
{
    var pairedCh;
    var parm_list = [];
    var exclude_list = [];

    for(var i=0;i<output_list.length;i++)
    {
        if (exclude_list.some(function(item) { return output_list[i] === item; })) {
            continue;
        }

        var cur_frq_bands = getFreqBands(getCurRoutingCfgData(output_list[i]).shift_freq.length);
        getCurRoutingCfgData(output_list[i]).S = [];
        if (pairedCh > -1) {
            getCurRoutingCfgData(pairedCh).S = [];
        }
        for(var j=0;j<cur_frq_bands.length;j++)
        {
            getCurRoutingCfgData(output_list[i]).S.push(1.0);

            if (pairedCh > -1) {
                getCurRoutingCfgData(pairedCh).S.push(1.0);
            }
        }
        parm_list.push({key:output_list[i], val:getCurRoutingCfgData(output_list[i]).S});

        if (pairedCh > -1) {
            parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).S});
            exclude_list.push(pairedCh);
        }
    }

    return devSetMutiChEqSlope(cb, getCurrentRouting(), parm_list);
}

function setEqSlopeVal(cb,arr,idx,new_val)
{
    var curTypes = getEqTypes(arr);
    var grp=getGroup(arr);// here i should equal to grp
    var grp_members=getGroupMembers(grp);
    var parm_list_eqType = [];
    var parm_list_freq = [];
    var parm_list_S = [];
    var parm_list_gain = [];
    var is_set_eqType = false; //是否设置了从通道的EQ类型为当前通道EQ类型
    var is_set_freq = false; //是否设置了从通道的频率值为当前通道的频率值
    var is_set_S = false; //是否设置了从通道的S值为当前通道S值
    var is_set_gain = false; //是否设置了从通道的EQ为当前通道的EQ值
    var pairedCh;
    var delta = Number(new_val[idx], 'f', 1) - Number(getCurRoutingCfgData(arr).S[idx], 'f', 1);
    var desS;

    if(getEqCorrMode()!="non") //不管是相对还是绝对，必须要把S值对齐，
    {
        for(var j=0;j<grp_members.length;j++)
        {
            if(grp_members[j]!=arr) {
                pairedCh = getPairedBridgeJointChannel(grp_members[j]);
                if (pairedCh === arr) {
                    continue;
                }

                is_set_eqType = false;
                if (getCurRoutingCfgData(grp_members[j]).type[idx] != curTypes[idx]) {
                    if (getEqCorrMode() == "abs") {
                        getCurRoutingCfgData(grp_members[j]).type[idx] = curTypes[idx];
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).type[idx] = curTypes[idx];
                        }
                        is_set_eqType = true;
                    } else {
                        continue;
                    }
                }
                if (is_set_eqType) {
                    parm_list_eqType.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).type});
                    if (pairedCh > -1) {
                        parm_list_eqType.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).type});
                    }
                }

                is_set_S = false;
                if (getEqCorrMode() == "abs") {
                    if (Number(getCurRoutingCfgData(grp_members[j]).S[idx], 'f', 1).toFixed(1) != Number(new_val[idx], 'f', 1).toFixed(1)) {
                        getCurRoutingCfgData(grp_members[j]).S[idx] = new_val[idx];
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).S[idx] = new_val[idx];
                        }
                        is_set_S = true;
                    }
                } else {
                    desS = Number(getCurRoutingCfgData(grp_members[j]).S[idx], 'f', 1) + delta;
                    if (desS < 0.5) {
                        desS = 0.5
                    } else if (desS > 2.0) {
                        desS = 2.0;
                    }
                    getCurRoutingCfgData(grp_members[j]).S[idx] = desS;
                    if (pairedCh > -1) {
                        getCurRoutingCfgData(pairedCh).S[idx] = desS;
                    }
                    is_set_S = true;
                }
                if (is_set_S) {
                    parm_list_S.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).S});
                    if (pairedCh > -1) {
                        parm_list_S.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).S});
                    }
                    //console.log("setSVal: set slave S");
                }

                if (getEqCorrMode() == "abs") {
                /* 当主通道S值改变时，从通道的频率、S、EQ都绝对同步至主通道 */
                is_set_freq = false;
                if (getCurRoutingCfgData(grp_members[j]).shift_freq[idx] != getCurRoutingCfgData(arr).shift_freq[idx]) {
                    getCurRoutingCfgData(grp_members[j]).shift_freq[idx] = getCurRoutingCfgData(arr).shift_freq[idx];
                    if (pairedCh > -1) {
                        getCurRoutingCfgData(pairedCh).shift_freq[idx] = getCurRoutingCfgData(arr).shift_freq[idx];
                    }
                    is_set_freq = true;
                }
                if (is_set_freq) {
                    var freqs = [];
                    for (var m = 0; m < getCurRoutingCfgData(grp_members[j]).shift_freq.length; m++) {
                        freqs.push(parseInt(getCurRoutingCfgData(grp_members[j]).shift_freq[m]) + parseInt(getFreqBands(getCurRoutingCfgData(grp_members[j]).shift_freq.length)[m]));
                    }
                    parm_list_freq.push({key:grp_members[j], val:freqs});
                    if (pairedCh > -1) {
                        parm_list_freq.push({key:pairedCh, val:freqs});
                    }
                    //console.log("setSVal: set slave freq");
                }

                is_set_gain = false;
                if (/*getEqCorrMode() != "bal" && */Number(getCurRoutingCfgData(grp_members[j]).gain[idx], 'f', 1).toFixed(1) != Number(getCurRoutingCfgData(arr).gain[idx], 'f', 1).toFixed(1)) {
                    getCurRoutingCfgData(grp_members[j]).gain[idx] = getCurRoutingCfgData(arr).gain[idx];
                    if (pairedCh > -1) {
                        getCurRoutingCfgData(pairedCh).gain[idx] = getCurRoutingCfgData(arr).gain[idx];
                    }
                    is_set_gain = true;
                }
                if (is_set_gain) {
                    parm_list_gain.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).gain});
                    if (pairedCh > -1) {
                        parm_list_gain.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).gain});
                    }
                    //console.log("setSVal: set slave EQ");
                }
                }
            }
        }

        if (parm_list_eqType.length > 0) {
            devSetMutiChEqType(cb, getCurrentRouting(), parm_list_eqType);
        }
        if (parm_list_freq.length > 0) {
            devSetMutiChFreq(cb, getCurrentRouting(), parm_list_freq);
        }
        if (parm_list_gain.length > 0) {
            devSetMutiChEQ(cb, getCurrentRouting(), parm_list_gain);
        }
    }

//    for(var i=0;i<new_val.length;i++) {
        getCurRoutingCfgData(arr).S[idx]=new_val[idx];
//    }
    parm_list_S.push({key:arr, val:getCurRoutingCfgData(arr).S});

    pairedCh = getPairedBridgeJointChannel(arr);
    if (pairedCh > -1) {
//    for(var i=0;i<new_val.length;i++) {
            getCurRoutingCfgData(pairedCh).S[idx]=new_val[idx];
//    }
        parm_list_S.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).S});
    }
    devSetMutiChEqSlope(cb, getCurrentRouting(), parm_list_S);
}

