/* 是否选择了光纤作为第13或14路输入源类型 */
function isFiberChecked(seq, strSide)
{
    var state = true;
    if (strSide == "left") {
        state = (getRoutingCfgData(seq, DIGITAL).fiber.left > 0)?true:false;
    } else if (strSide == "right") {
        state = (getRoutingCfgData(seq, DIGITAL).fiber.right > 0)?true:false;
    }

    return state;
}

