var levelState=[];
var lastLevelState=[];
var levelStateChanged = false;
function updLevelState(idx,level){
    levelState[idx]=level;
    //console.log("----updLevelState----levelState["+idx+"]="+ levelState[idx]+",level="+level)
}
function getLevelState(idx){
    return levelState[idx];
}
function getLastLevelState(idx) {
    return lastLevelState[idx];
}
function getLevelStateChangedList() {
    var changedList = [];
    for (var i = 0; i < levelState.length; i++) {
        if (levelState[i] != lastLevelState[i]) {
            changedList.push(i)
        }
    }
    return changedList;
}
function saveLastLevelStates() {
    return lastLevelState = deepCopy(levelState);
}

/* 保存高低电平变化状态（值在pop后被重置为false） */
function pushLevelStateChanged() {
    levelStateChanged = true;
}

/* 获取高低电平变化状态(仅在push后的第一次调用反馈真实状态) */
function popLevelStateChanged() {
    var isChanged = levelStateChanged;
    levelStateChanged = false;
    return isChanged;
}

/**获取高低电平参数，当不同的时候才赋值，避免发送相同命令**/
function getLevelParm(idx,idx2,level){
    var parms="";
    if(getLevelState(idx)!=level){
        parms=parms+ idx+":"+level
    }
    if(getLevelState(idx2)!=level){
        if(parms!=""){
            parms=parms  +"?"
        }
        parms=parms  +(idx2)+":"+level
    }
    //console.log("getLevelParm--------->idx="+idx+",idx2="+idx2+",level="+level+",parms="+parms);
    return parms;
}

/*
return the source(s) of the wanted  output(indexed by 'seq')
input:the sequence number of input type:number
output:array of input groups, null if haven't any connections.
[
{src:xxx,rate:xxx},
...
]
*/
function getSrc(seq, routing, srcType)
{
    if(seq >= getAllIndepOutputsLength())
    {
        console.log("getSrc:parameter error!" + " seq = " + seq + ", routing = " + routing + ", srcType = " + srcType);
        return null;
    }

    var desRate_0 = isConfigSourceBydB() ? -100.0 : 0;

    var retSrc = [];
    var sources;
    if (routing == DIGITAL || routing == ANALOG || routing == BLUETOOTH || routing == SPDIF || routing == KARAOKE || routing == SOUNDCARD || routing == A2B || routing == SURROUND) {
        var i;
        switch (routing) {
        case ANALOG:
            sources = getOutputRoutingCfgData(seq, ANALOG).sources;
            for (i = 0; i < sources.length; i++) {
                retSrc.push(sources[i]);
            }
            if (retSrc.length < 16) { //不足16条则补齐
                for (i = retSrc.length; i < 16; i++) {
                    retSrc.push({src:-1, rate:desRate_0, order:-1});
                }
            }
            break;
        case DIGITAL:
            if(isHasDigitalRoute()) {
                sources = getOutputRoutingCfgData(seq, DIGITAL).sources;
                for (i = 0; i < sources.length; i++) {
                    if (srcType != null) {
                        switch(srcType) {
                        case DIGITAL_SRC_TYPE_FIBER:
                            if (sources[i].src == 2 || sources[i].src == 3) { //光纤源
                                retSrc.push(sources[i]);
                            }
                            break;
                        case DIGITAL_SRC_TYPE_AXIS:
                            if (sources[i].src == 0 || sources[i].src == 1) { //同轴源
                                retSrc.push(sources[i]);
                            }
                            break;
                        }
                    } else {
                        retSrc.push(sources[i]);
                    }
                }
                var maxLength = (srcType != null)?2:sources.length;
                if (retSrc.length < maxLength) { //不足2条则补齐
                    for (i = retSrc.length; i < maxLength; i++) {
                        retSrc.push({src:-1, rate:desRate_0, order:-1});
                    }
                }
            }
            break;
        case BLUETOOTH:
            if(isHasBluetoothModule()) {
                sources = getOutputRoutingCfgData(seq, BLUETOOTH).sources;
                for (i = 0; i < sources.length; i++) {
                    retSrc.push(sources[i]);
                }
                if (retSrc.length < 2) { //不足2条则补齐
                    for (i = retSrc.length; i < 2; i++) {
                        retSrc.push({src:-1, rate:desRate_0, order:-1});
                    }
                }
            }
            break;
        case SPDIF:
            if(isVSRxGxHasSpdifRoute()) {
                sources = getOutputRoutingCfgData(seq, SPDIF).sources;
                for (i = 0; i < sources.length; i++) {
                    if (srcType != null) {
                        switch(srcType) {
                        case DIGITAL_SRC_TYPE_FIBER:
                            if (sources[i].src == 2 || sources[i].src == 3) { //光纤源
                                retSrc.push(sources[i]);
                            }
                            break;
                        case DIGITAL_SRC_TYPE_AXIS:
                            if (sources[i].src == 0 || sources[i].src == 1) { //同轴源
                                retSrc.push(sources[i]);
                            }
                            break;
                        }
                    } else {
                        retSrc.push(sources[i]);
                    }
                }
                var maxSpdifLength = (srcType != null)?2:sources.length;
                if (retSrc.length < maxSpdifLength) { //不足2条则补齐
                    for (i = retSrc.length; i < maxSpdifLength; i++) {
                        retSrc.push({src:-1, rate:desRate_0, order:-1});
                    }
                }
            }
            break;
        case KARAOKE:
            //console.log("getSrc: isHasKaraokeRoute() = " + isHasKaraokeRoute());
            if(isHasKaraokeRoute()) {
                sources = getOutputRoutingCfgData(seq, KARAOKE).sources;
                //console.log("getSrc: KARAOKE = " + JSON.stringify(sources)); //Debug
                for (i = 0; i < sources.length; i++) {
                    retSrc.push(sources[i]);
                }
                if (retSrc.length < getKaraokeSrcLength()) { //不足4条则补齐
                    for (i = retSrc.length; i < getKaraokeSrcLength(); i++) {
                        retSrc.push({src:-1, rate:desRate_0, order:-1});
                    }
                }
            }
            break;
        case SOUNDCARD:
            if(isHasSoundCardRoute()) {
                sources = getOutputRoutingCfgData(seq, SOUNDCARD).sources;
                //console.log("getSrc: SOUNDCARD = " + JSON.stringify(sources)); //Debug
                for (i = 0; i < sources.length; i++) {
                    retSrc.push(sources[i]);
                }
                if (retSrc.length < getSoundCardSrcLength()) { //不足2条则补齐
                    for (i = retSrc.length; i < getSoundCardSrcLength(); i++) {
                        retSrc.push({src:-1, rate:desRate_0, order:-1});
                    }
                }
            }
            break;
        case A2B:
            if (isHasA2BRoute()) {
                sources = getOutputRoutingCfgData(seq, A2B).sources;
                for (i = 0; i < sources.length; i++) {
                    retSrc.push(sources[i]);
                }
                if (retSrc.length < 16) { //不足16条则补齐
                    for (i = retSrc.length; i < 16; i++) {
                        retSrc.push({src:-1, rate:desRate_0, order:-1});
                    }
                }
            }
            break;
        case SURROUND:
            if(isHasSurroundRoute()) {
                sources = getOutputRoutingCfgData(seq, SURROUND).sources;
                //console.log("getSrc: SURROUND = " + JSON.stringify(sources)); //Debug
                for (i = 0; i < sources.length; i++) {
                    retSrc.push(sources[i]);
                }
                if (retSrc.length < 8) { //不足8条则补齐
                    for (i = retSrc.length; i < 8; i++) {
                        retSrc.push({src:-1, rate:desRate_0, order:-1});
                    }
                }
            }
            break;
        default:
            return null;
        }
    } else if (routing == null) {
        sources = getOutputRoutingCfgData(seq, ANALOG).sources;
        for (i = 0; i < sources.length; i++) {
            retSrc.push(sources[i]);
        }
        if(isHasDigitalRoute()) {
            sources = getOutputRoutingCfgData(seq, DIGITAL).sources;
            for (i = 0; i < sources.length; i++) {
                if (!isVSRxSeriesDevice() && srcType != null) {
                    switch(srcType) {
                    case DIGITAL_SRC_TYPE_FIBER:
                        if (sources[i].src == 2 || sources[i].src == 3) { //光纤源
                            retSrc.push(sources[i]);
                        }
                        break;
                    case DIGITAL_SRC_TYPE_AXIS:
                        if (sources[i].src == 0 || sources[i].src == 1) { //同轴源
                            retSrc.push(sources[i]);
                        }
                        break;
                    }
                } else {
                    retSrc.push(sources[i]);
                }
            }
        }
        if(isHasBluetoothModule()) {
            sources = getOutputRoutingCfgData(seq, BLUETOOTH).sources;
            for (i = 0; i < sources.length; i++) {
                retSrc.push(sources[i]);
            }
        }
        if (isVSRxGxHasSpdifRoute()) {
            sources = getOutputRoutingCfgData(seq, SPDIF).sources;
            for (i = 0; i < sources.length; i++) {
                if (srcType != null) {
                    switch(srcType) {
                    case DIGITAL_SRC_TYPE_FIBER:
                        if (sources[i].src == 2 || sources[i].src == 3) { //光纤源
                            retSrc.push(sources[i]);
                        }
                        break;
                    case DIGITAL_SRC_TYPE_AXIS:
                        if (sources[i].src == 0 || sources[i].src == 1) { //同轴源
                            retSrc.push(sources[i]);
                        }
                        break;
                    }
                } else {
                    retSrc.push(sources[i]);
                }
            }
        }
        if(isHasKaraokeRoute()) {
            sources = getOutputRoutingCfgData(seq, KARAOKE).sources;
            for (i = 0; i < sources.length; i++) {
                retSrc.push(sources[i]);
            }
        }
        if(isHasSoundCardRoute()) {
            sources = getOutputRoutingCfgData(seq, SOUNDCARD).sources;
            for (i = 0; i < sources.length; i++) {
                retSrc.push(sources[i]);
            }
        }
        if (isHasA2BRoute()) {
            sources = getOutputRoutingCfgData(seq, A2B).sources;
            for (i = 0; i < sources.length; i++) {
                retSrc.push(sources[i]);
            }
        }
        if(isHasSurroundRoute()) {
            sources = getOutputRoutingCfgData(seq, SURROUND).sources;
            for (i = 0; i < sources.length; i++) {
                retSrc.push(sources[i]);
            }
        }
    }

    return retSrc;
}

