/*
set the sources of the  output(indexed by seq).
caution: don't split src into subgroup to set,we don't support it now.
*/
function dbSetChSrc(seq,routing,srcs)
{
    if(seq>=getAllIndepOutputsLength())
    {
        console.log("dbSetChSrc:parameter seq error!"+seq);
        return false;
    }

    var desRate_0 = isConfigSourceBydB() ? -100.0 : 0;

    var desSrcs = srcs;
    if(srcs.length != getOutputRoutingCfgData(seq, routing).sources.length)
    {
        if ((routing == DIGITAL || routing == SPDIF) && srcs.length == 2) { //源数组中仅包含两个对象时的特殊处理
            /* 保留对立数字源配置值 */
//            var typeSources = getSrc(seq, routing, (getCurrentDigitalSrcType(routing) == DIGITAL_SRC_TYPE_FIBER)?DIGITAL_SRC_TYPE_AXIS:DIGITAL_SRC_TYPE_FIBER); //获取对立数字源
//            for(var i = 0; i < srcs.length; i++) {
//                typeSources.push(srcs[i]);
//            }
//            desSrcs = typeSources;
            /* 复制当前数字源配置值至对立数字源 */
            var nAddPos;
            var typeSources = deepCopy(srcs);
            for(var i = 0; i < srcs.length; i++) {
                var item = {src:-1, rate:desRate_0, order:-1};
                if (srcs[i].src != -1) {
                    nAddPos = (srcs[i].src < 2)?2:-2;
                    item.src = srcs[i].src + nAddPos;
                    item.order = srcs[i].order;
                }
                item.rate = srcs[i].rate;
                typeSources.push(item);
            }
            desSrcs = typeSources;
        } else {
            console.error("dbSetChSrc:parameter sources error!");
            return false;
        }
    }
    getOutputRoutingCfgData(seq, routing).sources=desSrcs;
    return true;
}

function setSrc(cb,seq,routing,srcs)
{
    if (dbSetChSrc(seq, routing, srcs) == false) {
        return null;
    }

    var desRate_0 = isConfigSourceBydB() ? -100.0 : 0;

    var desSrcs;
    var idx;
    if (routing === ANALOG && levelState != "" && getLevelStateCache().length > 0 && getAnalogSrcLength() < getRealSrcLength()) {
        var i, j;
        var maxOrder = -1; //最大排序编号
        var maxOrderIndex = -1; //最大排序编号的条目索引(即当前新增源编号)
        var parm = "";
        var levelIdx;
        var is_analog_src_changed;

        /* 保存修改前的高低电平状态 */
        saveLastLevelStates();

        /* 搜索新增的输入源 */
        for (i = 0; i < srcs.length; i++) {
            if (srcs[i].order > maxOrder) {
                maxOrder = srcs[i].order;
                maxOrderIndex = i;
            }
        }

//        /* 更改可能存在的高低电平互斥标识 */
//        if (maxOrderIndex > -1) {
//            if (srcs[maxOrderIndex].src >= getHighSrcLength()) {
//                 idx = srcs[maxOrderIndex].src - offset;
//                if (idx % 2 == 0) {
//                    parm = getLevelParm(idx, idx + 1, LEVEL_LOW);
//                    updLevelState(idx + 1, LEVEL_LOW);
//                } else {
//                    parm = getLevelParm(idx - 1, idx, LEVEL_LOW);
//                    updLevelState(idx - 1, LEVEL_LOW);
//                }
//                updLevelState(idx, LEVEL_LOW);
//                if (parm != "") {
//                    devSetLevelState(cb, parm);
//                }
//            } else {
//                idx = srcs[maxOrderIndex].src
//                if (idx % 2 == 0) {
//                    parm = getLevelParm(idx, idx + 1, LEVEL_HIGH);
//                    updLevelState(idx + 1, LEVEL_HIGH);
//                } else {
//                    parm = getLevelParm(idx - 1, idx, LEVEL_HIGH);
//                    updLevelState(idx - 1, LEVEL_HIGH);
//                }
//                updLevelState(idx, LEVEL_HIGH);
//                if(parm != ""){
//                    devSetLevelState(cb, parm);
//                }
//            }
//        }

        /* 更新所有输出通道中与新增输入源互斥的输入源的类型 */
        for (i = 0; i < getAllIndepOutputsLength(); i++) {
            is_analog_src_changed = false;
            desSrcs = getSrc(i, routing, null);

            if (i === seq) {
                var startOrder = 3;
                var reduceCnt = 0;

                for (j = 0; j < desSrcs.length; j++) {
                    if (desSrcs[j].src < 0) {
                        continue;
                    }
                    if(desSrcs[j].src >= getHighSrcLength()){//低电平
                        levelIdx = desSrcs[j].src - getOffset();
                        if (getLevelState(levelIdx) != LEVEL_LOW) {
                            desSrcs[j].src = levelIdx;
                            if (desSrcs[j].src == srcs[maxOrderIndex].src && desSrcs[j].order != srcs[maxOrderIndex].order) { //当前主输出通道如果发现同名输入源则清除(后续代码需要进行重排序)
                                startOrder = desSrcs[j].order < startOrder ? desSrcs[j].order : startOrder;
                                reduceCnt++;
                                desSrcs[j].src = -1;
                                desSrcs[j].rate = desRate_0;
                                desSrcs[j].order = -1;
                            }
                            is_analog_src_changed = true;
                        }
                    } else { //高电平
                        levelIdx = desSrcs[j].src;
                        if(getLevelState(levelIdx) != LEVEL_HIGH){
                            desSrcs[j].src = levelIdx + getOffset();
                            if (desSrcs[j].src == srcs[maxOrderIndex].src && desSrcs[j].order != srcs[maxOrderIndex].order) { //当前主输出通道如果发现同名输入源则清除(后续代码需要进行重排序)
                                startOrder = desSrcs[j].order < startOrder ? desSrcs[j].order : startOrder;
                                reduceCnt++;
                                desSrcs[j].src = -1;
                                desSrcs[j].rate = desRate_0;
                                desSrcs[j].order = -1;
                            }
                            is_analog_src_changed = true;
                        }
                    }
                }

                /* 如果需要则进行一次重排序 */
                if (reduceCnt > 0) {
                    /* 为当前路由赋值 */
                    for(j = 0; j< desSrcs.length; j++)
                    {
                        if(desSrcs[j].src != -1) {
                            if (desSrcs[j].order >= startOrder) {
                                desSrcs[j].order -= reduceCnt; //下标向下对齐
                            }
                        }
                    }
                    /* 为其它路由赋值 */
                    var digital_src = getSrc(i, DIGITAL, getCurrentDigitalSrcType(DIGITAL)); //获取当前数字源类型下的数字源，返回数组长度2
                    var is_digital_src_changed = false; //非当前路由配置1值是否发生变化
                    for (j = 0; j < digital_src.length; j++) {
                        if (digital_src[j].src != -1) {
                            if (digital_src[j].order >= startOrder) {
                                digital_src[j].order -= reduceCnt; //下标向下对齐
                                is_digital_src_changed = true; //指示值发生变化
                            }
                        }
                    }
                    if (is_digital_src_changed) {
                        dbSetChSrc(i, DIGITAL, digital_src);
                    }
                    if (!isDARoutingMixed()) {
                        var bluetooth_src = getSrc(i, BLUETOOTH, null); //获取蓝牙源，返回数组长度2
                        var is_bluetooth_src_changed = false; //非当前路由配置1值是否发生变化
                        for (j = 0; j < bluetooth_src.length; j++) {
                            if (bluetooth_src[j].src != -1) {
                                if (bluetooth_src[j].order >= startOrder) {
                                    bluetooth_src[j].order -= reduceCnt; //下标向下对齐
                                    is_bluetooth_src_changed = true; //指示值发生变化
                                }
                            }
                        }
                        if (is_bluetooth_src_changed) {
                            dbSetChSrc(i, BLUETOOTH, bluetooth_src);
                        }
                    }
                    if (isVSRxGxHasSpdifRoute()) {
                        var spdif_src = getSrc(i, SPDIF, getCurrentDigitalSrcType(SPDIF)); //获取当前数字源类型下的数字源，返回数组长度2
                        var is_spdif_src_changed = false; //非当前路由配置1值是否发生变化
                        for (j = 0; j < spdif_src.length; j++) {
                            if (spdif_src[j].src != -1) {
                                if (spdif_src[j].order >= startOrder) {
                                    spdif_src[j].order -= reduceCnt; //下标向下对齐
                                    is_spdif_src_changed = true; //指示值发生变化
                                }
                            }
                        }
                        if (is_spdif_src_changed) {
                            dbSetChSrc(i, SPDIF, spdif_src);
                        }
                    }
                    if (isHasKaraokeRoute()) {
                        var karaoke_src = getSrc(i, KARAOKE, null); //获取当前数字源类型下的数字源，返回数组长度2
                        var is_karaoke_src_changed = false; //非当前路由配置1值是否发生变化
                        for (j = 0; j < karaoke_src.length; j++) {
                            if (karaoke_src[j].src != -1) {
                                if (karaoke_src[j].order >= startOrder) {
                                    karaoke_src[j].order -= reduceCnt; //下标向下对齐
                                    is_karaoke_src_changed = true; //指示值发生变化
                                }
                            }
                        }
                        if (is_karaoke_src_changed) {
                            dbSetChSrc(i, KARAOKE, karaoke_src);
                        }
                    }
                    if (isHasSoundCardRoute()) {
                        var soundCard_src = getSrc(i, SOUNDCARD, null); //获取当前声卡源类型下的数字源，返回数组长度2
                        var is_soundCard_src_changed = false; //非当前路由配置1值是否发生变化
                        for (j = 0; j < soundCard_src.length; j++) {
                            if (soundCard_src[j].src != -1) {
                                if (soundCard_src[j].order >= startOrder) {
                                    soundCard_src[j].order -= reduceCnt; //下标向下对齐
                                    is_soundCard_src_changed = true; //指示值发生变化
                                }
                            }
                        }
                        if (is_soundCard_src_changed) {
                            dbSetChSrc(i, SOUNDCARD, soundCard_src);
                        }
                    }
                    if (isHasA2BRoute()) {
                        var A2B_src = getSrc(i, A2B, null); //获取当前声卡源类型下的数字源，返回数组长度2
                        var is_A2B_src_changed = false; //非当前路由配置1值是否发生变化
                        for (j = 0; j < A2B_src.length; j++) {
                            if (A2B_src[j].src != -1) {
                                if (A2B_src[j].order >= startOrder) {
                                    A2B_src[j].order -= reduceCnt; //下标向下对齐
                                    is_A2B_src_changed = true; //指示值发生变化
                                }
                            }
                        }
                        if (is_A2B_src_changed) {
                            dbSetChSrc(i, A2B, A2B_src);
                        }
                    }
                    if (isHasSurroundRoute()) {
                        var surround_src = getSrc(i, SURROUND, null); //获取当前天空全景声源类型下的数字源，返回数组长度4
                        var is_surround_src_changed = false; //值是否发生变化
                        for (j = 0; j < surround_src.length; j++) {
                            if (surround_src[j].src != -1) {
                                if (surround_src[j].order >= startOrder) {
                                    surround_src[j].order -= reduceCnt; //下标向下对齐
                                    is_surround_src_changed = true; //指示值发生变化
                                }
                            }
                        }
                        if (is_surround_src_changed) {
                            dbSetChSrc(i, SURROUND, surround_src);
                        }
                    }
                }
            } else {
                for (j = 0; j < desSrcs.length; j++) {
                    if (desSrcs[j].src < 0) {
                        continue;
                    }
                    if(desSrcs[j].src >= getHighSrcLength()){//低电平
                        levelIdx = desSrcs[j].src - getOffset();
                        if (getLevelState(levelIdx) != LEVEL_LOW) {
                            desSrcs[j].src = levelIdx;
                            is_analog_src_changed = true;
                        }
                    } else { //高电平
                        levelIdx = desSrcs[j].src;
                        if(getLevelState(levelIdx) != LEVEL_HIGH){
                            desSrcs[j].src = levelIdx + getOffset();
                            is_analog_src_changed = true;
                        }
                    }
                }
            }

            if (is_analog_src_changed) {
                is_analog_src_changed = false;
                dbSetChSrc(i, routing, desSrcs);
                pushLevelStateChanged();
            }
        }

        if (isHasDtsModule()) {
            /* 更新所有DTS环绕声源中与新增输入源互斥的输入源的类型 */
            var is_dts_analog_src_changed = false;
            for (i = 0; i < DtsSrcCfgData.length; i++) {
                is_dts_analog_src_changed = false;
                desSrcs = getDtsInputSrcs(i, routing, null);

                for (j = 0; j < desSrcs.length; j++) {
                    if (desSrcs[j].src < 0) {
                        continue;
                    }
                    if(desSrcs[j].src >= getHighSrcLength()){//低电平
                        levelIdx = desSrcs[j].src - getOffset();
                        if (getLevelState(levelIdx) != LEVEL_LOW) {
                            desSrcs[j].src = levelIdx;
                            is_dts_analog_src_changed = true;
                        }
                    } else { //高电平
                        levelIdx = desSrcs[j].src;
                        if(getLevelState(levelIdx) != LEVEL_HIGH){
                            desSrcs[j].src = levelIdx + getOffset();
                            is_dts_analog_src_changed = true;
                        }
                    }
                }

                if (is_dts_analog_src_changed) {
                    is_dts_analog_src_changed = false;
                    dbSetDtsInputChSrc(i, routing, desSrcs);
                    pushLevelStateChanged();
                }
            }
        }
    }

    /* 发送新输入源配置到设备端 */
    var val_list=[];
    if (routing == DIGITAL) {
        if (isVSRxSeriesDevice()) {
            val_list = [desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0];
            desSrcs = getSrc(seq, ANALOG, null);

            for (i = 0; i < desSrcs.length; i++) {
                if (desSrcs[i].src > -1) {
                    if (/*routing == ANALOG && */desSrcs[i].src >= getHighSrcLength()){
                        idx=desSrcs[i].src-offset;
                        val_list[idx] = desSrcs[i].rate;
                    } else {
                        idx=desSrcs[i].src;
                        val_list[idx] = desSrcs[i].rate;
                    }
                }
            }
        } else {
            for(i=0;i<getDigitalSrcLength();i++){
                val_list.push(desRate_0); //数字输入源
            }
        }
    } else if (routing == BLUETOOTH) {
        val_list = [desRate_0, desRate_0];
    } else if (routing == SPDIF) {
        for(i=0;i<getSpdifSrcLength();i++){
            val_list.push(desRate_0); //SPDIF输入源
        }
    } else if (routing == KARAOKE) {
        for(i=0;i<getKaraokeSrcLength();i++){
            val_list.push(desRate_0); //KARAOKE输入源
        }
    } else if (routing == SOUNDCARD) {
        for(i=0;i<getSoundCardSrcLength();i++){
            val_list.push(desRate_0); //声卡输入源
        }
    } else if (routing == A2B) {
        for(i=0;i<getDynamicA2BSrcLength();i++){
            val_list.push(desRate_0); //A2B输入源
        }
    } else if (routing == SURROUND) {
        for(i=0;i<getSurroundSrcLength();i++){
            val_list.push(desRate_0); //天空全景声输入源
        }
    } else {
        if (isVSRxSeriesDevice()) {
            val_list = [desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0];
            desSrcs = getSrc(seq, DIGITAL, null);
            for (i = 0; i < desSrcs.length; i++) {
                if (desSrcs[i].src > -1) {
                    idx=desSrcs[i].src + getAnalogSrcLength();
                    val_list[idx] = desSrcs[i].rate;
                }
            }
        } else {
            for(i=0;i<getAnalogSrcLength();i++){
                val_list.push(desRate_0); //模拟输入源
            }
        }
    }
    desSrcs = getSrc(seq, routing, null);
    for (i = 0; i < desSrcs.length; i++) {
        if (desSrcs[i].src > -1) {
            if (routing == ANALOG && desSrcs[i].src >= getHighSrcLength()){
                idx=desSrcs[i].src-offset;
                val_list[idx] = desSrcs[i].rate;
            } else {
                idx=desSrcs[i].src + (isVSRxSeriesDevice() && routing === DIGITAL ? getAnalogSrcLength() : 0);
                val_list[idx] = desSrcs[i].rate;
            }
        }
    }

    //devSetChSrc(cb, routing, seq, val_list);
    return val_list;
}

function sendSrc(cb, routing, parm_list)
{
    return devSetMutiChSrc(cb, routing, parm_list);
}

