/* 用数据库值设置设备所有天空全景声输入源配置 */
function setAllSurroundInputCfgByDB(cb)
{
    var desRate_0 = isConfigSourceBydB() ? -100.0 : 0;

    var cmdIdx = -1;
    var routingList = [];
    if (isHasDigitalRoute()) {
        routingList.push(DIGITAL);
    }
    routingList.push(ANALOG); //默认仅处理模拟路由
    if (isHasBluetoothModule()) {
        routingList.push(BLUETOOTH);
    }
    if (isVSRxGxHasSpdifRoute()) {
        routingList.push(SPDIF);
    }
    if (isHasSoundCardRoute()) {
        routingList.push(SOUNDCARD);
    }
    if (isHasA2BRoute()) {
        routingList.push(A2B);
    }

    setAllSurroundInputPhaseByDB(cb);
    setAllSurroundInputDelayByDB(cb);
    setAllSurroundInputMuteByDB(cb);
    setAllSurroundInputVolumeByDB(cb);

    for (var routingIdx = 0; routingIdx < routingList.length; routingIdx++) {
        var parm_list = [];
        for(var i = 0; i < getSurroundInputSrcLength(); i++) {
            var j;
            var val_list = [];
            if (routingList[routingIdx] == ANALOG) {
                for(j=0;j<getAnalogSrcLength();j++){
                    val_list.push(desRate_0); //模拟输入源
                }
            } else if (routingList[routingIdx] == BLUETOOTH) {
                val_list = [desRate_0, desRate_0]; //2个蓝牙输入源
            } else if (routingList[routingIdx] == SPDIF) {
                for(j=0;j<getSpdifSrcLength();j++){
                    val_list.push(desRate_0); //SPDIF输入源
                }
            } else if (routingList[routingIdx] == SOUNDCARD) {
                for(j=0;j<getSoundCardSrcLength();j++){
                    val_list.push(desRate_0); //声卡输入源
                }
            } else if (routingList[routingIdx] == A2B) {
                for(j=0;j<getA2BSrcLength();j++){
                    val_list.push(desRate_0); //A2B输入源
                }
           } else {
                for(j=0;j<getDigitalSrcLength();j++){
                    val_list.push(desRate_0); //数字输入源
                }
            }
            if (getSurroundInputCfgData(i, routingList[routingIdx]) == null) {
                return;
            }
            var srcCount = getSurroundInputCfgData(i, routingList[routingIdx]).sources.length
//            console.log("srcCount="+srcCount);
            for(j = 0; j < srcCount; j++)
            {
                /* 避免导入配置时，最大增益值越界 */
                if (isConfigSourceBydB() && getSurroundInputCfgData(i, routingList[routingIdx]).sources[j].rate > getSourceMaxdB(routingList[routingIdx])) {
                    getSurroundInputCfgData(i, routingList[routingIdx]).sources[j].rate = getSourceMaxdB(routingList[routingIdx]);
                }

                var srcItem = getSurroundInputCfgData(i, routingList[routingIdx]).sources[j];
//                console.log("srcItem="+srcItem.src+",srcItem.rate="+srcItem.rate);
                var idx=srcItem.src;
                if (srcItem.src != -1) {
                    if (routingList[routingIdx] == ANALOG) {
                        if(idx>=getHighSrcLength()){
                            idx=idx-getOffset();
                        }
                    }
                    val_list[idx] = srcItem.rate;
                }
            }

            parm_list.push({key:i, val:val_list});
        }

        cmdIdx = devSetMutiChSurroundInputSrc(cb, routingList[routingIdx], parm_list);
    }

    return cmdIdx;
}

