//                var resultGain = Number(getCurRoutingCfgData(grp_members[j]).gain[idx], 'f', 1) + gain_delta;
//                var gainRange = getGainRange();
//                if (resultGain < gainRange.min || resultGain > gainRange.max) {
//                    getCurRoutingGraphData(grp_members[j]).graph_data_items[idx] = funGenDataByVal(getFreqBands(getCurRoutingCfgData(grp_members[j]).shift_freq.length)[idx] + getCurRoutingCfgData(grp_members[j]).shift_freq[idx], getCurRoutingCfgData(grp_members[j]).Q[idx], getCurRoutingCfgData(grp_members[j]).S[idx], getCurRoutingCfgData(grp_members[j]).gain[idx], getCurRoutingCfgData(grp_members[j]).type[idx]); //使用值计算点
//                } else {
//                    for (var k = 0; k < getCurRoutingGraphData(grp_members[j]).graph_data_items[idx].length; k++) {
//                        if (graph_delta[k] != 0) {
//                            getCurRoutingGraphData(grp_members[j]).graph_data_items[idx][k].y += graph_delta[k];
//                        }
//                    }
