/* 获取与指定别名配对的高低通分频点联动通道 */
function getFiltersCorrelationChannelList(ch, grpMembers, hf)
{
    var channelList = [];
    var curChAlias = getOutputChAlias(ch);
    var searchForAliasElements = [];
    var thisSideAliasElements = getPairedAliasElements(curChAlias);
    var otherSideAliasElements = null;
    var i;
    var chAlias;

    if (thisSideAliasElements != null) {
        if (grpMembers != null && grpMembers.length > 1) { //多于一个成员的分组才是需要联调的
            var otherSideAlias = getOtherSideAlias(curChAlias);
            var tmpOtherSideAliasElements = null;
            for (i = 0; i < grpMembers.length; i++) {
                if (ch == grpMembers[i]) {
                    continue;
                }
                if (getOutputChAlias(grpMembers[i]) != otherSideAlias) { //被联调通道必须是当前通道的对侧别名
                    break;
                }
            }
            if (i == grpMembers.length) {
                tmpOtherSideAliasElements = getPairedAliasElements(otherSideAlias);
            }

//            if (tmpOtherSideAliasElements != null) {
//                var thisSideUsedAliasElements = [];
//                var otherSideUsedAliasElements = [];

//                /* 取两侧可配对的不重复的别名 */
//                for (i = 0; i < getAllIndepOutputsLength(); i++) {
//                    var chAlias = getOutputChAlias(i);
//                    if (chAlias == thisSideAliasElements.high || chAlias == thisSideAliasElements.mid || chAlias == thisSideAliasElements.low) {
//                        if (!thisSideUsedAliasElements.some(function(item) { return chAlias === item; })) {
//                            thisSideUsedAliasElements.push(chAlias);
//                        }
//                    }
//                    if (chAlias == tmpOtherSideAliasElements.high || chAlias == tmpOtherSideAliasElements.mid || chAlias == tmpOtherSideAliasElements.low) {
//                        if (!otherSideUsedAliasElements.some(function(item) { return chAlias === item; })) {
//                            otherSideUsedAliasElements.push(chAlias);
//                        }
//                    }
//                }

//                /* 两侧别名必须能匹配才能供后续使用 */
//                if (thisSideUsedAliasElements.length == otherSideUsedAliasElements.length) {
//                    var isChkPass = true;
//                    for (i = 0; i < thisSideUsedAliasElements.length; i++) {
//                        if (!otherSideUsedAliasElements.some(function(item) { return getOtherSideAlias(thisSideUsedAliasElements[i]) === item; })) {
//                            isChkPass = false;
//                            break;
//                        }
//                    }
//                    if (isChkPass) {
//                        console.log("isChkPass = " + isChkPass);
//                        otherSideAliasElements = tmpOtherSideAliasElements;
//                    }
//                }
//            }

            if (tmpOtherSideAliasElements != null) {
                var thisSideUsedAliasElements = {high: -1, mid: -1, low: -1};
                var otherSideUsedAliasElements = {high: -1, mid: -1, low: -1};
                var thisSideUsedAliasElementsCount = 0;
                var otherSideUsedAliasElementsCount = 0;

                /* 取两侧可配对的不重复的别名 */
                for (i = 0; i < getAllIndepOutputsLength(); i++) {
                    chAlias = getOutputChAlias(i);

                    if (chAlias == thisSideAliasElements.high) {
                        if (thisSideUsedAliasElements.high != chAlias) {
                            thisSideUsedAliasElements.high = chAlias;
                            thisSideUsedAliasElementsCount++;
                        }
                    } else if (chAlias == thisSideAliasElements.mid) {
                        if (thisSideUsedAliasElements.mid != chAlias) {
                            thisSideUsedAliasElements.mid = chAlias;
                            thisSideUsedAliasElementsCount++;
                        }
                    } else if (chAlias == thisSideAliasElements.low) {
                        if (thisSideUsedAliasElements.low != chAlias) {
                            thisSideUsedAliasElements.low = chAlias;
                            thisSideUsedAliasElementsCount++;
                        }
                    }
                    if (chAlias == tmpOtherSideAliasElements.high) {
                        if (otherSideUsedAliasElements.high != chAlias) {
                            otherSideUsedAliasElements.high = chAlias;
                            otherSideUsedAliasElementsCount++;
                        }
                    } else if (chAlias == tmpOtherSideAliasElements.mid) {
                        if (otherSideUsedAliasElements.mid != chAlias) {
                            otherSideUsedAliasElements.mid = chAlias;
                            otherSideUsedAliasElementsCount++;
                        }
                    } else if (chAlias == tmpOtherSideAliasElements.low) {
                        if (otherSideUsedAliasElements.low != chAlias) {
                            otherSideUsedAliasElements.low = chAlias;
                            otherSideUsedAliasElementsCount++;
                        }
                    }
                }
                /* 两侧各自别名必须至少有两个且能匹配才能供后续使用 */
                if (thisSideUsedAliasElementsCount > 1 && thisSideUsedAliasElementsCount == otherSideUsedAliasElementsCount) {
                    var isChkPass = true;
                    if (otherSideUsedAliasElements.high != getOtherSideAlias(thisSideUsedAliasElements.high) ||
                            otherSideUsedAliasElements.mid != getOtherSideAlias(thisSideUsedAliasElements.mid) ||
                            otherSideUsedAliasElements.low != getOtherSideAlias(thisSideUsedAliasElements.low)) {
                        isChkPass = false;
                    }
                    if (isChkPass) {
                        otherSideAliasElements = tmpOtherSideAliasElements;
                    }
                }
                //console.log("otherSideAliasElements = " + JSON.stringify(otherSideAliasElements));
            }
        }

        if (curChAlias === thisSideAliasElements.mid) { //当前别名为中音
            if (hf) {
                searchForAliasElements.push(thisSideAliasElements.low);
                if (otherSideAliasElements != null) {
                    searchForAliasElements.push(otherSideAliasElements.low);
                }
            } else {
                searchForAliasElements.push(thisSideAliasElements.high);
                if (otherSideAliasElements != null) {
                    searchForAliasElements.push(otherSideAliasElements.high);
                }
            }
        } else {
            var isHasMidAliasCh = false;

            /* 查找所有输出中是否有别名为中音的通道 */
            for (i = 0; i < getAllIndepOutputsLength(); i++) {
                chAlias = getOutputChAlias(i);
                if (chAlias === thisSideAliasElements.mid || (otherSideAliasElements != null && chAlias === otherSideAliasElements.mid)) {
                    isHasMidAliasCh = true;
                    break;
                }
            }

            if (hf && curChAlias === thisSideAliasElements.high) { //当前别名为高音且在调节高通
                searchForAliasElements.push(isHasMidAliasCh ? thisSideAliasElements.mid : thisSideAliasElements.low);
                if (otherSideAliasElements != null) {
                    searchForAliasElements.push(isHasMidAliasCh ? otherSideAliasElements.mid : otherSideAliasElements.low);
                }
            } else if (!hf && curChAlias === thisSideAliasElements.low) { //当前别名为低音且在调节低通
                searchForAliasElements.push(isHasMidAliasCh ? thisSideAliasElements.mid : thisSideAliasElements.high);
                if (otherSideAliasElements != null) {
                    searchForAliasElements.push(isHasMidAliasCh ? otherSideAliasElements.mid : otherSideAliasElements.high);
                }
            }
        }

        if (thisSideAliasElements.lows != null) {
            if (!hf) {
                searchForAliasElements.push.apply(searchForAliasElements, thisSideAliasElements.lows);
            }
        }
        if (thisSideAliasElements.subwoofers != null) {
            var subwoofers = [25, 26, 27, 28];

            if (hf || subwoofers.some(function(item) { return curChAlias === item; })) {
                searchForAliasElements.push.apply(searchForAliasElements, thisSideAliasElements.subwoofers);
            }
        }
        //console.log("searchForAliasElements = " + JSON.stringify(searchForAliasElements));

        if (searchForAliasElements.length > 0) {
            for (i = 0; i < getAllIndepOutputsLength(); i++) {
                if (searchForAliasElements.some(function(item) { return getOutputChAlias(i) === item; })) {
                    channelList.push(i);
                }
            }
        }
    }

    //console.log("channelList = " + JSON.stringify(channelList));
    return channelList;
}

var deepCopy = function(o) {
    if (o instanceof Array) {
        var n = [];
        for (var i = 0; i < o.length; ++i) {
            n[i] = deepCopy(o[i]);
        }
        return n;

    } else if (o instanceof Object) {
        var n = {}
        for (var i in o) {
            n[i] = deepCopy(o[i]);
        }
        return n;
    } else {
        return o;
    }
}

function getStrokeColor(idx)
{
    if (idx < DspCfgData.length) {
        return DspCfgData[idx].labels.strokeColor;
    } else if (idx < DspCfgData.length + DspCfgDataExtend.length) {
        return DspCfgDataExtend[idx - DspCfgData.length].labels.strokeColor;
    } else {
        return DspCfgDataExtend_32_TO_47[idx - DspCfgData.length - DspCfgDataExtend.length].labels.strokeColor;
    }
}

/* 根据增益(EQ)联动标识及是否存在分组判断是否需要联动输出通道图形 */
function isNeedToCorrelateGraph()
{
    var master = getCurrentMaster();
    var grp_master = getGroup(master);
    if(getEqCorrMode() != "non") {
        for(var i=0;i<getAllMembersLength();i++) {
            if(i != master && getCurRoutingCfgData(i).groups == grp_master)
            {
                var pairedCh = getPairedBridgeJointChannel(i);
                if (pairedCh === master) {
                    continue;
                }

                return true;
            }
        }
    }
    return false;
}

/*
return to the number of standard input groups of 'idx'
*/
function getStandardInputGroup(idx)
{
    var routing = getStandardInputRoutingByChannelIdx(idx);
    var dbIdx = getStandardInputDbIndexByChannelIdx(idx);

    return getBaseInputsCfgData(dbIdx, routing).standardEq.groups;
}

/*
   get the members of the standard input group.
*/
function getStandardInputGroupMembers(group)
{
    var a = new Array(0);
    for(var i=0;i<getDynamicAllBaseSrcLength();i++)
    {
        var routing = getStandardInputRoutingByChannelIdx(i);
        var dbIdx = getStandardInputDbIndexByChannelIdx(i);

        if(getBaseInputsCfgData(dbIdx, routing).standardEq.groups==group)
        {
            //console.log("getGroup,found:"+i);
            a.push(i);
        }
    }
    return a;
}
/*
把标准模式下基础输入源grps里面所有成员都加入到当前的组里面
*/
function setStandardInputGroupMembers(grps)
{
    var master=getCurrentStandardInputMaster();
    for(var i=0;i<grps.length;i++)
    {
        var routing = getStandardInputRoutingByChannelIdx(grps[i]);
        var dbIdx = getStandardInputDbIndexByChannelIdx(grps[i]);
        getBaseInputsCfgData(dbIdx, routing).standardEq.groups=master;
    }
}

/* 解散所有标准模式下基础输入源分组 */
function disbandAllStandardInputGroup()
{
    var count = getDynamicAllBaseSrcLength();
    for (var i = 0; i < count; i++) {
        var routing = getStandardInputRoutingByChannelIdx(i);
        var dbIdx = getStandardInputDbIndexByChannelIdx(i);
        getBaseInputsCfgData(dbIdx, routing).standardEq.groups = i;
    }
}

/*
return to the number of output groups of 'idx'
*/
function getOutputGroup(idx)
{
    var pairedCh = getPairedBridgeJointChannel(idx);
    if (pairedCh > -1 && !(pairedCh % 2)) {
        return getCurOutputRoutingCfgData(pairedCh).groups;
    }

    return getCurOutputRoutingCfgData(idx).groups;
}

/*
   get the members of the output group.
*/
function getOutputGroupMembers(group)
{
    var a=new Array();
    for(var i=0;i<getOutputsLength();i++)
    {
        if(getCurOutputRoutingCfgData(getOutputCmdLineIdxByViewIdx(i)).groups==group)
        {
            //console.log("getGroup,found:"+i);
            a.push(getOutputCmdLineIdxByViewIdx(i));
        }
    }

    //console.log("getGroupMembers : group(" + group + "): " + JSON.stringify(a));

    return a;
}
/*
把输出grps里面所有成员都加入到当前的组里面
*/
function setOutputGroupMembers(grps)
{
    var master=getCurrentOutputMaster();
    for(var i=0;i<grps.length;i++)
    {
        // console.log("add:"+grps[i]+"into grp:"+master);
        getCurOutputRoutingCfgData(grps[i]).groups=master;
    }
}

/* 解散所有输出分组 */
function disbandAllOutputGroup()
{
    var outputCount = getAllIndepOutputsLength();
    for (var i = 0; i < outputCount; i++) {
//        if (isHasDigitalRoute()) {
//            getOutputRoutingCfgData(i, DIGITAL).groups = i;
//        }
        getOutputRoutingCfgData(i, ANALOG).groups = i;
    }
}

/*
增益和具体的频点有关，所以如果选择相对或绝对，则需要保持两者的频点一致，否则无法对应。
*/
function setGainVal(cb,arr,idx,gains)
{
    var curTypes = getEqTypes(arr);
    var grp=getGroup(arr);// here arr should equal to grp
    var grp_members=getGroupMembers(grp);
    var parm_list_eqType = [];
    var parm_list_freq = [];
    var parm_list_q = [];
    var parm_list_gain = [];
    var is_set_eqType = false; //是否设置了从通道的EQ类型为当前通道EQ类型
    var is_set_freq = false; //是否设置了从通道的频率值为当前通道的频率值
    var is_set_q = false; //是否设置了从通道的Q值为当前通道Q值
    var is_set_gain = false; //是否设置了从通道的EQ为当前通道的EQ值
    var pairedCh;

    //console.log("setGainVal: grp = " + grp + ", grp_members = " + JSON.stringify(grp_members));

    switch(getEqCorrMode())
    {
    case "bal":
    case "rel":
    case "abs":
        var old_gains=getCurRoutingCfgData(arr).gain;
        var delta = Number(gains[idx], 'f', 1) - Number(old_gains[idx], 'f', 1);
//        for(var i=0;i<gains.length;i++) {
//             delta.push(Number(gains[i], 'f', 1) - Number(old_gains[i], 'f', 1));
//        }
        for(var j=0;j<grp_members.length;j++)
        {
            /* 当主通道EQ值改变时，从通道的频率、Q绝对同步至主通道，EQ相对同步于主通道 */
            if (grp_members[j] != arr) {
                pairedCh = getPairedBridgeJointChannel(grp_members[j]);
                if (pairedCh === arr) {
                    continue;
                }

                is_set_eqType = false;
                if (getCurRoutingCfgData(grp_members[j]).type[idx] != curTypes[idx]) {
                    if (getEqCorrMode() == "abs") {
                        getCurRoutingCfgData(grp_members[j]).type[idx] = curTypes[idx];
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).type[idx] = curTypes[idx];
                        }
                        is_set_eqType = true;
                    } else {
                        continue;
                    }
                }
                if (is_set_eqType) {
                    parm_list_eqType.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).type});
                    if (pairedCh > -1) {
                        parm_list_eqType.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).type});
                    }
                }

                if (getEqCorrMode() == "abs") {
                    is_set_freq = false;
                    if (getCurRoutingCfgData(grp_members[j]).shift_freq[idx] != getCurRoutingCfgData(arr).shift_freq[idx]) {
                        getCurRoutingCfgData(grp_members[j]).shift_freq[idx] = getCurRoutingCfgData(arr).shift_freq[idx];
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).shift_freq[idx] = getCurRoutingCfgData(grp_members[j]).shift_freq[idx];
                        }
                        is_set_freq = true;
                    }
                    if (is_set_freq) {
                        var freqs = [];
                        for (var m = 0; m < getCurRoutingCfgData(grp_members[j]).shift_freq.length; m++) {
                            freqs.push(parseInt(getCurRoutingCfgData(grp_members[j]).shift_freq[m]) + parseInt(getFreqBands(getCurRoutingCfgData(grp_members[j]).shift_freq.length)[m]));
                        }
                        parm_list_freq.push({key:grp_members[j], val:freqs});
                        if (pairedCh > -1) {
                            parm_list_freq.push({key:pairedCh, val:freqs});
                        }
                        //console.log("setGainVal: set slave freq");
                    }

                    is_set_q = false;
                    if (curTypes[idx] === 1 || curTypes[idx] === 2) {
                        if (Number(getCurRoutingCfgData(grp_members[j]).S[idx], 'f', 1).toFixed(1) != Number(getCurRoutingCfgData(arr).S[idx], 'f', 1).toFixed(1)) {
                            getCurRoutingCfgData(grp_members[j]).S[idx]= getCurRoutingCfgData(arr).S[idx];
                            if (pairedCh > -1) {
                                getCurRoutingCfgData(pairedCh).S[idx]= getCurRoutingCfgData(grp_members[j]).S[idx];
                            }
                            is_set_q = true;
                        }
                    } else {
                        if (Number(getCurRoutingCfgData(grp_members[j]).Q[idx], 'f', 1).toFixed(1) != Number(getCurRoutingCfgData(arr).Q[idx], 'f', 1).toFixed(1)) {
                            getCurRoutingCfgData(grp_members[j]).Q[idx]= getCurRoutingCfgData(arr).Q[idx];
                            if (pairedCh > -1) {
                                getCurRoutingCfgData(pairedCh).Q[idx]= getCurRoutingCfgData(grp_members[j]).Q[idx];
                            }
                            is_set_q = true;
                        }
                    }
                    if (is_set_q) {
                        if (curTypes[idx] === 1 || curTypes[idx] === 2) {
                            parm_list_q.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).S});
                            if (pairedCh > -1) {
                                parm_list_q.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).S});
                            }
                        } else {
                            parm_list_q.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).Q});
                            if (pairedCh > -1) {
                                parm_list_q.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).Q});
                            }
                        }
                        //console.log("setGainVal: set slave Q");
                    }
                }

                is_set_gain = false;
                if (Math.abs(Number(delta, 'f', 1)) > 0) {
                    if ((getEqCorrMode() == "bal" || getEqCorrMode() == "rel")/* && !is_set_freq && !is_set_q*/) { //只有两个通道的频率值、Q值本身是一致时，EQ值才相对联动
                        var resultVal = Number(getCurRoutingCfgData(grp_members[j]).gain[idx], 'f', 1) + (getEqCorrMode() == "bal" ? -Number(delta, 'f', 1) : Number(delta, 'f', 1));
                        var gainRange = getGainRange();
                        if (resultVal > gainRange.max) {
                            resultVal = gainRange.max;
                        } else if (resultVal < gainRange.min) {
                            resultVal = gainRange.min;
                        }
                        getCurRoutingCfgData(grp_members[j]).gain[idx] = resultVal.toFixed(1);
                        //console.log("setGainVal: set slave as rel.");
                    } else { //getEqCorrMode() == "abs"
                        getCurRoutingCfgData(grp_members[j]).gain[idx] = gains[idx];
                        //console.log("setGainVal: set slave as abs.");
                    }
                    if (pairedCh > -1) {
                        getCurRoutingCfgData(pairedCh).gain[idx] = getCurRoutingCfgData(grp_members[j]).gain[idx];
                    }
                    is_set_gain = true;
                }
                if (is_set_gain) {
                    parm_list_gain.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).gain});
                    if (pairedCh > -1) {
                        parm_list_gain.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).gain});
                    }
//                    console.log("setGainVal: set slave EQ");
                }
            }
        }

        if (parm_list_eqType.length > 0) {
            devSetMutiChEqType(cb, getCurrentRouting(), parm_list_eqType);
        }
        if (parm_list_freq.length > 0) {
            devSetMutiChFreq(cb, getCurrentRouting(), parm_list_freq);
        }
        if (parm_list_q.length > 0) {
            if (curTypes[idx] === 1 || curTypes[idx] === 2) {
                devSetMutiChEqSlope(cb, getCurrentRouting(), parm_list_q);
            } else {
                devSetMutiChQ(cb, getCurrentRouting(), parm_list_q);
            }
        }
        break;
    case "non":
    }

    getCurRoutingCfgData(arr).gain=deepCopy(gains);
    parm_list_gain.push({key:arr, val:gains});

    pairedCh = getPairedBridgeJointChannel(arr);
    if (pairedCh > -1) {
        getCurRoutingCfgData(pairedCh).gain=deepCopy(gains);
        parm_list_gain.push({key:pairedCh, val:gains});
    }

    devSetMutiChEQ(cb, getCurrentRouting(), parm_list_gain);
}

function resetChGains(cb, arr)
{
    var output_list = [];

    if(getEqCorrMode()!="non") {//不管是相对还是绝对，必须要把频率值对齐，
        var grp=getGroup(arr);// here i should equal to grp
        var grp_members=getGroupMembers(grp);
        output_list = grp_members;
    } else {
        output_list.push(arr);
    }
    resetAllGains(cb, output_list);
}

function resetAllGains(cb, output_list)
{
    var pairedCh;
    var parm_list = [];
    var exclude_list = [];

    for(var i=0;i<output_list.length;i++)
    {
        if (exclude_list.some(function(item) { return output_list[i] === item; })) {
            continue;
        }

        pairedCh = getPairedBridgeJointChannel(output_list[i]);

        var cur_frq_bands = getFreqBands(getCurRoutingCfgData(output_list[i]).shift_freq.length);
        getCurRoutingCfgData(output_list[i]).gain = [];
        if (pairedCh > -1) {
            getCurRoutingCfgData(pairedCh).gain = [];
        }
        for(var j=0;j<cur_frq_bands.length;j++)
        {
            getCurRoutingCfgData(output_list[i]).gain.push(0);

            if (pairedCh > -1) {
                getCurRoutingCfgData(pairedCh).gain.push(0);
            }
        }
        parm_list.push({key:output_list[i], val:getCurRoutingCfgData(output_list[i]).gain});

        if (pairedCh > -1) {
            parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).gain});
            exclude_list.push(pairedCh);
        }

    }
    return devSetMutiChEQ(cb, getCurrentRouting(), parm_list);
}

/* 获取gainRecovery */
function getGainRecoveryVal(arr, idx)
{
    console.assert(getAllMembersLength()>arr>=0,"getGainVal group sequence out of range");
    return getCurRoutingCfgDataCache(arr).gainRecovery[idx];
}

/* 设置gainRecovery */
function setGainRecoveryVal(arr,idx,gain)
{
    var grp=getGroup(arr);// here arr should equal to grp
    var grp_members=getGroupMembers(grp);
    switch(getEqCorrMode())
    {
    case "bal":
    case "rel":
    case "abs":
        for(var j=0;j<grp_members.length;j++)
        {
            if (grp_members[j] != arr/* && getCurRoutingCfgData(grp_members[j]).gain[idx] != 0*/) {
                getCurRoutingCfgDataCache(grp_members[j]).gainRecovery[idx] = getCurRoutingCfgData(grp_members[j]).gain[idx];
            }
        }
        break;
    case "non":
        break;
    }
    getCurRoutingCfgDataCache(arr).gainRecovery[idx]=gain;
}

/* 重置所有gainRecovery */
function resetAllGainRecoveries(output_list)
{
    for(var i=0;i<output_list.length;i++)
    {
        getCurRoutingCfgDataCache(output_list[i]).gainRecovery = [];
        var cur_frq_bands = getFreqBands(getCurRoutingCfgData(output_list[i]).shift_freq.length);
        for(var j=0;j<cur_frq_bands.length;j++)
        {
            getCurRoutingCfgDataCache(output_list[i]).gainRecovery.push(0);
        }
    }
}

/* 重置所有通道的gainRecovery */
function resetAllChGainRecoveries()
{
    var output_list;
    var i, j;

    console.log("resetAllChGainRecoveries called");

    for (i = STANDARD_INPUTS_GROUPS; i <= OUTPUTS_GROUPS; i++) {
        setCallbackFun(i);

        output_list = [];
        for (j = 0; j < getAllMembersLength(); j++) {
            output_list.push(j);
        }

        resetAllGainRecoveries(output_list);
    }
    setCallbackFun(getCurrentActiveGroupsFlag());
}

function isFilterBypass(hf)
{
    var i = getCurrentMaster();
    var pass_band;
    if (hf) {
        pass_band = getCurOutputRoutingCfgData(i).pass_band.high;
    } else {
        pass_band = getCurOutputRoutingCfgData(i).pass_band.low;
    }
    return (pass_band.bypass > 0)?true:false;
}

function setFilter(cb, idx, isCorrelate, hf, isBypass, type_indx, slope, freq)
{
    var enabled = isBypass?0:1;
    var filterType = (type_indx * 8 + 1) + slope;
    var pass_band_master;
    var pass_band_slave;
    var pass_band_paired;
    var pass_band_linked;
    var pairedCh;
    var linkedChList = [];
    var parm_list = [];
    var parm_list_linked = [];
    var grp_members = [];
    var i;
    var delta;
    var desFreq;

    if (hf) {
        pass_band_master = getCurOutputRoutingCfgData(idx).pass_band.high;
    } else {
        pass_band_master = getCurOutputRoutingCfgData(idx).pass_band.low;
    }
    delta = freq - pass_band_master.freq;

    if(hf != null && isCorrelate && getEqCorrMode() != "non") //不管是相对还是绝对，必须要把高/低通滤波器值对齐，
    {
        var grp=getGroup(idx);// here i should equal to grp
        grp_members=getGroupMembers(grp);

        for(var j=0; j < grp_members.length; j++)
        {
            pairedCh = getPairedBridgeJointChannel(grp_members[j]);
//            if (pairedCh === idx) {
//                continue;
//            }

            if (hf) {
                pass_band_slave = getCurOutputRoutingCfgData(grp_members[j]).pass_band.high;
                if (pairedCh > -1) {
                    pass_band_paired = getCurOutputRoutingCfgData(pairedCh).pass_band.high;
                }
            } else {
                pass_band_slave = getCurOutputRoutingCfgData(grp_members[j]).pass_band.low;
                if (pairedCh > -1) {
                    pass_band_paired = getCurOutputRoutingCfgData(pairedCh).pass_band.low;
                }
            }

            pass_band_slave.type = type_indx;
            pass_band_slave.slope = slope;
            pass_band_slave.bypass = isBypass?1:0;
            if (getEqCorrMode() == "rel" && grp_members[j] != idx) {
                desFreq = parseInt(pass_band_slave.freq) + delta;
                if (desFreq < frq_31_bands[0]) {
                    desFreq = frq_31_bands[0];
                } else if (desFreq > frq_31_bands[frq_31_bands.length - 1]) {
                    desFreq = frq_31_bands[frq_31_bands.length - 1];
                }
                pass_band_slave.freq = desFreq;
            } else {
                pass_band_slave.freq = freq;
            }
            parm_list.push({key:grp_members[j], val:[enabled,filterType,pass_band_slave.freq]});

            if (pairedCh > -1) {
                pass_band_paired.type = pass_band_slave.type;
                pass_band_paired.slope = pass_band_slave.slope;
                pass_band_paired.freq = pass_band_slave.freq;
                pass_band_paired.bypass = pass_band_slave.bypass
                parm_list.push({key:pairedCh, val:[enabled,filterType,pass_band_paired.freq]});
            }
        }
    } else {
        if (hf != null) {
            pairedCh = getPairedBridgeJointChannel(idx);

            if (hf) {
                pass_band_master = getCurOutputRoutingCfgData(idx).pass_band.high;
                if (pairedCh > -1) {
                    pass_band_paired = getCurOutputRoutingCfgData(pairedCh).pass_band.high;
                }
            } else {
                pass_band_master = getCurOutputRoutingCfgData(idx).pass_band.low;
                if (pairedCh > -1) {
                    pass_band_paired = getCurOutputRoutingCfgData(pairedCh).pass_band.low;
                }
            }
        } else {
            pairedCh = -1;

            switch (idx) {
            case "MicLowpass":
                pass_band_master = MicLowpass;
                break;
            case "MicHighpass":
                pass_band_master = MicHighpass ;
                break;
            default:
                return;
            }
        }

        pass_band_master.type = type_indx;
        pass_band_master.slope = slope;
        pass_band_master.freq = freq;
        pass_band_master.bypass = isBypass?1:0;
        parm_list.push({key:idx, val:[enabled,filterType,pass_band_master.freq]});

        if (pairedCh > -1) {
            pass_band_paired.type = type_indx;
            pass_band_paired.slope = slope;
            pass_band_paired.freq = freq;
            pass_band_paired.bypass = isBypass?1:0;
            parm_list.push({key:pairedCh, val:[enabled,filterType,pass_band_paired.freq]});
        }
    }

    if (hf != null) {
        var subwoofers = [25, 26, 27, 28];

        if (getFiltersCorrelationMode() != "non") {
            linkedChList = getFiltersCorrelationChannelList(idx, grp_members, hf);
            if (linkedChList.length > 0) {
                for (i = 0; i < linkedChList.length; i++) {
                    if (parm_list.some(function(item) { return linkedChList[i] === item.key; })) {
                        continue; //已被联调或桥接通道不做处理
                    }

                    /* 当前别名为超重低音1~4中的一个，且列表中含超重低音别名的特殊处理 */
                    if (subwoofers.some(function(item) { return getOutputChAlias(idx) === item; })) {
                        if (subwoofers.some(function(item) { return getOutputChAlias(linkedChList[i]) === item; })) {
                            pairedCh = getPairedBridgeJointChannel(linkedChList[i]);
                            //            if (pairedCh === idx) {
                            //                continue;
                            //            }

                            if (hf) {
                                pass_band_slave = getCurOutputRoutingCfgData(linkedChList[i]).pass_band.high;
                                if (pairedCh > -1) {
                                    pass_band_paired = getCurOutputRoutingCfgData(pairedCh).pass_band.high;
                                }
                            } else {
                                pass_band_slave = getCurOutputRoutingCfgData(linkedChList[i]).pass_band.low;
                                if (pairedCh > -1) {
                                    pass_band_paired = getCurOutputRoutingCfgData(pairedCh).pass_band.low;
                                }
                            }

                            pass_band_slave.type = type_indx;
                            pass_band_slave.slope = slope;
                            pass_band_slave.bypass = isBypass?1:0;
                            if (getEqCorrMode() == "rel" && linkedChList[i] != idx) {
                                desFreq = parseInt(pass_band_slave.freq) + delta;
                                if (desFreq < frq_31_bands[0]) {
                                    desFreq = frq_31_bands[0];
                                } else if (desFreq > frq_31_bands[frq_31_bands.length - 1]) {
                                    desFreq = frq_31_bands[frq_31_bands.length - 1];
                                }
                                pass_band_slave.freq = desFreq;
                            } else {
                                pass_band_slave.freq = freq;
                            }
                            parm_list.push({key:linkedChList[i], val:[enabled,filterType,pass_band_slave.freq]});

                            if (pairedCh > -1) {
                                pass_band_paired.type = pass_band_slave.type;
                                pass_band_paired.slope = pass_band_slave.slope;
                                pass_band_paired.freq = pass_band_slave.freq;
                                pass_band_paired.bypass = pass_band_slave.bypass
                                parm_list.push({key:pairedCh, val:[enabled,filterType,pass_band_paired.freq]});
                            }
                            continue;
                        }
                    }

                    if (hf) {
                        pass_band_linked = getCurOutputRoutingCfgData(linkedChList[i]).pass_band.low;

                    } else {
                        pass_band_linked = getCurOutputRoutingCfgData(linkedChList[i]).pass_band.high;
                    }
                    if (getFiltersCorrelationMode() == "rel") {
                        desFreq = parseInt(pass_band_linked.freq) + delta;
                        if (desFreq < frq_31_bands[0]) {
                            desFreq = frq_31_bands[0];
                        } else if (desFreq > frq_31_bands[frq_31_bands.length - 1]) {
                            desFreq = frq_31_bands[frq_31_bands.length - 1];
                        }
                    } else {
                        desFreq = freq;
                    }
                    pass_band_linked.freq = desFreq;
                    parm_list_linked.push({key:linkedChList[i], val:[pass_band_linked.bypass?0:1,(pass_band_linked.type * 8 + 1) + pass_band_linked.slope,pass_band_linked.freq]});
                }
                if (parm_list_linked.length > 0) {
                    if (hf) {
                        devSetMutiChLowpass(cb, getCurrentRouting(), parm_list_linked);
                    } else {
                        devSetMutiChHighpass(cb, getCurrentRouting(), parm_list_linked);
                    }
                }
            }
        }

        if (hf) {
            devSetMutiChHighpass(cb, getCurrentRouting(), parm_list);
        } else {
            devSetMutiChLowpass(cb, getCurrentRouting(), parm_list);
        }
    } else {
        switch (idx) {
        case "MicLowpass":
            devSetMicLowpass(cb, enabled, filterType, freq);
            break;
        case "MicHighpass":
            devSetMicHighpass(cb, enabled, filterType, freq);
            break;
        }
    }
}

function resetAllHighFilter(cb, output_list)
{
    var pairedCh;
    var parm_list = [];
    var exclude_list = [];

    for(var i=0;i<output_list.length;i++)
    {
        if (exclude_list.some(function(item) { return output_list[i] === item; })) {
            continue;
        }

        getCurOutputRoutingCfgData(output_list[i]).pass_band.high={bypass:1,freq:frq_31_bands[0],type:2,slope:1};
        parm_list.push({key:output_list[i], val:[0,18,frq_31_bands[0]]});

        pairedCh = getPairedBridgeJointChannel(output_list[i]);
        if (pairedCh > -1) {
            getCurOutputRoutingCfgData(pairedCh).pass_band.high={bypass:1,freq:frq_31_bands[0],type:2,slope:1};
            parm_list.push({key:pairedCh, val:[0,18,frq_31_bands[0]]});
            exclude_list.push(pairedCh);
        }
    }
    return devSetMutiChHighpass(cb, getCurrentRouting(), parm_list);
}

function resetAllLowFilter(cb, output_list)
{
    var pairedCh;
    var parm_list = [];
    var exclude_list = [];

    for(var i=0;i<output_list.length;i++)
    {
        if (exclude_list.some(function(item) { return output_list[i] === item; })) {
            continue;
        }

        getCurOutputRoutingCfgData(output_list[i]).pass_band.low={bypass:1,freq:frq_31_bands[frq_31_bands.length-1],type:2,slope:1};
        parm_list.push({key:output_list[i], val:[0,18,frq_31_bands[frq_31_bands.length-1]]});

        pairedCh = getPairedBridgeJointChannel(output_list[i]);
        if (pairedCh > -1) {
            getCurOutputRoutingCfgData(pairedCh).pass_band.low={bypass:1,freq:frq_31_bands[frq_31_bands.length-1],type:2,slope:1};
            parm_list.push({key:pairedCh, val:[0,18,frq_31_bands[frq_31_bands.length-1]]});
            exclude_list.push(pairedCh);
        }
    }
    return devSetMutiChLowpass(cb, getCurrentRouting(), parm_list);
}

