/* 获取相位翻转状态 */
function getPhase(idx)
{
    return getCurOutputRoutingCfgData(idx).phase;
}

/* 设置相位翻转状态(绝对联调时允许相位联调) */
function setPhase(cb, idx, phase, isCorrelate)
{
    var pairedCh;
    var parm_list = [];

    if(isCorrelate && EqCorrelationMode=="abs")
    {
        var grp=getGroup(idx);
        var grp_members=getGroupMembers(grp);
        for(var j=0;j<grp_members.length;j++)
        {
            if (grp_members[j] != idx) {
                getCurOutputRoutingCfgData(grp_members[j]).phase=phase;
                parm_list.push({key:grp_members[j], val:getCurOutputRoutingCfgData(grp_members[j]).phase});

                pairedCh = getPairedBridgeJointChannel(grp_members[j]);
                if (pairedCh === idx) {
                    continue;
                }
                if (pairedCh > -1) {
                    //getCurOutputRoutingCfgData(pairedCh).phase=(phase ? 0 : 180); //被桥接通道需反相
                    getCurOutputRoutingCfgData(pairedCh).phase=phase;
                    parm_list.push({key:pairedCh, val:getCurOutputRoutingCfgData(pairedCh).phase});
                }
            }
        }
    }

    getCurOutputRoutingCfgData(idx).phase = phase;
    parm_list.push({key:idx, val:getCurOutputRoutingCfgData(idx).phase});

    pairedCh = getPairedBridgeJointChannel(idx);
    if (pairedCh > -1) {
        //getCurOutputRoutingCfgData(pairedCh).phase=(phase ? 0 : 180); //被桥接通道需反相
        getCurOutputRoutingCfgData(pairedCh).phase=phase;
        parm_list.push({key:pairedCh, val:getCurOutputRoutingCfgData(pairedCh).phase});
    }

    devSetMutiChPhase(cb, getCurrentRouting(), parm_list);
}

/* 复位相位翻转状态 */
function resetAllPhase(cb, output_list)
{
    var pairedCh;
    var parm_list = [];
    var exclude_list = [];

    for(var i=0;i<output_list.length;i++)
    {
        if (exclude_list.some(function(item) { return output_list[i] === item; })) {
            continue;
        }

        getCurOutputRoutingCfgData(output_list[i]).phase=0;
        parm_list.push({key:output_list[i], val:0});

        pairedCh = getPairedBridgeJointChannel(output_list[i]);
        if (pairedCh > -1) {
            //getCurOutputRoutingCfgData(pairedCh).phase=180; //被桥接通道需反相
            getCurOutputRoutingCfgData(pairedCh).phase=0;
            //parm_list.push({key:pairedCh, val:getCurOutputRoutingCfgData(pairedCh).phase});
            parm_list.push({key:pairedCh, val:0});
            exclude_list.push(pairedCh);
        }
    }
    return devSetMutiChPhase(cb, getCurrentRouting(), parm_list);
}

/* 重置是否存在任意相位调节功能模块为指定值 */
function resetArbitraryPhaseExist(state)
{
    ArbitraryPhaseExist = state;
}

function isHasArbitraryPhaseAngle()
{
    return ArbitraryPhaseExist;
}

/* 任意相位调节功能是否有效 */
function isArbitraryPhaseValid(seq)
{
    if (isHasArbitraryPhaseAngle()) {
        var pass_band = getCurRoutingCfgData(seq).pass_band.low;
        if (!pass_band.bypass && pass_band.freq <= 10000) {
            pass_band = getCurRoutingCfgData(seq).pass_band.high;
            if (pass_band.bypass) {
                return true;
            } else if (pass_band.freq <= 10000) {
                return true;
            }
        }
    }

    return false;
}

/* 获取通道的任意相位角度调节开关 */
function getArbitraryPhaseEnable(idx)
{
    return (getCurRoutingCfgData(idx).arbitrary_phase_enable? 1 : 0);
}

/* 设置通道的任意相位角度调节开关(允许相位联调；needCheckValid有效时，要在滤波器设置完成后再调用才能符合实际情况) */
function setArbitraryPhaseEnable(cb, idx, state, needCheckValid, isCorrelate)
{
    var isAnyCheckFailed = false;
    var desState = state;
    var pairedCh;
    var parm_list = [];

    if (state && needCheckValid && !isArbitraryPhaseValid(idx)) {
        isAnyCheckFailed = true;
        desState = false;
    } else {
        desState = state;
    }

    if (isCorrelate != null) {
        if (isCorrelate && (EqCorrelationMode=="abs" || EqCorrelationMode=="rel")) {
            var grp=getGroup(idx);
            var grp_members=getGroupMembers(grp);

            for (var j = 0; j < grp_members.length; j++) {
                if (grp_members[j] != idx && isArbitraryPhaseValid(grp_members[j])) {
                    getCurRoutingCfgData(grp_members[j]).arbitrary_phase_enable = (desState ? 1 : 0);
                    parm_list.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).arbitrary_phase_enable});

                    pairedCh = getPairedBridgeJointChannel(grp_members[j]);
                    if (pairedCh === idx) {
                        continue;
                    }
                    if (pairedCh > -1) {
                        getCurRoutingCfgData(pairedCh).arbitrary_phase_enable = (desState ? 1 : 0);
                        parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).arbitrary_phase_enable});
                    }
                }
            }
        }
    }

    getCurRoutingCfgData(idx).arbitrary_phase_enable = (desState ? 1 : 0);
    parm_list.push({key:idx, val:getCurRoutingCfgData(idx).arbitrary_phase_enable});

    pairedCh = getPairedBridgeJointChannel(idx);
    if (pairedCh > -1) {
        getCurRoutingCfgData(pairedCh).arbitrary_phase_enable = (desState ? 1 : 0);
        parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).arbitrary_phase_enable});
    }

    devSetMutiChArbitraryPhaseEnable(cb, parm_list);

    return isAnyCheckFailed;
}

/* 检测并使通道的任意相位角度调节开关与滤波器值保持兼容状态(允许相位联调) */
function checkRepairArbitraryPhaseEnable(cb, idx, isCorrelate)
{
    var isAnyChanged = false;
    var pairedCh;
    var parm_list = [];

    if (!isHasArbitraryPhaseAngle()) {
        return isAnyChanged;
    }

    if(isCorrelate && (EqCorrelationMode=="abs" || EqCorrelationMode=="rel"))
    {
        var grp=getGroup(idx);
        var grp_members=getGroupMembers(grp);
        for(var j=0;j<grp_members.length;j++)
        {
            if (grp_members[j] != idx) {
                if (!isArbitraryPhaseValid(grp_members[j]) && getCurRoutingCfgData(grp_members[j]).arbitrary_phase_enable) {
                    isAnyChanged = true;
                    getCurRoutingCfgData(grp_members[j]).arbitrary_phase_enable = 0;
                    parm_list.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).arbitrary_phase_enable});

                    pairedCh = getPairedBridgeJointChannel(grp_members[j]);
                    if (pairedCh === idx) {
                        continue;
                    }
                    if (pairedCh > -1) {
                        getCurRoutingCfgData(pairedCh).arbitrary_phase_enable = 0;
                        parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).arbitrary_phase_enable});
                    }
                }
            }
        }
    }

    if (!isArbitraryPhaseValid(idx) && getCurRoutingCfgData(idx).arbitrary_phase_enable) {
        isAnyChanged = true;
        getCurRoutingCfgData(idx).arbitrary_phase_enable = 0;
        parm_list.push({key:idx, val:getCurRoutingCfgData(idx).arbitrary_phase_enable});

        pairedCh = getPairedBridgeJointChannel(idx);
        if (pairedCh > -1) {
            getCurRoutingCfgData(pairedCh).arbitrary_phase_enable = 0;
            parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).arbitrary_phase_enable});
        }
    }

    if (parm_list.length > 0) {
        devSetMutiChArbitraryPhaseEnable(cb, parm_list);
    }

    return isAnyChanged;
}

/* 复位通道列表的任意相位角度调节开关 */
function resetAllArbitraryPhaseEnable(cb, output_list)
{
    var pairedCh;
    var parm_list = [];
    var exclude_list = [];

    for(var i=0;i<output_list.length;i++)
    {
        if (exclude_list.some(function(item) { return output_list[i] === item; })) {
            continue;
        }

        getCurRoutingCfgData(output_list[i]).arbitrary_phase_enable=0;
        parm_list.push({key:output_list[i], val:0});

        pairedCh = getPairedBridgeJointChannel(output_list[i]);
        if (pairedCh > -1) {
            getCurRoutingCfgData(pairedCh).arbitrary_phase_enable=0;
            parm_list.push({key:pairedCh, val:0});
            exclude_list.push(pairedCh);
        }
    }

    return devSetMutiChArbitraryPhaseEnable(cb, parm_list);
}

/* 设置所有已列出通道的任意相位角度调节开关(needCheckValid有效时，要在滤波器设置完成后再调用才能符合实际情况) */
function setAllArbitraryPhaseEnable(cb, val_list, needCheckValid)
{
    var isAnyCheckFailed = false;
    var pairedCh;
    var parm_list = [];

    for(var i=0;i<val_list.length;i++)
    {
        if (val_list[i].val > 0 && needCheckValid && !isArbitraryPhaseValid(val_list[i].key)) {
            isAnyCheckFailed = true;
            val_list[i].val = 0;
        }
        getCurRoutingCfgData(val_list[i].key).arbitrary_phase_enable=val_list[i].val;
        parm_list.push({key:val_list[i].key, val:val_list[i].val});

        pairedCh = getPairedBridgeJointChannel(val_list[i].key);
        if (pairedCh > -1) {
            getCurRoutingCfgData(pairedCh).arbitrary_phase_enable=val_list[i].val;
            parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).arbitrary_phase_enable});
        }
    }
    devSetMutiChArbitraryPhaseEnable(cb, parm_list);

    return isAnyCheckFailed;
}

/* 获取通道的任意相位角度 */
function getArbitraryPhaseAngle(idx)
{
    return getCurRoutingCfgData(idx).arbitrary_phase_angle;
}

/* 设置通道的任意相位角度 */
function setArbitraryPhaseAngle(cb, idx, phase, isCorrelate)
{
    var pairedCh;
    var parm_list = [];
    var parm_list_enable = [];

    if (isCorrelate != null) {
        if(isCorrelate && (EqCorrelationMode=="abs" || EqCorrelationMode=="rel")) {
            var grp=getGroup(idx);
            var grp_members=getGroupMembers(grp);
            var j;

            switch (EqCorrelationMode) {
            case "rel":
                var delta = phase - getCurRoutingCfgData(idx).arbitrary_phase_angle;
                for (j = 0; j < grp_members.length; j++) {
                    if (grp_members[j] != idx && isArbitraryPhaseValid(grp_members[j])) {
                        var relTmp = phase;
                        if (getArbitraryPhaseEnable(grp_members[j])) {
                            relTmp = getCurRoutingCfgData(grp_members[j]).arbitrary_phase_angle + delta;
                            if (relTmp > 359) {
                                relTmp = 359;
                            } else if (relTmp < 0) {
                                relTmp = 0;
                            }
                        } else {
                            getCurRoutingCfgData(grp_members[j]).arbitrary_phase_enable = 1;
                            parm_list_enable.push({key:grp_members[j], val:1});
                        }

                        getCurRoutingCfgData(grp_members[j]).arbitrary_phase_angle = relTmp;
                        parm_list.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).arbitrary_phase_angle});

                        pairedCh = getPairedBridgeJointChannel(grp_members[j]);
                        if (pairedCh === idx) {
                            continue;
                        }
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).arbitrary_phase_angle = relTmp;
                            parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).arbitrary_phase_angle});

                            if (!getArbitraryPhaseEnable(pairedCh)) {
                                getCurRoutingCfgData(pairedCh).arbitrary_phase_enable = 1;
                                parm_list_enable.push({key:pairedCh, val:1});
                            }
                        }
                    }
                }
                break;
            case "abs":
                for (j = 0; j < grp_members.length; j++) {
                    if (grp_members[j] != idx && isArbitraryPhaseValid(grp_members[j])) {
                        getCurRoutingCfgData(grp_members[j]).arbitrary_phase_angle = phase;
                        parm_list.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).arbitrary_phase_angle});

                        if (!getArbitraryPhaseEnable(grp_members[j])) {
                            getCurRoutingCfgData(grp_members[j]).arbitrary_phase_enable = 1;
                            parm_list_enable.push({key:grp_members[j], val:1});
                        }

                        pairedCh = getPairedBridgeJointChannel(grp_members[j]);
                        if (pairedCh === idx) {
                            continue;
                        }
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).arbitrary_phase_angle = phase;
                            parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).arbitrary_phase_angle});

                            if (!getArbitraryPhaseEnable(pairedCh)) {
                                getCurRoutingCfgData(pairedCh).arbitrary_phase_enable = 1;
                                parm_list_enable.push({key:pairedCh, val:1});
                            }
                        }
                    }
                }
                break;
            //case "non":
            default:
                break;
            }
        }
    }

    getCurRoutingCfgData(idx).arbitrary_phase_angle=phase;
    parm_list.push({key:idx, val:getCurRoutingCfgData(idx).arbitrary_phase_angle});

    pairedCh = getPairedBridgeJointChannel(idx);
    if (pairedCh > -1) {
        getCurRoutingCfgData(pairedCh).arbitrary_phase_angle=phase;
        parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).arbitrary_phase_angle});

        if (!getArbitraryPhaseEnable(pairedCh)) {
            getCurRoutingCfgData(pairedCh).arbitrary_phase_enable = 1;
            parm_list_enable.push({key:pairedCh, val:1});
        }
    }

    if (parm_list_enable.length > 0) {
        devSetMutiChArbitraryPhaseEnable(cb, parm_list_enable);
    }

    return devSetMutiChArbitraryPhaseAngle(cb, parm_list);
}

/* 复位通道列表的任意相位角度 */
function resetAllArbitraryPhaseAngle(cb, output_list)
{
    var pairedCh;
    var parm_list = [];
    var parm_list_enable = [];
    var exclude_list = [];

    for(var i=0;i<output_list.length;i++)
    {
        if (exclude_list.some(function(item) { return output_list[i] === item; })) {
            continue;
        }

        getCurRoutingCfgData(output_list[i]).arbitrary_phase_angle=0;
        parm_list.push({key:output_list[i], val:0});

        pairedCh = getPairedBridgeJointChannel(output_list[i]);
        if (pairedCh > -1) {
            getCurRoutingCfgData(pairedCh).arbitrary_phase_angle=0;
            parm_list.push({key:pairedCh, val:0});
            exclude_list.push(pairedCh);
        }
    }
    return devSetMutiChArbitraryPhaseAngle(cb, parm_list);
}

/* 设置所有已列出通道的任意相位角度 */
function setAllArbitraryPhaseAngle(cb, val_list)
{
    var pairedCh;
    var parm_list = [];
    var parm_list_enable = [];
    var exclude_list = [];

    for(var i=0;i<val_list.length;i++)
    {
        if (exclude_list.some(function(item) { return val_list[i].key === item; })) {
            continue;
        }

        getCurRoutingCfgData(val_list[i].key).arbitrary_phase_angle=val_list[i].val;
        parm_list.push({key:val_list[i].key, val:val_list[i].val});

        if (!getArbitraryPhaseEnable(val_list[i].key)) {
            getCurRoutingCfgData(val_list[i].key).arbitrary_phase_enable = 1;
            parm_list_enable.push({key:val_list[i].key, val:1});
        }

        pairedCh = getPairedBridgeJointChannel(val_list[i].key);
        if (pairedCh > -1) {
            getCurRoutingCfgData(pairedCh).arbitrary_phase_angle=val_list[i].val;
            parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).arbitrary_phase_angle});
            exclude_list.push(pairedCh);

            if (!getArbitraryPhaseEnable(pairedCh)) {
                getCurRoutingCfgData(pairedCh).arbitrary_phase_enable = 1;
                parm_list_enable.push({key:pairedCh, val:1});
            }
        }
    }

    if (parm_list_enable.length > 0) {
        devSetMutiChArbitraryPhaseEnable(cb, parm_list_enable);
    }

    return devSetMutiChArbitraryPhaseAngle(cb, parm_list);
}

/* 重置是否存在Allpass功能模块为指定值 */
