/* 设置通道的低通滤波器Allpass相位角度调节开关(允许相位联调；needCheckValid有效时，要在滤波器设置完成后再调用才能符合实际情况) */
function setLowFilterAllpassEnable(cb, idx, state, needCheckValid, isCorrelate)
