    pairedCh = getPairedBridgeJointChannel(idx);
    if (pairedCh > -1) {
        getCurRoutingCfgData(pairedCh).low_filter_allpass_enable = (desState ? 1 : 0);
        parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).low_filter_allpass_enable});
    }

    devSetMutiChLowFilterAllpassEnable(cb, parm_list);

    return isAnyCheckFailed;
