/* 获取通道的低通滤波器Allpass相位角度 */
function getLowFilterAllpassAngle(idx)
{
    return getCurRoutingCfgData(idx).low_filter_allpass_angle;
}

/* 设置通道的低通滤波器Allpass相位角度 */
function setLowFilterAllpassAngle(cb, idx, phase, isCorrelate)
{
    var pairedCh;
    var parm_list = [];
    var parm_list_enable = [];

    if (isCorrelate != null) {
        if(isCorrelate && (EqCorrelationMode=="abs" || EqCorrelationMode=="rel")) {
            var grp=getGroup(idx);
            var grp_members=getGroupMembers(grp);
            var j;

            switch (EqCorrelationMode) {
            case "rel":
                var delta = phase - getCurRoutingCfgData(idx).low_filter_allpass_angle;
                for (j = 0; j < grp_members.length; j++) {
                    if (grp_members[j] != idx && isLowFilterAllpassValid(grp_members[j])) {
                        var relTmp = phase;
                        if (getLowFilterAllpassEnable(grp_members[j])) {
                            relTmp = getCurRoutingCfgData(grp_members[j]).low_filter_allpass_angle + delta;
                            if (relTmp > 359) {
                                relTmp = 359;
                            } else if (relTmp < 0) {
                                relTmp = 0;
                            }
                        } else {
                            getCurRoutingCfgData(grp_members[j]).low_filter_allpass_enable = 1;
                            parm_list_enable.push({key:grp_members[j], val:1});
                        }

                        getCurRoutingCfgData(grp_members[j]).low_filter_allpass_angle = relTmp;
                        parm_list.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).low_filter_allpass_angle});

                        pairedCh = getPairedBridgeJointChannel(grp_members[j]);
                        if (pairedCh === idx) {
                            continue;
                        }
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).low_filter_allpass_angle = relTmp;
                            parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).low_filter_allpass_angle});

                            if (!getLowFilterAllpassEnable(pairedCh)) {
                                getCurRoutingCfgData(pairedCh).low_filter_allpass_enable = 1;
                                parm_list_enable.push({key:pairedCh, val:1});
                            }
                        }
                    }
                }
                break;
            case "abs":
                for (j = 0; j < grp_members.length; j++) {
                    if (grp_members[j] != idx && isLowFilterAllpassValid(grp_members[j])) {
                        getCurRoutingCfgData(grp_members[j]).low_filter_allpass_angle = phase;
                        parm_list.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).low_filter_allpass_angle});

                        if (!getLowFilterAllpassEnable(grp_members[j])) {
                            getCurRoutingCfgData(grp_members[j]).low_filter_allpass_enable = 1;
                            parm_list_enable.push({key:grp_members[j], val:1});
                        }

                        pairedCh = getPairedBridgeJointChannel(grp_members[j]);
                        if (pairedCh === idx) {
                            continue;
                        }
                        if (pairedCh > -1) {
                            getCurRoutingCfgData(pairedCh).low_filter_allpass_angle = phase;
                            parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).low_filter_allpass_angle});

                            if (!getLowFilterAllpassEnable(pairedCh)) {
                                getCurRoutingCfgData(pairedCh).low_filter_allpass_enable = 1;
                                parm_list_enable.push({key:pairedCh, val:1});
                            }
                        }
                    }
                }
                break;
            //case "non":
            default:
                break;
            }
        }
    }

    getCurRoutingCfgData(idx).low_filter_allpass_angle=phase;
    parm_list.push({key:idx, val:getCurRoutingCfgData(idx).low_filter_allpass_angle});

    pairedCh = getPairedBridgeJointChannel(idx);
    if (pairedCh > -1) {
        getCurRoutingCfgData(pairedCh).low_filter_allpass_angle=phase;
        parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).low_filter_allpass_angle});

        if (!getLowFilterAllpassEnable(pairedCh)) {
            getCurRoutingCfgData(pairedCh).low_filter_allpass_enable = 1;
            parm_list_enable.push({key:pairedCh, val:1});
        }
    }

    if (parm_list_enable.length > 0) {
        devSetMutiChLowFilterAllpassEnable(cb, parm_list_enable);
    }

    return devSetMutiChLowFilterAllpassAngle(cb, parm_list);
}

