/* 高通滤波器Allpass相位调节功能是否有效 */
function isHighFilterAllpassValid(seq)
{
    return true;
}

/* 获取通道的高通滤波器Allpass相位角度调节开关 */
function getHighFilterAllpassEnable(idx)
{
    return (getCurRoutingCfgData(idx).high_filter_allpass_enable? 1 : 0);
}

/* 设置通道的高通滤波器Allpass相位角度调节开关(允许相位联调；needCheckValid有效时，要在滤波器设置完成后再调用才能符合实际情况) */
function setHighFilterAllpassEnable(cb, idx, state, needCheckValid, isCorrelate)
{
    var isAnyCheckFailed = false;
    var desState = state;
    var pairedCh;
    var parm_list = [];

    if (state && needCheckValid && !isHighFilterAllpassValid(idx)) {
        isAnyCheckFailed = true;
        desState = false;
    } else {
        desState = state;
    }

    if (isCorrelate != null) {
        if (isCorrelate && (EqCorrelationMode=="abs" || EqCorrelationMode=="rel")) {
            var grp=getGroup(idx);
            var grp_members=getGroupMembers(grp);

            for (var j = 0; j < grp_members.length; j++) {
                if (grp_members[j] != idx && isHighFilterAllpassValid(grp_members[j])) {
                    getCurRoutingCfgData(grp_members[j]).high_filter_allpass_enable = (desState ? 1 : 0);
                    parm_list.push({key:grp_members[j], val:getCurRoutingCfgData(grp_members[j]).high_filter_allpass_enable});

                    pairedCh = getPairedBridgeJointChannel(grp_members[j]);
                    if (pairedCh === idx) {
                        continue;
                    }
                    if (pairedCh > -1) {
                        getCurRoutingCfgData(pairedCh).high_filter_allpass_enable = (desState ? 1 : 0);
                        parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).high_filter_allpass_enable});
                    }
                }
            }
        }
    }

    getCurRoutingCfgData(idx).high_filter_allpass_enable = (desState ? 1 : 0);
    parm_list.push({key:idx, val:getCurRoutingCfgData(idx).high_filter_allpass_enable});

    pairedCh = getPairedBridgeJointChannel(idx);
    if (pairedCh > -1) {
        getCurRoutingCfgData(pairedCh).high_filter_allpass_enable = (desState ? 1 : 0);
        parm_list.push({key:pairedCh, val:getCurRoutingCfgData(pairedCh).high_filter_allpass_enable});
    }

    devSetMutiChHighFilterAllpassEnable(cb, parm_list);

    return isAnyCheckFailed;
}

