/* 获取以ms为单位的最大输出延时 */
function getMaxDelay_ms()
{
    switch (getDeviceType()) {
    case GDT42:
        if (isInputEQExist()) {
            return 20.00;
        } else {
            return 15.00;
        }
    case GDT46PRO:
        return 15.00;
    case GDT06:
        return 5.00;
    case GDT68:
        if (versionCmp(readDeviceVersion(), "2.1.x") == 0) {
            return 17.00;
        } else {
            return 20.00;
        }
    case GDT68PRO:
    case GDT08:
        if (isInputEQExist()) {
            return 15.00;
        } else {
            return 17.00;
        }
    case VSR6:
        if (isHasKaraokeRoute()) {
            return 17.00;
        } else {
            return 20.00;
        }
    default:
        return 20.00;
    }
}

/* 获取以cm为单位的最大输出延时 */
function getMaxDelay_cm()
{
    switch (getDeviceType()) {
    case GDT42:
        if (isInputEQExist()) {
            return 680.00;
        } else {
            return 510.00;
        }
    case GDT46PRO:
        return 510.00;
    case GDT06:
        return 170.00;
    case GDT68:
        if (versionCmp(readDeviceVersion(), "2.1.x") == 0) {
            return 578.00;
        } else {
            return 680.00;
        }
    case GDT68PRO:
    case GDT08:
        if (isInputEQExist()) {
            return 510.00;
        } else {
            return 578.00;
        }
    case VSR6:
        if (isHasKaraokeRoute()) {
            return 578.00;
        } else {
            return 680.00;
        }
    default:
        return 680.00;
    }
}

/* 获取通道延时 */
function getDelay(idx)
{
    return getCurRoutingCfgData(idx).delay;
}

/* 设置通道延时 */
function setDelay(cb, idx, delay)
{
    var pairedCh;
    var parm_list = [];

    getCurRoutingCfgData(idx).delay = delay;
    parm_list.push({key:idx, val:Math.round(delay * 1000)});

    pairedCh = getPairedBridgeJointChannel(idx);
    if (pairedCh > -1) {
        getCurRoutingCfgData(pairedCh).delay = delay;
        parm_list.push({key:pairedCh, val:Math.round(delay * 1000)});
    }

    return devSetMutiChDelay(cb, getCurrentRouting(), parm_list);
}

/* 复位通道延时 */
function resetAllDelay(cb, output_list)
{
    var pairedCh;
    var parm_list = [];
    var exclude_list = [];

    for(var i=0;i<output_list.length;i++)
    {
        if (exclude_list.some(function(item) { return output_list[i] === item; })) {
            continue;
        }

        getCurRoutingCfgData(output_list[i]).delay=0.00;
        parm_list.push({key:output_list[i], val:0});

        pairedCh = getPairedBridgeJointChannel(output_list[i]);
        if (pairedCh > -1) {
            getCurRoutingCfgData(pairedCh).delay=0.00;
            parm_list.push({key:pairedCh, val:0});
            exclude_list.push(pairedCh);
        }
    }
    return devSetMutiChDelay(cb, getCurrentRouting(), parm_list);
}
/* 设置所有通道延时 */
function setAllDelay(cb, val_list)
{
    var pairedCh;
    var parm_list = [];
    var exclude_list = [];

    for(var i=0;i<val_list.length;i++)
    {
        if (exclude_list.some(function(item) { return val_list[i].key === item; })) {
            continue;
        }

        getCurRoutingCfgData(val_list[i].key).delay=val_list[i].val/1000;
        parm_list.push({key:val_list[i].key, val:val_list[i].val});

        pairedCh = getPairedBridgeJointChannel(val_list[i].key);
        if (pairedCh > -1) {
            getCurRoutingCfgData(pairedCh).delay=val_list[i].val/1000;
            parm_list.push({key:pairedCh, val:val_list[i].val});
            exclude_list.push(pairedCh);
        }
    }
    return devSetMutiChDelay(cb, getCurrentRouting(), parm_list);
}

