function resetAllChVolume(cb, output_list)
{
    var pairedCh;
    var parm_list = [];
    var exclude_list = [];
    var def_vol = /*gainToPercent*/(0); //0dB 最大音量
    for(var i=0;i<output_list.length;i++)
    {
        if (exclude_list.some(function(item) { return output_list[i] === item; })) {
            continue;
        }

        getCurRoutingCfgData(output_list[i]).mute=0;
        getCurRoutingCfgData(output_list[i]).volume=def_vol;
        parm_list.push({key:output_list[i], val:0});

        pairedCh = getPairedBridgeJointChannel(output_list[i]);
        if (pairedCh > -1) {
            getCurRoutingCfgData(pairedCh).mute=0;
            getCurRoutingCfgData(pairedCh).volume=def_vol;
            parm_list.push({key:pairedCh, val:0});
            exclude_list.push(pairedCh);
        }
    }
    devSetMutiChMute(cb, getCurrentRouting(), parm_list);
    return devSetMutiChOutputVolume(cb, getCurrentRouting(), parm_list);
}

/* 将 0~60 转换为 -100dB~0dB */
function percentToVolume(percent) {
    if (percent > 40) { //步进：0.5dB，范围：-9.5dB~0dB
        return ((percent - 40) * 0.5 - 10).toFixed(1);
    } else if (percent > 20) { //步进：1dB，范围：-29dB~-10dB
        return (percent - 50).toFixed(1);
    } else if (percent > 10) { //步进：2dB，范围：-48dB~-30dB
        return ((percent - 10) * 2 - 50).toFixed(1);
    } else if (percent > 5) { //步进：3dB，范围：-62dB~-50dB
        return ((percent - 5) * 3 - 65).toFixed(1);
    } else if (percent > 0) { //步进：5dB，范围：-85dB~-65dB
        return (percent * 5 - 90).toFixed(1);
    } else { //返回：0,范围：-100dB~-90dB
        return (-100).toFixed(1);
    }
}

/* 将 -100dB~0dB 转换为 0~60 */
function volumeToPercent(gain) {
    if (gain > -10) { //范围：41~60
        return Math.floor((gain + 10) * 2 + 40.5);
    } else if (gain > -30) { //范围：21~40
        return Math.floor(gain + 50.5);
    } else if (gain > -50) { //范围：11~20
        return Math.floor((gain + 50) / 2 + 10.5);
    } else if (gain > -65) { //范围：6~10
        return Math.floor((gain + 65) / 3 + 5.5);
    } else if (gain > -90) { //范围：1~5
        return Math.floor((gain + 90) / 5 + 0.5);
    } else { //范围：0
        return 0;
    }
}

/**
 * 将 0~30(步进1) 转换为 -20dB~10dB(步进1dB)
 */
function percentToGain(percent) {
    if (percent >= 30) {
        return (10).toFixed(1);
    } else {
        return (percent - 20).toFixed(1);
    }
}

/**
 * 将 -20dB~10dB(步进1dB) 转换为 0~30(步进1)
 */
function gainToPercent(gain) {
    if (gain >= 10) {
        return Math.floor(30);
    } else if (gain <= -20) {
        return Math.floor(0);
    } else {
        return Math.floor(gain + 20);
    }
}

