function setVolume(cb, idx,val)
{
    var pairedCh;
    var parm_list = [];
    var delta = parseFloat(val) - parseFloat(getCurRoutingCfgData(idx).volume);
    //var isSBAlias = isSBOutputChannels(idx);
    var grp=getGroup(idx);// here idx should equal to grp
    var grp_members=getGroupMembers(grp);
    var gainRange = getOutputGainRange();

    switch(VolCorrelationMode)
    {
    case "rel":
        for(var j=0;j<grp_members.length;j++)
        {
            if (grp_members[j] != idx/* && (!isHasNewFeature() || isSBOutputChannels(grp_members[j]) === isSBAlias)*/) {
                var relTmp = parseFloat(getCurRoutingCfgData(grp_members[j]).volume) + parseFloat(delta);

                /* 限制取值范围为：-20dB~0dB 、-40dB/-20dB~+5dB 或 -40dB/-20dB~+10dB */
                var relMin = gainRange.min, relMax = 0.0;
                if (getDeviceType() === GSR1 && versionCmp(readDeviceVersion(), "1.0.x") == 0 && versionCmp(readFirmwareVersion(), "1.1.0") >= 0) {
                    relMax = 10.0;
                } else if (isHasNewFeature()) {
                    if (isSBOutputChannels(grp_members[j])) {
                        relMax = gainRange.max;
                    } else {
                        if (gainRange.max > 5.0) {
                            relMax = 5.0;
                        } else {
                            relMax = gainRange.max;
                        }
                    }
                }
                if (relTmp > relMax) {
                    relTmp = relMax;
                } else if (relTmp < relMin) {
                    relTmp = relMin;
                }

                getCurRoutingCfgData(grp_members[j]).volume=relTmp;
                parm_list.push({key:grp_members[j], val:/*percentToGain*/(relTmp)});

                pairedCh = getPairedBridgeJointChannel(grp_members[j]);
                if (pairedCh === idx) {
                    continue;
                }
                if (pairedCh > -1) {
                    getCurRoutingCfgData(pairedCh).volume=relTmp;
                    parm_list.push({key:pairedCh, val:/*percentToGain*/(relTmp)});
                }
            }
        }
        break;
    case "abs":
        for(var j=0;j<grp_members.length;j++)
        {
            if (grp_members[j] != idx/* && (!isHasNewFeature() || isSBOutputChannels(grp_members[j]) === isSBAlias)*/) {
                var absTmp = val;
                if (isHasNewFeature()) {
                    /* 限制取值范围为：-20dB~0dB 、-40dB/-20dB~+5dB 或 -40dB/-20dB~+10dB */
                    var absMin = gainRange.min, absMax = 0.0;
                    if (getDeviceType() === GSR1 && versionCmp(readDeviceVersion(), "1.0.x") == 0 && versionCmp(readFirmwareVersion(), "1.1.0") >= 0) {
                        absMax = 10.0;
                    } else if (isHasNewFeature()) {
                        if (isSBOutputChannels(grp_members[j])) {
                            absMax = gainRange.max;
                        } else {
                            if (gainRange.max > 5.0) {
                                absMax = 5.0;
                            } else {
                                absMax = gainRange.max;
                            }
                        }
                    }
                    if (absTmp > absMax) {
                        absTmp = absMax;
                    } else if (absTmp < absMin) {
                        absTmp = absMin;
                    }
                }

                getCurRoutingCfgData(grp_members[j]).volume=absTmp;
                parm_list.push({key:grp_members[j], val:/*percentToGain*/(absTmp)});

                pairedCh = getPairedBridgeJointChannel(grp_members[j]);
                if (pairedCh === idx) {
                    continue;
                }
                if (pairedCh > -1) {
                    getCurRoutingCfgData(pairedCh).volume=absTmp;
                    parm_list.push({key:pairedCh, val:/*percentToGain*/(absTmp)});
                }
            }
        }
        break;
    case "non":
        break;
    }

    getCurRoutingCfgData(idx).volume=val;
    parm_list.push({key:idx, val:val});

    pairedCh = getPairedBridgeJointChannel(idx);
    if (pairedCh > -1) {
        getCurRoutingCfgData(pairedCh).volume=val;
        parm_list.push({key:pairedCh, val:val});
    }

    devSetMutiChOutputVolume(cb, getCurrentRouting(), parm_list);
}

