/* 从数据库及设备删除指定模式 */
function deleteConfigMode(cb, mode)
{
    if (mode >= 0 && mode < getMaxConfigModeCount()) {
        CurrentConfigMode[mode].isValid = 0;
        CurrentConfigMode[mode].isActive = 0;
        CurrentConfigMode[mode].name = "";
        return devDeleteConfig(cb, mode);
    }
}

