/* 用数据库值设置设备所有输出通道的输入源 */
function setAllChSrcByDB(cb, routing, output_list, cfgDevType, cfgDevVersion)
{
    if (routing == DIGITAL && isVSRxSeriesDevice()) {
        return;
    }

    var desRate_0 = isConfigSourceBydB() ? -100.0 : 0;

    var parm_list = [];

    if (output_list == null) {
        output_list = getAllOutputList();
    }

    for(var i = 0; i < output_list.length; i++) {
        var j;
        var val_list = [];
        if (routing == ANALOG) {
            if (isVSRxSeriesDevice()) {
                val_list = [desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0];
                var srcCount2 = getOutputRoutingCfgData(output_list[i], DIGITAL).sources.length
                for(var j2 = 0; j2 < srcCount2; j2++)
                {
                    var srcItem2 = getOutputRoutingCfgData(output_list[i], DIGITAL).sources[j2];
                    var idx2=srcItem2.src + getAnalogSrcLength();
                    if (srcItem2.src != -1) {
                        val_list[idx2] = srcItem2.rate;
                    }
                }
            } else {
                for(j=0;j<getAnalogSrcLength();j++){
                    val_list.push(desRate_0); //模拟输入源
                }
            }
        } else if (routing == BLUETOOTH) {
            val_list = [desRate_0, desRate_0]; //2个蓝牙输入源
        } else if (routing == SPDIF) {
            for(j=0;j<getSpdifSrcLength();j++){
                val_list.push(desRate_0); //SPDIF输入源
            }
        } else if (routing == KARAOKE) {
            for(j=0;j<getKaraokeSrcLength();j++){
                val_list.push(desRate_0); //KARAOKE输入源
            }
        } else if (routing == SOUNDCARD) {
            for(j=0;j<getSoundCardSrcLength();j++){
                val_list.push(desRate_0); //声卡输入源
            }
        } else if (routing == A2B) {
            for(j=0;j<getDynamicA2BSrcLength();j++){
                val_list.push(desRate_0); //A2B输入源
            }
        } else if (routing == SURROUND) {
            for(j=0;j<getSurroundSrcLength();j++){
                val_list.push(desRate_0); //天空全景声输入源
            }
       } else {
            for(j=0;j<getDigitalSrcLength();j++){
                val_list.push(desRate_0); //数字输入源
            }
        }
        if (getRoutingCfgData(output_list[i], routing) == null) {
            return;
        }
        var srcCount = getOutputRoutingCfgData(output_list[i], routing).sources.length
//        console.log("srcCount="+srcCount);
        for(j = 0; j < srcCount; j++)
        {
            /* 避免导入配置时，最大增益值越界 */
            if (isConfigSourceBydB() && getOutputRoutingCfgData(output_list[i], routing).sources[j].rate > getSourceMaxdB(routing)) {
                getOutputRoutingCfgData(output_list[i], routing).sources[j].rate = getSourceMaxdB(routing);
            }

            var srcItem = getOutputRoutingCfgData(output_list[i], routing).sources[j];
//            console.log("srcItem="+srcItem.src+",srcItem.rate="+srcItem.rate);
            var idx=srcItem.src;
            if (srcItem.src != -1) {
                if (routing == A2B) {
                    /* 头枕通道互导时的特殊处理 */
                    if (cfgDevType != null) {
                        var devType = getDeviceType();
                        if (devType == AB218 || devType == AB216_U || devType == AB216_M9) {
                            var fromLessToMore = false; //从少到多
                            var fromMoreToLess = false; //从多到少
                            if (cfgDevVersion == null) {
                                if (devType == AB216_M9) {
                                    cfgDevVersion = "1.0.x";
                                } else {
                                    cfgDevVersion = "1.2.x";
                                }
                            }
                            var devVersion = readDeviceVersion();
                            if (cfgDevType == AB218 && versionCmp(cfgDevVersion, "1.3.x") >= 0 && (cfgDevType != devType || versionCmp(cfgDevVersion, devVersion) > 0)) {
                                fromMoreToLess = true;
                            } else if (devType == AB218 && versionCmp(devVersion, "1.3.x") >= 0 && versionCmp(cfgDevVersion, "1.3.x") < 0) {
                                fromLessToMore = true;
                            }
                            //console.log("fromLessToMore = " + fromLessToMore + ", fromMoreToLess = " + fromMoreToLess);
                            if (fromLessToMore) { //设备为A2B源数量更多的硬件版本，配置文件为A2B源数量较少的硬件版本导出的情况
                                if (srcItem.src > 23 && srcItem.src < 26) {
                                    getOutputRoutingCfgData(output_list[i], routing).sources[j].src += 8;
                                    idx = getOutputRoutingCfgData(output_list[i], routing).sources[j].src;
                                }
                            } else if (fromMoreToLess) { //设备为A2B源数量较少的硬件版本，配置文件为A2B源数量更多的硬件版本导出的情况
                                if (srcItem.src > 31) {
                                    getOutputRoutingCfgData(output_list[i], routing).sources[j].src -= 8;
                                    idx = getOutputRoutingCfgData(output_list[i], routing).sources[j].src;
                                }
                            }
                        }
                    }

                    if (idx >= getDynamicA2BSrcLength()) {
                        getOutputRoutingCfgData(output_list[i], routing).sources[j] = {src:-1, rate:desRate_0, order:-1};
                        continue;
                    }
                } else if (routing == ANALOG) {
                    if(idx>=getHighSrcLength()){
                       idx=idx-getOffset();
                    }
                } else if (isVSRxSeriesDevice() && routing === DIGITAL) {
                    idx += getAnalogSrcLength();
                }
                val_list[idx] = srcItem.rate;
            }
        }
        parm_list.push({key:output_list[i], val:val_list});
    }

    return devSetMutiChSrc(cb, routing, parm_list);
}

/* 用数据库值设置设备所有输出通道的滤波器值 */
function setAllChFilterByDB(cb, routing, filterName, output_list)
{
    var pass_band;
    var parm_list = [];

    if (output_list == null) {
        output_list = getAllOutputList();
    }

    for (var i = 0; i < output_list.length; i++) {
        if (filterName == "H") {
            pass_band = getRoutingCfgData(output_list[i], routing).pass_band.high;
        } else {
            pass_band = getRoutingCfgData(output_list[i], routing).pass_band.low;
        }
        parm_list.push({key:output_list[i], val:[pass_band.bypass?0:1,(pass_band.type * 8 + 1) + pass_band.slope,pass_band.freq]});
    }

    if (filterName == "H") {
        return devSetMutiChHighpass(cb, routing, parm_list);
    } else {
        return devSetMutiChLowpass(cb, routing, parm_list);
    }
}

