/* 用数据库值设置设备所有通道的频率值 */
function setAllChFreqByDB(cb, routing, output_list)
{
    var parm_list = [];

    if (output_list == null) {
        output_list = getAllOutputList();
    }

    for (var i = 0; i < output_list.length; i++) {
        var srcFreqs = getRoutingCfgData(output_list[i], routing).shift_freq;
        var desFreqs = [];
        var cur_frq_bands = getFreqBands(srcFreqs.length);
        for (var j = 0; j < cur_frq_bands.length; j++) {
            desFreqs.push(cur_frq_bands[j] + srcFreqs[j]);
        }
        parm_list.push({key:output_list[i], val:desFreqs});
    }
    return devSetMutiChFreq(cb, routing, parm_list);
}

