/* 用数据库值设置设备所有输出通道的高通滤波器Allpass相位角度调节开关 */
function setAllChHighFilterAllpassEnableByDB(cb, output_list)
{
    var parm_list = [];

    if (output_list == null) {
        output_list = getAllOutputList();
    }

    for (var i = 0; i < output_list.length; i++) {
        parm_list.push({key:output_list[i], val:getRoutingCfgData(output_list[i], ANALOG).high_filter_allpass_enable});
    }
    return devSetMutiChHighFilterAllpassEnable(cb, parm_list);
}

/* 用数据库值设置设备所有输出通道的高通滤波器Allpass相位角度调节开关 */
function setAllChHighFilterAllpassAngleByDB(cb, output_list)
{
    var parm_list = [];

    if (output_list == null) {
        output_list = getAllOutputList();
    }

    for (var i = 0; i < output_list.length; i++) {
        parm_list.push({key:output_list[i], val:getRoutingCfgData(output_list[i], ANALOG).high_filter_allpass_angle});
    }
    return devSetMutiChHighFilterAllpassAngle(cb, parm_list);
}

/* 用数据库值设置设备所有输出通道的相位 */
function setAllChPhaseByDB(cb, routing, output_list)
{
    var parm_list = [];

    if (output_list == null) {
        output_list = getAllOutputList();
    }

    for (var i = 0; i < output_list.length; i++) {
        parm_list.push({key:output_list[i], val:getRoutingCfgData(output_list[i], routing).phase});
    }
    return devSetMutiChPhase(cb, routing, parm_list);
}

/* 将DspCfgData数组中的数据全部设置到设备中（用于PC端导入后的设备设置同步） */
function setAllCfgDataByDB(cb, ignoreBluetoothSrc, cfgDevType, cfgDevVersion)
{
//    var cmdIdx = -1;
//    var minIdx = (DIGITAL < ANALOG)?DIGITAL:ANALOG;
//    var maxIdx = (DIGITAL > ANALOG)?DIGITAL:ANALOG;
//    if (isHasDigitalRoute()) {
//        minIdx = (DIGITAL < ANALOG)?DIGITAL:ANALOG;
//        maxIdx = (DIGITAL > ANALOG)?DIGITAL:ANALOG;
//    } else {
//        minIdx = maxIdx = ANALOG; //仅处理模拟路由
//    }
//    for (var routing = minIdx; routing <= maxIdx; routing++) {
//        if (routing != DIGITAL && routing != ANALOG) {
//            continue; //不是存在的路由则跳过
//        }

        var i = OUTPUTS_GROUPS;
        if (isInputEQExist()) {
            if (isInputDelayExist()) { //支持输入EQ的GDT68PRO、R216等型号不支持输入延时功能
                setAllChInputDelayByDB(cb); //设置设备所有输入通道的延时
            }
            i = STANDARD_INPUTS_GROUPS;
        }

//        if (isHasA2BRoute()) {
//            setAllChInputVolumeByDB(cb); //设置设备所有输入源音量
//        }

        for (; i <= OUTPUTS_GROUPS; i++) {
            setCallbackFun(i);

            if (i == STANDARD_INPUTS_GROUPS || (i == OUTPUTS_GROUPS && isHasAllpassModule())) {
                setAllChEqTypeByDB(cb, getCurrentRouting()); //设置设备所有的EQ类型
                setAllChEqSlopeByDB(cb, getCurrentRouting()); //设置设备所有的EQ斜率
            }

            setAllChFreqByDB(cb, getCurrentRouting()); //设置设备所有的频率值
            setAllChQByDB(cb, getCurrentRouting()); //设置设备所有的Q值
            setAllChGainByDB(cb, getCurrentRouting()); //设置设备所有的EQ值

            if (isHasAllpassModule()) {
                setAllChBypassByDB(cb, getCurrentRouting()); //设置设备所有的EQ直通
            }
        }

        if (isHasAnalogInputAlias()) {
            setAllAnalogInputAliasByDB(cb);
        }
        if (isHasAnalogInputPhase()) {
            setAllAnalogInputPhaseByDB(cb);
        }
        setAllChAliasByDB(cb, ANALOG); //设置设备所有输出通道的别名

        /* 设置输出通道上的输入源 */
        if (isHasDigitalRoute()) {
            setAllChSrcByDB(cb, DIGITAL); //设置设备所有输出通道的数字输入源
        } else {
            clearAllChDigitalSrcInDB(); //清除数据库所有输出通道的蓝牙输入源
        }
        setAllChSrcByDB(cb, ANALOG); //设置设备所有输出通道的模拟输入源
        if (isHasBluetoothModule()) {
            if (ignoreBluetoothSrc) {
                resetAllBluetoothSrc(cb); //复位设备所有输出通道的蓝牙输入源
            } else {
                setAllChSrcByDB(cb, BLUETOOTH); //设置设备所有输出通道的蓝牙输入源
            }
        } else {
            clearAllChBluetoothSrcInDB(); //清除数据库所有输出通道的蓝牙输入源
        }
        if (isVSRxGxHasSpdifRoute()) {
            setAllChSrcByDB(cb, SPDIF); //设置设备所有输出通道的SPDIF输入源
        }
        if (isHasKaraokeRoute()) {
            setAllChSrcByDB(cb, KARAOKE); //设置设备所有输出通道的卡拉OK输入源
        }
        if (isHasSoundCardRoute()) {
            setAllChSrcByDB(cb, SOUNDCARD); //设置设备所有输出通道的声卡输入源
        } else {
            clearAllChSoundCardSrcInDB(); //清除数据库所有输出通道的声卡输入源
        }
        if (isHasA2BRoute()) {
            setAllChSrcByDB(cb, A2B, null, cfgDevType, cfgDevVersion); //设置设备所有输出通道的A2B输入源
        }
        if (isHasSurroundRoute()) {
            setAllChSrcByDB(cb, SURROUND); //设置设备所有输出通道的天空全景声输入源
        } else {
            clearAllChSurroundSrcInDB(); //清除数据库所有输出通道的天空全景声输入源
        }

        setAllChFilterByDB(cb, ANALOG, "H"); //设置设备所有输出通道的高通滤波器
        setAllChFilterByDB(cb, ANALOG, "L"); //设置设备所有输出通道的低通滤波器
        if (isHasAllpassModule()) {
            setAllChLowFilterAllpassEnableByDB(cb);
            setAllChLowFilterAllpassAngleByDB(cb);
            setAllChHighFilterAllpassEnableByDB(cb);
            setAllChHighFilterAllpassAngleByDB(cb);
        }
        setAllChDelayByDB(cb, ANALOG); //设置设备所有输出通道的延时
        setAllChVolumeByDB(cb, ANALOG); //设置设备所有输出通道的通道音量
        setAllChMuteByDB(cb, ANALOG); //设置设备所有输出通道的静音
        if (isAmplifierChannelMuteExist()) {
            setAllChAmplifierChannelMuteByDB(cb); //设置设备所有输出通道的静音
        }
        if (isHasAllpassModule()) {
            setAllChBypassByDB(cb, ANALOG); //设置设备所有输出通道的增益(EQ)直通
        }
//        if(routing == ANALOG){
//            loadLevel(cb);
//        }

        if (isHasArbitraryPhaseAngle()) {
            setAllChArbitraryPhaseAngleByDB(cb);
            setAllChArbitraryPhaseEnableByDB(cb);
        }

        return setAllChPhaseByDB(cb, ANALOG); //设置设备所有输出通道的相位
//    }

//    return cmdIdx;
}

function setVolCorrMode(mode)
{
    VolCorrelationMode=mode;
}

function getVolCorrMode()
{
    return VolCorrelationMode;
}

function setEqCorrMode(mode)
{
    EqCorrelationMode=mode;
}

function getEqCorrMode()
{
    return EqCorrelationMode;
}

/* 是否为联动模式 */
function isCorrelationMode()
{
    return (EqCorrelationMode != "non" || VolCorrelationMode != "non")
}

/* 获取输出通道别名索引 */
function getOutputChAlias(seq)
{
    return getCurRoutingCfgData(seq).aliasIdx;
}

/* 设置输出通道别名索引 */
function setOutputChAlias(cb, seq, aliasIndex)
{
    var pairedCh;
    var parm_list = [];

    getCurRoutingCfgData(seq).aliasIdx = aliasIndex;
    parm_list.push({key:seq, val:aliasIndex});

    pairedCh = getPairedBridgeJointChannel(seq);
    if (pairedCh > -1) {
        getCurRoutingCfgData(pairedCh).aliasIdx = aliasIndex;
        parm_list.push({key:pairedCh, val:aliasIndex});
    }

    return devSetMutiChAlias(cb, getCurrentRouting(), parm_list);
}

function resetAllAlias(cb, output_list)
{
    var pairedCh;
    var parm_list = [];
    var exclude_list = [];

    for(var i=0;i<output_list.length;i++)
    {
        if (exclude_list.some(function(item) { return output_list[i] === item; })) {
            continue;
        }

        getCurRoutingCfgData(output_list[i]).aliasIdx=0;
        parm_list.push({key:output_list[i], val:0});

        pairedCh = getPairedBridgeJointChannel(output_list[i]);
        if (pairedCh > -1) {
            getCurRoutingCfgData(pairedCh).aliasIdx=0;
            parm_list.push({key:pairedCh, val:0});
            exclude_list.push(pairedCh);
        }
    }
    return devSetMutiChAlias(cb, getCurrentRouting(), parm_list);
}

/* 输出通道别名索引是否已被使用 */
function isOutputChAliasInUse(seq, aliasIndex)
{
    if (aliasIndex < 1) {
        return false; //未指定别名，不处理
    }

    for (var i = 0; i < getAllIndepOutputsLength(); i++) {
        if (i != seq) { //不判断当前选中通道
            if (getCurRoutingCfgData(i).aliasIdx == aliasIndex) {
                return true;
            }
        }
    }
    return false;
}

/* 获取对侧与指定别名相同的别名 */
function getOtherSideAlias(aliasIdx)
{
    var otherSideAlias = -1;
    var aliasElements = getPairedAliasElements(aliasIdx);
    if (aliasElements != null && aliasElements.high != null && aliasElements.mid != null && aliasElements.low != null) { //不为空说明别名符合规则，会有对侧别名
        otherSideAlias = aliasIdx + (aliasIdx % 2 ? 1 : -1); //奇为左、偶为右
    }

    return otherSideAlias;
}

/* 获取可与指定别名配对的所有别名 */
function getPairedAliasElements(aliasIdx)
{
    var aliasElements = null;
    var minIdx = 0, maxIdx = 0;

    if (aliasIdx >= 3 && aliasIdx <= 8) { //前置高/中/低
        minIdx = 3;
        maxIdx = 8;
    } else if (aliasIdx >= 15 && aliasIdx <= 20) { //后置高/中/低
        minIdx = 15;
        maxIdx = 20;
    } else if (aliasIdx >= 31 && aliasIdx <= 36) { //环绕高/中/低
        minIdx = 31;
        maxIdx = 36;
    } else if (aliasIdx >= 39 && aliasIdx <= 44) { //后环绕高/中/低
        minIdx = 39;
        maxIdx = 44;
    } else if (aliasIdx >= 47 && aliasIdx <= 52) { //星空环绕高/中/低
        minIdx = 47;
        maxIdx = 52;
    }

    if (minIdx > 0 && maxIdx > 0) {
        var tmpList = [];
        for (var i = (aliasIdx % 2) ? minIdx : minIdx + 1; i <= maxIdx; i += 2) {
//            if (i === aliasIdx) {
//                continue;
//            }
            tmpList.push(i); //将有三个元素，按高、中、低排列
        }
        aliasElements = {high: tmpList[0], mid: tmpList[1], low: tmpList[2]};
    }

    /* 超重低音别名列表的特殊处理 */
    if (aliasIdx == 7 || aliasIdx == 8) {
        aliasElements.subwoofers = [25, 26, 27, 28];
    } else if (aliasIdx >= 25 && aliasIdx <= 28) {
        if (aliasElements == null) {
            aliasElements = {};
        }
        aliasElements.lows = [7, 8];
//        var desList = [];
//        for (var i = 25; i <= 28; i++) {
//            if (aliasIdx != i) {
//                desList.push(i);
//            }
//        }
//        aliasElements.subwoofers = desList;
        aliasElements.subwoofers = [25, 26, 27, 28];
    }

    //console.log("aliasIdx = " + aliasIdx + ", aliasList = " + JSON.stringify(aliasElements));
    return aliasElements;
}

/* 加载输出通道别名对应的滤波器配置 */
function loadOutputAliasFilter(seq, aliasIndex)
{
    return getCurRoutingCfgData(seq).pass_band = deepCopy(getAliasBand(aliasIndex));
}

/* 当前设备是否有别名、相位设置功能 */
function isHasAliasAndPhase() {
    if ((getDeviceType() === GD4 || getDeviceType() === GD6) ||
            (versionCmp(readFirmwareVersion(), "1.3.0") < 0 &&
             ((getDeviceType() === GD10 && versionCmp(readDeviceVersion(), "2.0.0") < 0) ||
             (getDeviceType() === GD16 && versionCmp(readDeviceVersion(), "1.0.1") < 0) ||
             getDeviceType() === GD28 ||
             getDeviceType() === GD46 ||
             getDeviceType() === A5))) {
        return false;
    }
    return true;
}

/* 是否支持模拟输入通道别名 */
function isHasAnalogInputAlias()
{
    if (isDebug || isDemoMode()) {
        return true;
    }

    if (isHasAliasAndPhase()) { //指定的设备型号、固件版本才有别名、相位设置功能
        var inputCount = getAnalogSrcLength();
        for (var i = 0; i < inputCount; i ++) {
            if (AnalogSrcCfgData[i].aliasIdx !== -1) {
                break;
            }
        }
        if (i == inputCount) {
            return false;
        } else {
            return true;
        }
    } else {
        return false;
    }
}

/* 获取模拟输入通道别名 */
function getAnalogInputChAlias(seq)
{
    return AnalogSrcCfgData[seq].aliasIdx;
}

/* 设置模拟输入通道别名 */
function setAnalogInputChAlias(cb, seq, aliasIndex)
{
    AnalogSrcCfgData[seq].aliasIdx = aliasIndex;
    devSetAnalogInputChAlias(cb, seq, aliasIndex);
}

/* 复位模拟输入通道别名 */
function resetAllAnalogInputAlias(cb)
{
    var parm_list = [];
    var inputCount = getAnalogSrcLength();
    for(var i = 0; i < inputCount; i++)
    {
        AnalogSrcCfgData[i].aliasIdx=0;
        parm_list.push({key:i, val:0});
    }
    return devSetAnalogInputMutiChAlias(cb, parm_list);
}

/*模拟输入通道别名索引是否已被使用 */
function isAnalogInputAliasInUse(seq, aliasIndex)
{
    if (aliasIndex < 1) {
        return false; //未指定别名，不处理
    }

    var inputCount = getAnalogSrcLength();
    for (var i = 0; i < inputCount; i++) {
        if (i != seq) { //不判断当前选中通道
            if (AnalogSrcCfgData[i].aliasIdx == aliasIndex) {
                return true;
            }
        }
    }
    return false;
}

/* 是否支持模拟输入通道相位 */
function isHasAnalogInputPhase()
{
    if (isDebug || isDemoMode()) {
        return true;
    }

    if (isHasAliasAndPhase()) { //指定的设备型号、固件版本才有别名、相位设置功能
        var inputCount = getAnalogSrcLength();
        for (var i = 0; i < inputCount; i ++) {
            if (AnalogSrcCfgData[i].phase !== -1) {
                break;
            }
        }
        if (i == inputCount) {
            return false;
        } else {
            return true;
        }
    } else {
        return false;
    }
}

/* 获取模拟输入通道相位 */
function getAnalogInputChPhase(seq)
{
    return AnalogSrcCfgData[seq].phase;
}

/* 设置模拟输入通道相位 */
function setAnalogInputChPhase(cb, seq, isInvert)
{
    AnalogSrcCfgData[seq].phase = isInvert?180:0;
    devSetAnalogInputChPhase(cb, seq, isInvert?180:0);
}

/* 复位模拟输入通道相位 */
function resetAllAnalogInputPhase(cb)
{
    var parm_list = [];
    var inputCount = getAnalogSrcLength();
    for(var i = 0; i < inputCount; i++)
    {
        AnalogSrcCfgData[i].phase=0;
        parm_list.push({key:i, val:0});
    }
    return devSetAnalogInputMutiChPhase(cb, parm_list);
}

/* 失能模拟输入通道别名及相位设置功能 */
function disableAnalogInputAliasAndPhase()
{
    var inputCount = getAnalogSrcLength();
    for(var i = 0; i < inputCount; i++)
    {
        AnalogSrcCfgData[i].aliasIdx=-1;
        AnalogSrcCfgData[i].phase=-1;
    }
}

/* 复位所有DTS配置值 */
function resetAllDtsCfg(cb)
{
    console.log("resetAllDtsCfg called");
    setDtsEnabled(cb, false); //默认DTS为关

    if (isVSRxSeriesDevice()) {
        //setDsdOutputType(cb, 2); //默认DTS输出类型为"2.0"
        setDtsOutputType(cb, 6); //默认DTS虚拟环绕输出类型为"5.1"
    } else {
        setDtsInputType(cb, DIGITAL); //默认DTS输入源类型为数字
        setDtsOutputType(cb, 2); //默认DTS输出类型为"5.1"
        setDtsPcmMode(cb, 2); //默认DTS的PCM模式为"音乐 1"
        setDtsBassMode(cb, 20); //默认DTS低频拐点为"250Hz"
    }
    resetAllDtsAnalogSrcs(cb); //复位DTS模拟输入源
    return resetAllDtsRoutingSrcs(cb); //复位设备所有路由3(即DTS路由)输入源
}

/* 复位所有天空全景声配置值 */
function resetAllSurroundCfg(cb)
{
    console.log("resetAllSurroundCfg called");

    if (getSurroundSrcLength() > 6) {
        setFrontSurroundEnhanceEnable(cb, 0);
        setRearSurroundEnhanceEnable(cb, 0);
    } else {
        setSurroundEnhanceEnable(cb, 0);
    }

    if (getSurroundSrcLength() > 2) {
        setSubHarmEnable(cb, 0);
        setSoundFiledExpandEnable(cb, 0);
        setSoundFiledExpandCutFreq(cb, 1500);
        setSoundFiledExpandGain(cb, -12);
        setTrebleBoostEnable(cb, 0);
        setTrebleBoostGain(cb, 0.5);
        setCenterEnhanceEnable(cb, 0);
        setCenterTrebleBoostEnable(cb, 0);
        setCenterTrebleBoostGain(cb, 0.5);
        setBassBoostEnable(cb, 0);
        setBassBoostFreq(cb, 20);
        setBassBoostGain(cb, 3);
    }

    resetAllSurroundInputPhase(cb);
    resetAllSurroundInputDelay(cb);
    resetAllSurroundInputMute(cb);
    resetAllSurroundInputVolume(cb);
    return resetAllSurroundInputSrc(cb);
}

