    OriginalCarEqEnable = 0; //原车EQ使能状态（失能：0；使能：1；）
    SoundFieldBalanceEnable = 0; //声场平衡使能状态（失能：0；使能：1；）
    /*********************************** 卡拉OK数据库开始（不含卡拉OK输出源路由）***********************************/
