    AccompanySource = 0; //卡拉OK伴奏音源（伴奏左右：0；输入7/8：1；光纤/同轴左右：2；）
    KaraokeMixerGain = [0.0, 0.0, 0.0];//卡拉OK输出增益
    MicInputMixerGain = [0.0, 0.0]; //MIC输入增益
