/* 设备当前配置还原 */
function resetAllCurrentConfigs(cb) {
    var i,j;
    var curCmdIdx = -1;
    var output_list = [];
    var input_list = [];

    for (i = 0; i < getAllIndepOutputsLength(); i++) {
        output_list.push(i);
    }

    setCallbackFun(OUTPUTS_GROUPS); //设置回调为处理输出通道

    curCmdIdx = resetAllAlias(cb, output_list);
    curCmdIdx = resetAllFreqs(cb, output_list);
    curCmdIdx = resetAllQs(cb, output_list);
    curCmdIdx = resetAllGains(cb, output_list);
    if (isHasAllpassModule()) {
        /*curCmdIdx = */resetAllGainRecoveries(output_list);
        curCmdIdx = resetAllEqTypes(cb, output_list);
        curCmdIdx = resetAllEqSlopes(cb, output_list);
        curCmdIdx = resetAllBypass(cb, output_list);
        curCmdIdx = resetAllLowFilterAllpassEnable(cb, output_list);
        curCmdIdx = resetAllLowFilterAllpassAngle(cb, output_list);
        curCmdIdx = resetAllHighFilterAllpassEnable(cb, output_list);
        curCmdIdx = resetAllHighFilterAllpassAngle(cb, output_list);
    }
    curCmdIdx = resetAllHighFilter(cb, output_list);
    curCmdIdx = resetAllLowFilter(cb, output_list);
    if (isAmplifierChannelMuteExist()) {
        curCmdIdx = resetAllChAmplifierChannelMute(cb, output_list);
    }
    curCmdIdx = resetAllChVolume(cb, output_list);
    if (isHasArbitraryPhaseAngle()) {
        curCmdIdx = resetAllArbitraryPhaseEnable(cb, output_list);
        curCmdIdx = resetAllArbitraryPhaseAngle(cb, output_list);
    }
    curCmdIdx = resetAllPhase(cb, output_list);
    curCmdIdx = resetAllDelay(cb, output_list);
    /*curCmdIdx = */resetLevel(cb);
    curCmdIdx = resetAllSrc(cb, output_list);
    if (isHasAnalogInputAlias()) {
        curCmdIdx = resetAllAnalogInputAlias(cb);
    }
    if (isHasAnalogInputPhase()) {
        curCmdIdx = resetAllAnalogInputPhase(cb);
    }
    if (isHasDtsModule()) {
        curCmdIdx = resetAllDtsCfg(cb);
    }
    if (isHasSurroundRoute()) {
        curCmdIdx = resetAllSurroundCfg(cb);
    }

    if (isInputDLCExist()) {
        curCmdIdx = resetAllInputDlcCfg(cb);
    }

    if (isDacFilterShapeExist()) {
        curCmdIdx = setDacFilterShape(cb, 2);
    }

    if (isInputEQExist()) {
        setCallbackFun(STANDARD_INPUTS_GROUPS); //设置回调为处理输入通道
        for (j = 0; j < getAllMembersLength(); j++) {
            input_list.push(j);
        }
        curCmdIdx = resetAllEqTypes(cb, input_list);
        curCmdIdx = resetAllFreqs(cb, input_list);
        curCmdIdx = resetAllQs(cb, input_list);
        curCmdIdx = resetAllEqSlopes(cb, input_list);
        curCmdIdx = resetAllGains(cb, input_list);
        /*curCmdIdx = */resetAllGainRecoveries(input_list);
        if (isHasAllpassModule()) {
            curCmdIdx = resetAllBypass(cb, input_list);
        }

        if (isInputDelayExist()) { //支持输入EQ的GDT68PRO、R216等型号不支持输入延时功能
            curCmdIdx = resetAllInputDelay(cb);
        }
    }

    if (isHasA2BRoute()) {
        //curCmdIdx = resetAllInputVolume(cb);

        if (isOriginalCarEqExist()) {
            curCmdIdx = setOriginalCarEqEnable(cb, 0);
        }

        if (isSoundFieldBalanceExist()) {
            curCmdIdx = setSoundFieldBalanceEnable(cb, 0);
        }
    }

    for (i = STANDARD_INPUTS_GROUPS; i <= OUTPUTS_GROUPS; i++) {
        setCallbackFun(i);

        var ch_list;
        if (i == STANDARD_INPUTS_GROUPS) {
            ch_list = input_list;
        } else {
            ch_list = output_list;
        }

        for (j = 0; j < ch_list.length; j++) {
            if (ch_list[j] != getCurrentMaster()) {
                setGraphDisplay(ch_list[j], 0); //被复位通道默认不显示
            }
        }
    }

    setCallbackFun(getCurrentActiveGroupsFlag()); //设置回调为当前处理的输入或输出通道

    return curCmdIdx;
}


function getPwdCheckedState()
{
    return DevPwdCheckedState;
}

function setPwdCheckedState(state)
{
    DevPwdCheckedState = state;
}

/* DSP直通是否已使能能 */
function isDspBypass()
{
    return (DspBypass && isHasDspBypassModule())?true:false;
}

/* 设置DSP直通使能状态 */
function setDspBypass(cb, state)
{
    DspBypass = state?1:0;
    return devSetDspBypassState(cb, state);
}

/* DTS是否已使能 */
function isDtsEnabled()
{
    return (DtsEnabled && isHasDtsModule() && !(isHasKaraokeRoute() && getKaraokeMode() > 0));
}

/* 设置DTS使能状态 */
function setDtsEnabled(cb, state)
{
    DtsEnabled = state?1:0;
    return devSetDtsEnabledState(cb, state);
}

/* 获取DTS输入源类型（数字：DIGITAL；模拟：ANALOG；） */
function getDtsInputType()
{
    return (isVSRxSeriesDevice() ? ANALOG : DtsInputType);
}

/* 设置DTS输入源类型（数字：DIGITAL；模拟：ANALOG；） */
function setDtsInputType(cb, type)
{
    DtsInputType = type;
    return devSetDtsInputType(cb, type);
}

/* 获取DTS输出类型(1:"5.1"；2"6.1"；3:"7.1") */
function getDtsOutputTypeName()
{
    if (isVSRxSeriesDevice()) {
        switch (DtsOutputType) {
//        case 2:
//            return "2.0";
        case 6:
            return "5.1";
        case 8:
            return "7.1";
        default:
            return "";
        }
    } else {
        switch (DtsOutputType) {
        case 1:
            return "5.1";
        case 2:
            return "6.1";
        case 3:
            return "7.1";
        default:
            return "";
        }
    }
}

