/* 获取DTS输入源指定路由的数据库配置, routingIdx：DIGITAL 数字路由；ANALOG 模拟路由 */
function getDtsSrcCfgData(seq, routingIdx)
{
    if (routingIdx === ANALOG) {
        return DtsSrcCfgData[seq].Analog;
    } else {
        return DtsSrcCfgData[seq].Digital;
    }
}

/* 获取DTS模拟输入源 */
function getDtsInputSrcs(side, routing, srcType)
{
    if(side>=2)
    {
        console.log("getDtsInputSrcs:parameter error!");
        return null;
    }

    var desRate_0 = isConfigSourceBydB() ? -100.0 : 0;

    var retSrc = [];
    var sources;
    if (routing == DIGITAL || routing == ANALOG) {
        var i;
        switch (routing) {
        case ANALOG:
            sources = getDtsSrcCfgData(side, ANALOG).sources;
            for (i = 0; i < sources.length; i++) {
                retSrc.push(sources[i]);
            }
            if (retSrc.length < 4) { //不足4条则补齐
                for (i = retSrc.length; i < 4; i++) {
                    retSrc.push({src:-1, rate:desRate_0, order:-1});
                }
            }
            break;
        case DIGITAL:
            if(isHasDigitalRoute()) {
                sources = getDtsSrcCfgData(side, DIGITAL).sources;
                for (i = 0; i < sources.length; i++) {
                    if (srcType != null) {
                        switch(srcType) {
                        case DIGITAL_SRC_TYPE_FIBER:
                            if (sources[i].src == 2 || sources[i].src == 3) { //光纤源
                                retSrc.push(sources[i]);
                            }
                            break;
                        case DIGITAL_SRC_TYPE_AXIS:
                            if (sources[i].src == 0 || sources[i].src == 1) { //同轴源
                                retSrc.push(sources[i]);
                            }
                            break;
                        }
                    } else {
                        retSrc.push(sources[i]);
                    }
                }
                var maxLength = (srcType != null)?2:sources.length;
                if (retSrc.length < maxLength) { //不足2条则补齐
                    for (i = retSrc.length; i < maxLength; i++) {
                        retSrc.push({src:-1, rate:desRate_0, order:-1});
                    }
                }
            }
            break;
        default:
            return null;
        }
    } else {
        sources = getDtsSrcCfgData(side, ANALOG).sources;
        for (i = 0; i < sources.length; i++) {
            retSrc.push(sources[i]);
        }
        if(isHasDigitalRoute()) {
            sources = getDtsSrcCfgData(side, DIGITAL).sources;
            for (i = 0; i < sources.length; i++) {
                if (srcType != null) {
                    switch(srcType) {
                    case DIGITAL_SRC_TYPE_FIBER:
                        if (sources[i].src == 2 || sources[i].src == 3) { //光纤源
                            retSrc.push(sources[i]);
                        }
                        break;
                    case DIGITAL_SRC_TYPE_AXIS:
                        if (sources[i].src == 0 || sources[i].src == 1) { //同轴源
                            retSrc.push(sources[i]);
                        }
                        break;
                    }
                } else {
                    retSrc.push(sources[i]);
                }
            }
        }
    }

    return retSrc;
}

function dbSetDtsInputChSrc(side,routing,srcs)
{
    if(side>=2)
    {
        console.log("dbSetDtsInputChSrc:parameter side error!"+side);
        return false;
    }

    var desRate_0 = isConfigSourceBydB() ? -100.0 : 0;

    var desSrcs = srcs;
    if(srcs.length != getDtsSrcCfgData(side, routing).sources.length)
    {
        if (routing == DIGITAL && srcs.length == 2) { //源数组中仅包含两个对象时的特殊处理
            /* 保留对立数字源配置值 */
//            var typeSources = getSrc(side, routing, (getCurrentDigitalSrcType(routing) == DIGITAL_SRC_TYPE_FIBER)?DIGITAL_SRC_TYPE_AXIS:DIGITAL_SRC_TYPE_FIBER); //获取对立数字源
//            for(var i = 0; i < srcs.length; i++) {
//                typeSources.push(srcs[i]);
//            }
//            desSrcs = typeSources;
            /* 复制当前数字源配置值至对立数字源 */
            var nAddPos;
            var typeSources = deepCopy(srcs);
            for(var i = 0; i < srcs.length; i++) {
                var item = {src:-1, rate:desRate_0, order:-1};
                if (srcs[i].src != -1) {
                    nAddPos = (srcs[i].src < 2)?2:-2;
                    item.src = srcs[i].src + nAddPos;
                    item.order = srcs[i].order;
                }
                item.rate = srcs[i].rate;
                typeSources.push(item);
            }
            desSrcs = typeSources;
        } else {
            console.error("dbSetDtsInputChSrc:parameter sources error!");
            return false;
        }
    }
    getDtsSrcCfgData(side, routing).sources = desSrcs;
    return true;
}

/* 设置DTS模拟输入源(目前仅设置模拟源) */
function setDtsInputSrcs(cb,side,routing,srcs)
{
    if (dbSetDtsInputChSrc(side, routing, srcs) == false) {
        return;
    }

    setDtsInputSrcsToDev(cb,side,routing,srcs);
}

/* 复位DTS模拟输入源(目前仅设置模拟源) */
function resetAllDtsAnalogSrcs(cb)
{
    var desRate_0 = isConfigSourceBydB() ? -100.0 : 0;
    var desRate_100 = isConfigSourceBydB() ? 0.0 : 100;

    for (var i = 0; i < DtsSrcCfgData.length; i++) {
        var sources=[ //最多4路模拟输入
                     {src:8 + (i%2), rate:desRate_100, order:0},
                     {src:-1, rate:desRate_0, order:-1},
                     {src:-1, rate:desRate_0, order:-1},
                     {src:-1, rate:desRate_0, order:-1}
                ]
        setDtsInputSrcs(cb, i, ANALOG, sources);
    }
}

/* 将DtsSrcCfgData数组中的数据全部设置到设备中（用于PC端导入后的设备设置同步，目前仅设置模拟源、输出通道源） */
function setAllDtsSrcsByDB(cb)
{
    setDtsInputSrcsToDev(cb, 0, ANALOG, getDtsInputSrcs(0, ANALOG, null));
    setDtsInputSrcsToDev(cb, 1, ANALOG, getDtsInputSrcs(1, ANALOG, null));
}

/* 设置DTS模拟输入源至设备(不存储数据库，目前仅设置模拟源) */
function setDtsInputSrcsToDev(cb,side,routing,srcs)
{
    if (routing === ANALOG && levelState != "" && getLevelStateCache().length > 0 && getAnalogSrcLength() < getRealSrcLength()) {
        var desRate_0 = isConfigSourceBydB() ? -100.0 : 0;

        var desSrcs;
        var idx;
        var i, j;
        var maxOrder = -1; //最大排序编号
        var maxOrderIndex = -1; //最大排序编号的条目索引(即当前新增源编号)
        var parm = "";
        var levelIdx;
        var is_dts_analog_src_changed;

        /* 保存修改前的高低电平状态 */
        saveLastLevelStates();

        /* 搜索新增的输入源 */
        for (i = 0; i < srcs.length; i++) {
            if (srcs[i].order > maxOrder) {
                maxOrder = srcs[i].order;
                maxOrderIndex = i;
            }
        }

//        /* 更改可能存在的高低电平互斥标识 */
//        if (maxOrderIndex > -1) {
//            if (srcs[maxOrderIndex].src >= getAnalogSrcLength()) {
//                 idx = srcs[maxOrderIndex].src - offset;
//                if (idx % 2 == 0) {
//                    parm = getLevelParm(idx, idx + 1, LEVEL_LOW);
//                    updLevelState(idx + 1, LEVEL_LOW);
//                } else {
//                    parm = getLevelParm(idx - 1, idx, LEVEL_LOW);
//                    updLevelState(idx - 1, LEVEL_LOW);
//                }
//                updLevelState(idx, LEVEL_LOW);
//                if (parm != "") {
//                    devSetLevelState(cb, parm);
//                }
//            } else {
//                idx = srcs[maxOrderIndex].src
//                if (idx % 2 == 0) {
//                    parm = getLevelParm(idx, idx + 1, LEVEL_HIGH);
//                    updLevelState(idx + 1, LEVEL_HIGH);
//                } else {
//                    parm = getLevelParm(idx - 1, idx, LEVEL_HIGH);
//                    updLevelState(idx - 1, LEVEL_HIGH);
//                }
//                updLevelState(idx, LEVEL_HIGH);
//                if(parm != ""){
//                    devSetLevelState(cb, parm);
//                }
//            }
//        }

        /* 更新所有DTS环绕声源中与新增输入源互斥的输入源的类型 */
        for (i = 0; i < DtsSrcCfgData.length; i++) {
            is_dts_analog_src_changed = false;
            desSrcs = getDtsInputSrcs(i, routing, null);

            if (i === side) {
                var startOrder = 3;
                var reduceCnt = 0;

                for (j = 0; j < desSrcs.length; j++) {
                    if (desSrcs[j].src < 0) {
                        continue;
                    }
                    if(desSrcs[j].src >= getAnalogSrcLength()){//低电平
                        levelIdx = desSrcs[j].src - getOffset();
                        if (getLevelState(levelIdx) != LEVEL_LOW) {
                            desSrcs[j].src = levelIdx;
                            if (desSrcs[j].src == srcs[maxOrderIndex].src && desSrcs[j].order != srcs[maxOrderIndex].order) { //当前主输出通道如果发现同名输入源则清除(后续代码需要进行重排序)
                                startOrder = desSrcs[j].order < startOrder ? desSrcs[j].order : startOrder;
                                reduceCnt++;
                                desSrcs[j].src = -1;
                                desSrcs[j].rate = desRate_0;
                                desSrcs[j].order = -1;
                            }
                            is_dts_analog_src_changed = true;
                        }
                    } else { //高电平
                        levelIdx = desSrcs[j].src;
                        if(getLevelState(levelIdx) != LEVEL_HIGH){
                            desSrcs[j].src = levelIdx + getOffset();
                            if (desSrcs[j].src == srcs[maxOrderIndex].src && desSrcs[j].order != srcs[maxOrderIndex].order) { //当前主输出通道如果发现同名输入源则清除(后续代码需要进行重排序)
                                startOrder = desSrcs[j].order < startOrder ? desSrcs[j].order : startOrder;
                                reduceCnt++;
                                desSrcs[j].src = -1;
                                desSrcs[j].rate = desRate_0;
                                desSrcs[j].order = -1;
                            }
                            is_dts_analog_src_changed = true;
                        }
                    }
                }

                /* 如果需要则进行一次重排序 */
                if (reduceCnt > 0) {
                    /* 为当前路由赋值 */
                    for(j = 0; j< desSrcs.length; j++)
                    {
                        if(desSrcs[j].src != -1) {
                            if (desSrcs[j].order >= startOrder) {
                                desSrcs[j].order -= reduceCnt; //下标向下对齐
                            }
                        }
                    }
                }
            } else {
                for (j = 0; j < desSrcs.length; j++) {
                    if (desSrcs[j].src < 0) {
                        continue;
                    }
                    if(desSrcs[j].src >= getAnalogSrcLength()){//低电平
                        levelIdx = desSrcs[j].src - getOffset();
                        if (getLevelState(levelIdx) != LEVEL_LOW) {
                            desSrcs[j].src = levelIdx;
                            is_dts_analog_src_changed = true;
                        }
                    } else { //高电平
                        levelIdx = desSrcs[j].src;
                        if(getLevelState(levelIdx) != LEVEL_HIGH){
                            desSrcs[j].src = levelIdx + getOffset();
                            is_dts_analog_src_changed = true;
                        }
                    }
                }
            }

            if (is_dts_analog_src_changed) {
                is_dts_analog_src_changed = false;
                dbSetDtsInputChSrc(i, routing, desSrcs);
                pushLevelStateChanged();
            }
        }

        /* 更新所有输出通道中与新增输入源互斥的输入源的类型 */
        var is_analog_src_changed = false;
        for (i = 0; i < getAllIndepOutputsLength(); i++) {
            is_analog_src_changed = false;
            desSrcs = getSrc(i, routing, null);

            for (j = 0; j < desSrcs.length; j++) {
                if (desSrcs[j].src < 0) {
                    continue;
                }
                if(desSrcs[j].src >= getAnalogSrcLength()){//低电平
                    levelIdx = desSrcs[j].src - getOffset();
                    if (getLevelState(levelIdx) != LEVEL_LOW) {
                        desSrcs[j].src = levelIdx;
                        is_analog_src_changed = true;
                    }
                } else { //高电平
                    levelIdx = desSrcs[j].src;
                    if(getLevelState(levelIdx) != LEVEL_HIGH){
                        desSrcs[j].src = levelIdx + getOffset();
                        is_analog_src_changed = true;
                    }
                }
            }

            if (is_analog_src_changed) {
                is_analog_src_changed = false;
                dbSetChSrc(i, routing, desSrcs);
                pushLevelStateChanged();
            }
        }

        /* 发送新输入源配置到设备端 */
        var val_list=[];
        for(i=0;i<getAnalogSrcLength();i++){
            val_list.push(desRate_0);//12路模拟输入源
        }
        desSrcs = getDtsInputSrcs(side, routing, null);
        for (i = 0; i < desSrcs.length; i++) {
            if (desSrcs[i].src > -1) {
                if (routing == ANALOG && desSrcs[i].src >= getAnalogSrcLength()){
                    idx=desSrcs[i].src-offset;
                    val_list[idx] = desSrcs[i].rate;
                } else {
                    idx=desSrcs[i].src
                    val_list[idx] = desSrcs[i].rate;
                }
            }
        }
        devSetDtsChAnalogInputSrc(cb, side, val_list);
    }
}

/* 获取路由3(即DTS路由)输入源 */
function getDtsRoutingSrcs(seq)
{
    if (seq < DspCfgData.length) {
        return DspCfgData[seq].Dts.sources;
    } else if (seq < DspCfgData.length + DspCfgDataExtend.length) {
        return DspCfgDataExtend[seq - DspCfgData.length].Dts.sources;
    } else {
        return DspCfgDataExtend[seq - DspCfgData.length - DspCfgDataExtend.length].Dts.sources;
    }
}

