/* 复位设备所有路由3(即DTS路由)输入源 */
function resetAllDtsRoutingSrcs(cb)
{
    var desRate_100 = isConfigSourceBydB() ? 0.0 : 100;

    var parm_list = [];
    var outCount = getAllIndepOutputsLength();
    var src;
    for(var i = 0; i < outCount; i++) {
        switch (i) {
        case 0:
        case 8:
            src = 0;
            break;
        case 1:
        case 9:
            src = 1;
            break;
        case 2:
        case 10:
            src = 0;
            break;
        case 3:
        case 11:
            src = 1;
            break;
        case 4:
        case 12:
            src = 2;
            break;
        case 5:
        case 13:
            src = 3;
            break;
        case 6:
        case 14:
            src = 4;
            break;
        case 7:
        case 15:
            src = 5;
            break;
        default:
            src = -1;
            break;
        }
        getDtsRoutingSrcs(i)[0].src = src;
        getDtsRoutingSrcs(i)[0].rate = desRate_100;
        getDtsRoutingSrcs(i)[0].order = (src > -1)?0:-1;
        parm_list.push({key:i, val:getDtsRoutingSrcs(i)[0].src>-1?getDtsRoutingSrcs(i)[0].src:-1});
    }
    return devSetDtsRoutingMutiChSrc(cb, parm_list);
}

/* 用数据库值设置设备所有路由3(即DTS路由)输入源 */
function setAllDtsRoutingSrcsByDB(cb)
{
    var parm_list = [];
    var outCount = getAllIndepOutputsLength();
    for(var i = 0; i < outCount; i++) {
        parm_list.push({key:i, val:getDtsRoutingSrcs(i)[0].src>-1?getDtsRoutingSrcs(i)[0].src:-1});
    }
    devSetDtsRoutingMutiChSrc(cb, parm_list);
}

