/* 筛选保留路由3(即DTS路由)所有输出通道的共用输入源(目前各输出通道仅存在一个输入源) */
function filterDtsRoutingSrcs(cb, lastDtsOutputTypeName) {
    var parm_list = [];
    var i;

    if (isVSRxSeriesDevice()) {
        var curDtsOutputTypeName = getDtsOutputTypeName();
        if (curDtsOutputTypeName === lastDtsOutputTypeName) {
            return;
        }

        for (i = 0; i < getAllIndepOutputsLength(); i++) {
            if (curDtsOutputTypeName === "5.1" && lastDtsOutputTypeName === "7.1") {
                if (getOutputCfgData(i).Dts.sources[0].src > 1 && getOutputCfgData(i).Dts.sources[0].src < 4) {
                    getOutputCfgData(i).Dts.sources[0].src += 4;
                    parm_list.push({key:i, val:getOutputCfgData(i).Dts.sources[0].src});
                } else if (getOutputCfgData(i).Dts.sources[0].src > 5 && getOutputCfgData(i).Dts.sources[0].src < 8) {
                    getOutputCfgData(i).Dts.sources[0].src = -1;
                    getOutputCfgData(i).Dts.sources[0].order = -1;
                    parm_list.push({key:i, val:-1});
                }
            } else if (curDtsOutputTypeName === "7.1" && lastDtsOutputTypeName === "5.1") {
                if (getOutputCfgData(i).Dts.sources[0].src > 5 && getOutputCfgData(i).Dts.sources[0].src < 8) {
                    getOutputCfgData(i).Dts.sources[0].src -= 4;
                    parm_list.push({key:i, val:getOutputCfgData(i).Dts.sources[0].src});
                }
            }
        }
    } else {
        for (i = 0; i < getAllIndepOutputsLength(); i++) {
            if (getOutputCfgData(i).Dts.sources[0].src > 5) {
                getOutputCfgData(i).Dts.sources[0].src = -1;
                getOutputCfgData(i).Dts.sources[0].order = -1;
                parm_list.push({key:i, val:-1});
            }
        }
    }

    if (parm_list.length < 1) {
        return -1;
    }
    return devSetDtsRoutingMutiChSrc(cb, parm_list);
}

/* 筛选保留所有输出通道的共用主机输入源(仅适用于VSRx系列型号) */
function filterDsdMasterSrcs(cb, lastDsdOutputTypeName) {
    var curDsdOutputTypeName = getDsdOutputTypeName();
    if (!isVSRxSeriesDevice() || curDsdOutputTypeName === lastDsdOutputTypeName) {
        return;
    }

    var desRate_0 = isConfigSourceBydB() ? -100.0 : 0;

    var parm_list = [];
    var desSrcs;
    var isDesSrcsChanged;
    var idx, j;

    for (var i = 0; i < getAllIndepOutputsLength(); i++) {
        var val_list = [desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0, desRate_0];
        var startOrder = 3;
        var reduceCnt = 0;
        isDesSrcsChanged = false;
        desSrcs = getSrc(i, DIGITAL, null);
        for (j = 0; j < desSrcs.length; j++) {
            if (desSrcs[j].src > -1) {
                if (curDsdOutputTypeName === "5.1") {
                    if (lastDsdOutputTypeName === "7.1") {
                        if (desSrcs[j].src > 1 && desSrcs[j].src < 4) {
                            desSrcs[j].src += 4;
                            idx = desSrcs[j].src + 8;
                            val_list[idx] = desSrcs[j].rate;
                            isDesSrcsChanged = true;
                        } else if (desSrcs[j].src > 5 && desSrcs[j].src < 8) {
                            startOrder = desSrcs[j].order < startOrder ? desSrcs[j].order : startOrder;
                            reduceCnt++;
                            desSrcs[j].src = -1;
                            desSrcs[j].rate = desRate_0;
                            desSrcs[j].order = -1;
                            isDesSrcsChanged = true;
                        } else {
                            idx=desSrcs[j].src + 8;
                            val_list[idx] = desSrcs[j].rate;
                        }
                    } else {
                        idx=desSrcs[j].src + 8;
                        val_list[idx] = desSrcs[j].rate;
                    }
                } else if (curDsdOutputTypeName === "7.1") {
                    if (lastDsdOutputTypeName === "5.1") {
                        if (desSrcs[j].src > 5 && desSrcs[j].src < 8) {
                            desSrcs[j].src -= 4;
                            idx = desSrcs[j].src + 8;
                            val_list[idx] = desSrcs[j].rate;
                            isDesSrcsChanged = true;
                        } else {
                            idx=desSrcs[j].src + 8;
                            val_list[idx] = desSrcs[j].rate;
                        }
                    } else {
                        idx=desSrcs[j].src + 8;
                        val_list[idx] = desSrcs[j].rate;
                    }
                } else {
                    if (desSrcs[j].src > getDsdOutputType() - 1) {
                        startOrder = desSrcs[j].order < startOrder ? desSrcs[j].order : startOrder;
                        reduceCnt++;
                        desSrcs[j].src = -1;
                        desSrcs[j].rate = desRate_0;
                        desSrcs[j].order = -1;
                        isDesSrcsChanged = true;
                    } else {
                        idx=desSrcs[j].src + 8;
                        val_list[idx] = desSrcs[j].rate;
                    }
                }
            }
        }
        if (isDesSrcsChanged) {
            for (j = 0; j < desSrcs.length; j++) {
                if(desSrcs[j].src != -1) {
                    if (desSrcs[j].order >= startOrder) {
                        desSrcs[j].order -= reduceCnt; //下标向下对齐
                    }
                }
            }
            dbSetChSrc(i, DIGITAL, desSrcs);
            var desSrcs2 = getSrc(i, ANALOG, null);
            for (j = 0; j < desSrcs2.length; j++) {
                if(desSrcs2[j].src != -1) {
                    if (desSrcs2[j].order >= startOrder) {
                        desSrcs2[j].order -= reduceCnt; //下标向下对齐
                    }
                }
            }
            dbSetChSrc(i, ANALOG, desSrcs2);
            for (j = 0; j < desSrcs2.length; j++) {
                if (desSrcs2[j].src > -1) {
                    if (desSrcs2[j].src >= getHighSrcLength()){
                        idx=desSrcs2[j].src-offset;
                        val_list[idx] = desSrcs2[j].rate;
                    } else {
                        idx=desSrcs2[j].src;
                        val_list[idx] = desSrcs2[j].rate;
                    }
                }
            }
            parm_list.push({key:i, val:val_list});
        }
    }
    if (parm_list.length < 1) {
        return -1;
    }
    return devSetMutiChSrc(cb, ANALOG, parm_list);
}

