/* 以数据库中的通道索引获取基础输入源（即外接输入源）在命令格式中的通道索引 */
function getBaseInputsCmdLineChannelIdxByDbIdx(idx, routing)
{
    var realIdx = idx;

    if (routing !== ANALOG) {
        realIdx += getAnalogSrcLength();
    }

    return realIdx;
}

/* 以报文中的通道索引获取标准模式输入源（即外接输入源）在数据库中所属的路由，报文中的输入源排序为：模拟 + A2B + 蓝牙 + USB + 独立于DSD主机的SPDIF + 数字/DSD主机 */
function getStandardInputRoutingByChannelIdx(ch, isStaticBluetooth, isStaticSoundcard, isStaticSpdif)
{
    var analogLength = getAnalogSrcLength();
//    var blutoothSrclength = getDynamicBluetoothSrcLength();
    var bluetoothLength = 0;
    var soundCardLength = 0;
    var A2BLength = 0;
    var digitalLength = getStaticDigitalSrcLength();

    if (isHasA2BRoute()) {
        A2BLength = getA2BSrcLength();
    }

    if (isHasBluetoothModule() || (isStaticBluetooth != null && isStaticBluetooth)) {
        bluetoothLength = getStaticBluetoothSrcLength();
    }

    if (isHasSoundCardRoute() || (isStaticSoundcard != null && isStaticSoundcard)) {
        soundCardLength = getStaticDigitalSrcLength();
    }

    if (ch < analogLength) {
        return ANALOG;
    } else if (ch < analogLength + A2BLength) {
        return A2B;
    } else if (ch < analogLength + A2BLength + bluetoothLength) {
        return BLUETOOTH;
    } else if (ch < analogLength + A2BLength + bluetoothLength + soundCardLength) {
        return SOUNDCARD;
    } else if (ch < analogLength + A2BLength + bluetoothLength + soundCardLength + digitalLength) {
        if (isVSRxGxHasSpdifRoute() || (isStaticSpdif != null && isStaticSpdif)) {
            return SPDIF;
        } else {
            return DIGITAL;
        }
    } else {
        if (isVSRxGxHasSpdifRoute() || (isStaticSpdif != null && isStaticSpdif)) {
            return DIGITAL;
        } else {
            return SPDIF;
        }
    }
}

/* 以报文中的通道索引获取标准模式输入源（即外接输入源）在数据库中的索引，报文中的输入源排序为：模拟 + A2B + 蓝牙 + USB + 独立于DSD主机的SPDIF + 数字/DSD主机 */
function getStandardInputDbIndexByChannelIdx(ch, isStaticBluetooth, isStaticSoundcard, isStaticSpdif)
{
    var analogLength = getAnalogSrcLength();
//    var blutoothSrclength = getDynamicBluetoothSrcLength();
    var blutoothSrclength = 0;
    var soundCardLength = 0;
    var A2BLength = 0;
    var digitalLength = getStaticDigitalSrcLength();

    if (isHasA2BRoute()) {
        A2BLength = getA2BSrcLength();
    }

    if (isHasBluetoothModule() || (isStaticBluetooth != null && isStaticBluetooth)) {
        blutoothSrclength = getStaticBluetoothSrcLength();
    }

    if (isHasSoundCardRoute() || (isStaticSoundcard != null && isStaticSoundcard)) {
        soundCardLength = getStaticDigitalSrcLength();
    }

    if (ch < analogLength) {
        return ch;
    } else if (ch < analogLength + A2BLength) {
        return (ch - analogLength);
    } else if (ch < analogLength + A2BLength + blutoothSrclength) {
        return (ch - analogLength - A2BLength);
    } else if (ch < analogLength + A2BLength + blutoothSrclength + soundCardLength) {
        return (ch - analogLength - A2BLength - blutoothSrclength);
    } else if (ch < analogLength + A2BLength + blutoothSrclength + soundCardLength + digitalLength) {
        return (ch - analogLength - A2BLength - blutoothSrclength - soundCardLength);
    } else {
        return (ch - analogLength - A2BLength - blutoothSrclength - soundCardLength - digitalLength);
    }
}

/* 解析当前播放流的信息串 */
function streamInfoParse(streamInfo)
{
    var ch;
    var val;
    var subIndex;
    var infoList = streamInfo.split('?');

    for (var i = 0; i < infoList.length; i++) {
        var router3DesSrcs = [];
        subIndex = infoList[i].indexOf(':');
        ch = parseInt(infoList[i].substring(0, subIndex));
        val = parseInt(infoList[i].substring(subIndex + 1));
        switch (ch) {
        case 1:
            DtsStreamType.stream_type = val;
            break;
        case 2:
            DtsStreamType.stream_channel = val;
            break;
        case 3:
            DtsStreamType.stream_sample = val;
            break;
        }
    }

    return DtsStreamType;
}

