/* 用数据库值设置设备所有卡拉OK输入滤波器值 */
function setAllChKaraokeFilter(cb, filterName, pass_band)
{
    var parm_list = [];

    switch (filterName) {
    case "MicLowpass":
        MicLowpass = pass_band;
        break;
    case "MicHighpass":
        MicHighpass = pass_band;
        break;
    default:
        return;
    }

    var enabled = (pass_band.bypass ? 0 : 1);
    var filterType = (pass_band.type * 8 + 1) + pass_band.slope;

    switch (filterName) {
    case "MicLowpass":
        devSetMicLowpass(cb, enabled, filterType, pass_band.freq);
        break;
    case "MicHighpass":
        devSetMicHighpass(cb, enabled, filterType, pass_band.freq);
        break;
    }
}

