/* 获取与指定通道相配对的输出通道，不存在时返回-1 */
function getPairedBridgeJointChannel(ch)
{
    if (getCurrentActiveCallbackFunsFlag() === OUTPUTS_GROUPS) {
        if (isHasOutputBridgeJointModule()) {
            if (getDeviceType() === R408 || getDeviceType() === R210) {
                if ((getOutputBridgeJoint(1) === 1 && (ch === 6 || ch === 7))) {
                    return (ch + (ch % 2 ? -1 : 1));
                }
            } else if (getDeviceType() === AB212) {
//                if (getUniversalOutputsLength() == 0 || getCurrentOutputsTypeGroup() >= AMP_OUTPUTS_GROUP_1) {
//                    if ((getOutputBridgeJoint(0) === 1 && (ch === 8 || ch === 9)) ||
//                            (getOutputBridgeJoint(1) === 1 && ((ch === 10 || ch === 11)))) {
//                        return (ch + (ch % 2 ? -1 : 1));
//                    }
//                } else {
                    if ((getOutputBridgeJoint(0) === 1 && (ch === 6 || ch === 7)) ||
                            (getOutputBridgeJoint(1) === 1 && ((ch === 8 || ch === 9)))) {
                        return (ch + (ch % 2 ? -1 : 1));
                    }
//                }
            } else if (getDeviceType() === GDT212 || getDeviceType() === R212 || getDeviceType() === GDT216 || getDeviceType() === R216 || getDeviceType() === R316 || getDeviceType() === A6 || getDeviceType() === AB216_D9 || getDeviceType() === AB216_M9 || getDeviceType() === AB216_U || getDeviceType() === AB218 || getDeviceType() === AB218_TANK) {
                if ((getOutputBridgeJoint(0) === 1 && (ch === 8 || ch === 9)) ||
                        (getOutputBridgeJoint(1) === 1 && ((ch === 10 || ch === 11)))) {
                    return (ch + (ch % 2 ? -1 : 1));
                }
            } else if (getDeviceType() === R336) {
                if ((getOutputBridgeJoint(0) === 1 && (ch === 12 || ch === 13)) ||
                        (getOutputBridgeJoint(1) === 1 && ((ch === 14 || ch === 15)))) {
                    return (ch + (ch % 2 ? -1 : 1));
                }
            }
        }
    }

    return -1;
}

