/* 将当前通道的配置数据复制到被桥接通道上(不含对DspCfgDataExtend的处理) */
function copyOutputBridgeJointChannel(cb, srcCh, desCh)
{
    var pairList = [];
    var parm_list = [];
    var output_list = [];

    if (srcCh == null || desCh == null) {
        if (getDeviceType() === R408 || getDeviceType() === R210) {
            if (getOutputBridgeJoint(1) === 1) {
                srcCh = 6;
                desCh = 7;
                pairList.push({srcCh: srcCh, desCh: desCh});
                output_list.push(desCh);
            }
        } else if (getDeviceType() === AB212) {
            if (getOutputBridgeJoint(0) === 1) {
                srcCh = 6;
                desCh = 7;
                pairList.push({srcCh: srcCh, desCh: desCh});
                output_list.push(desCh);
            }

            if (getOutputBridgeJoint(1) === 1) {
                srcCh = 8;
                desCh = 9;
                pairList.push({srcCh: srcCh, desCh: desCh});
                output_list.push(desCh);
            }
        } else if (getDeviceType() === GDT212 || getDeviceType() === R212 || getDeviceType() === GDT216 || getDeviceType() === R216 || getDeviceType() === R316 || getDeviceType() === A6 || getDeviceType() === AB216_D9 || getDeviceType() === AB216_M9 || getDeviceType() === AB216_U || getDeviceType() === AB218 || getDeviceType() === AB218_TANK) {
            if (getOutputBridgeJoint(0) === 1) {
                srcCh = 8;
                desCh = 9;
                pairList.push({srcCh: srcCh, desCh: desCh});
                output_list.push(desCh);
            }

            if (getOutputBridgeJoint(1) === 1) {
                srcCh = 10;
                desCh = 11;
                pairList.push({srcCh: srcCh, desCh: desCh});
                output_list.push(desCh);
            }
        } else if (getDeviceType() === R336) {
            if (getOutputBridgeJoint(0) === 1) {
                srcCh = 12;
                desCh = 13;
                pairList.push({srcCh: srcCh, desCh: desCh});
                output_list.push(desCh);
            }

            if (getOutputBridgeJoint(1) === 1) {
                srcCh = 14;
                desCh = 15;
                pairList.push({srcCh: srcCh, desCh: desCh});
                output_list.push(desCh);
            }
        }
    } else {
        pairList.push({srcCh: srcCh, desCh: desCh});
        output_list.push(desCh);
    }

    /* 复制配置数据到被桥接输出通道 */
    for (var i = 0; i < pairList.length; i++) {
        resetGroup(pairList[i].desCh); //取消被桥接通道的分组
        //checkRepairCurrentMaster();
//        if (getCurrentMaster() === pairList[i].desCh) {
//            setCurrentMaster(pairList[i].srcCh, true);
//        }

        DspCfgData[pairList[i].desCh].Analog.type = deepCopy(DspCfgData[pairList[i].srcCh].Analog.type);
        //DspCfgData[pairList[i].desCh].Digital.type = deepCopy(DspCfgData[pairList[i].srcCh].Digital.type);

        DspCfgData[pairList[i].desCh].Analog.shift_freq = deepCopy(DspCfgData[pairList[i].srcCh].Analog.shift_freq);
        //DspCfgData[pairList[i].desCh].Digital.shift_freq = deepCopy(DspCfgData[pairList[i].srcCh].Digital.shift_freq);

        DspCfgData[pairList[i].desCh].Analog.gain = deepCopy(DspCfgData[pairList[i].srcCh].Analog.gain);
        //DspCfgData[pairList[i].desCh].Digital.gain = deepCopy(DspCfgData[pairList[i].srcCh].Digital.gain);

        DspCfgData[pairList[i].desCh].Analog.Q = deepCopy(DspCfgData[pairList[i].srcCh].Analog.Q);
        //DspCfgData[pairList[i].desCh].Digital.Q = deepCopy(DspCfgData[pairList[i].srcCh].Digital.Q);

        DspCfgData[pairList[i].desCh].Analog.S = deepCopy(DspCfgData[pairList[i].srcCh].Analog.S);
        //DspCfgData[pairList[i].desCh].Digital.S = deepCopy(DspCfgData[pairList[i].srcCh].Digital.S);

        DspCfgData[pairList[i].desCh].Analog.amp_mute = DspCfgData[pairList[i].srcCh].Analog.amp_mute;

        DspCfgData[pairList[i].desCh].Analog.mute = DspCfgData[pairList[i].srcCh].Analog.mute;
        //DspCfgData[pairList[i].desCh].Digital.mute = DspCfgData[pairList[i].srcCh].Digital.mute;

        DspCfgData[pairList[i].desCh].Analog.volume = DspCfgData[pairList[i].srcCh].Analog.volume;
        //DspCfgData[pairList[i].desCh].Digital.volume = DspCfgData[pairList[i].srcCh].Digital.volume;

        DspCfgData[pairList[i].desCh].Analog.pass_band.high = deepCopy(DspCfgData[pairList[i].srcCh].Analog.pass_band.high);
        //DspCfgData[pairList[i].desCh].Digital.pass_band.high = deepCopy(DspCfgData[pairList[i].srcCh].Digital.pass_band.high);

        DspCfgData[pairList[i].desCh].Analog.pass_band.low = deepCopy(DspCfgData[pairList[i].srcCh].Analog.pass_band.low);
        //DspCfgData[pairList[i].desCh].Digital.pass_band.low = deepCopy(DspCfgData[pairList[i].srcCh].Digital.pass_band.low);

        //DspCfgData[pairList[i].desCh].Analog.phase = (DspCfgData[pairList[i].srcCh].Analog.phase ? 0 : 180); //被桥接通道需反相
        DspCfgData[pairList[i].desCh].Analog.phase = DspCfgData[pairList[i].srcCh].Analog.phase;
        //DspCfgData[pairList[i].desCh].Digital.phase = DspCfgData[pairList[i].srcCh].Digital.phase;

        DspCfgData[pairList[i].desCh].Analog.delay = DspCfgData[pairList[i].srcCh].Analog.delay;
        //DspCfgData[pairList[i].desCh].Digital.delay = DspCfgData[pairList[i].srcCh].Digital.delay;

        DspCfgData[pairList[i].desCh].Analog.aliasIdx = DspCfgData[pairList[i].srcCh].Analog.aliasIdx;
        //DspCfgData[pairList[i].desCh].Digital.aliasIdx = DspCfgData[pairList[i].srcCh].Digital.aliasIdx;

        //DspCfgData[pairList[i].desCh].Analog.groups = pairList[i].desCh; //已经被取消分组，不需要再赋值
        //DspCfgData[pairList[i].desCh].Digital.groups = pairList[i].desCh;

        DspCfgData[pairList[i].desCh].Analog.bypass = DspCfgData[pairList[i].srcCh].Analog.bypass;
        //DspCfgData[pairList[i].desCh].Digital.bypass = DspCfgData[pairList[i].srcCh].Digital.bypass;

        DspCfgData[pairList[i].desCh].Analog.arbitrary_phase_enable = DspCfgData[pairList[i].srcCh].Analog.arbitrary_phase_enable;
        //DspCfgData[pairList[i].desCh].Digital.arbitrary_phase_enable = DspCfgData[pairList[i].srcCh].Digital.arbitrary_phase_enable;

        DspCfgData[pairList[i].desCh].Analog.arbitrary_phase_angle = DspCfgData[pairList[i].srcCh].Analog.arbitrary_phase_angle;
        //DspCfgData[pairList[i].desCh].Digital.arbitrary_phase_angle = DspCfgData[pairList[i].srcCh].Digital.arbitrary_phase_angle;

        DspCfgData[pairList[i].desCh].Analog.low_filter_allpass_enable = DspCfgData[pairList[i].srcCh].Analog.low_filter_allpass_enable;
        //DspCfgData[pairList[i].desCh].Digital.low_filter_allpass_enable = DspCfgData[pairList[i].srcCh].Digital.low_filter_allpass_enable;

        DspCfgData[pairList[i].desCh].Analog.low_filter_allpass_angle = DspCfgData[pairList[i].srcCh].Analog.low_filter_allpass_angle;
        //DspCfgData[pairList[i].desCh].Digital.low_filter_allpass_angle = DspCfgData[pairList[i].srcCh].Digital.low_filter_allpass_angle;

        DspCfgData[pairList[i].desCh].Analog.high_filter_allpass_enable = DspCfgData[pairList[i].srcCh].Analog.high_filter_allpass_enable;
        //DspCfgData[pairList[i].desCh].Digital.high_filter_allpass_enable = DspCfgData[pairList[i].srcCh].Digital.high_filter_allpass_enable;

        DspCfgData[pairList[i].desCh].Analog.high_filter_allpass_angle = DspCfgData[pairList[i].srcCh].Analog.high_filter_allpass_angle;
        //DspCfgData[pairList[i].desCh].Digital.high_filter_allpass_angle = DspCfgData[pairList[i].srcCh].Digital.high_filter_allpass_angle;

        //DspCfgData[pairList[i].desCh].Analog.graph = 0; //不显示被桥接通道的图形
        //DspCfgData[pairList[i].desCh].Digital.graph = 0;

        DspCfgData[pairList[i].desCh].Analog.sources = deepCopy(DspCfgData[pairList[i].srcCh].Analog.sources);
        DspCfgData[pairList[i].desCh].Digital.sources = deepCopy(DspCfgData[pairList[i].srcCh].Digital.sources);
        DspCfgData[pairList[i].desCh].Dts.sources = deepCopy(DspCfgData[pairList[i].srcCh].Dts.sources);
        DspCfgData[pairList[i].desCh].Bluetooth.sources = deepCopy(DspCfgData[pairList[i].srcCh].Bluetooth.sources);
        DspCfgData[pairList[i].desCh].Spdif.sources = deepCopy(DspCfgData[pairList[i].srcCh].Spdif.sources);
        DspCfgData[pairList[i].desCh].Karaoke.sources = deepCopy(DspCfgData[pairList[i].srcCh].Karaoke.sources);
        DspCfgData[pairList[i].desCh].SoundCard.sources = deepCopy(DspCfgData[pairList[i].srcCh].SoundCard.sources);
        DspCfgData[pairList[i].desCh].A2B.sources = deepCopy(DspCfgData[pairList[i].srcCh].A2B.sources);
        DspCfgData[pairList[i].desCh].Surround.sources = deepCopy(DspCfgData[pairList[i].srcCh].Surround.sources);
        //DtsSrcCfgData[pairList[i].desCh].Analog.sources = deepCopy(DtsSrcCfgData[pairList[i].srcCh].Analog.sources);
        //DtsSrcCfgData[pairList[i].desCh].Digital.sources = deepCopy(DtsSrcCfgData[pairList[i].srcCh].Digital.sources);

        OutputEqGraphData[pairList[i].desCh] = deepCopy(OutputEqGraphData[pairList[i].srcCh]);
    }

    /* 将新配置数据写入设备 */
    if (output_list.length > 0) {
        setAllChAliasByDB(cb, ANALOG, output_list); //设置设备所有输出通道的别名
        if (isHasDigitalRoute()) {
            setAllChSrcByDB(cb, DIGITAL, output_list); //设置设备所有输出通道的数字输入源
        }
        setAllChSrcByDB(cb, ANALOG, output_list); //设置设备所有输出通道的模拟输入源
        if (isHasBluetoothModule()) {
            setAllChSrcByDB(cb, BLUETOOTH, output_list); //设置设备所有输出通道的蓝牙输入源
        }
        if (isVSRxGxHasSpdifRoute()) {
            setAllChSrcByDB(cb, SPDIF, output_list); //设置设备所有输出通道的SPDIF输入源
        }
        if (isHasKaraokeRoute()) {
            setAllChSrcByDB(cb, KARAOKE, output_list); //设置设备所有输出通道的卡拉OK输入源
        }
        if (isHasSoundCardRoute()) {
            setAllChSrcByDB(cb, SOUNDCARD, output_list); //设置设备所有输出通道的声卡输入源
        }
        if (isHasA2BRoute()) {
            setAllChSrcByDB(cb, A2B, output_list); //设置设备所有输出通道的A2B输入源
        }
        if (isHasSurroundRoute()) {
            setAllChSrcByDB(cb, SURROUND, output_list); //设置设备所有输出通道的天空全景声输入源
        }
        setAllChFilterByDB(cb, ANALOG, "H", output_list); //设置设备所有输出通道的高通滤波器
        setAllChFilterByDB(cb, ANALOG, "L", output_list); //设置设备所有输出通道的低通滤波器
        setAllChFreqByDB(cb, ANALOG, output_list); //设置设备所有输出通道的频率值
        setAllChQByDB(cb, ANALOG, output_list); //设置设备所有输出通道的Q值
        setAllChGainByDB(cb, ANALOG, output_list); //设置设备所有输出通道的EQ值
        if (isHasAllpassModule()) {
            setAllChEqSlopeByDB(cb, getCurrentRouting(), output_list); //设置设备所有的EQ斜率
            setAllChEqTypeByDB(cb, getCurrentRouting(), output_list); //设置设备所有的EQ类型
            setAllChBypassByDB(cb, getCurrentRouting(), output_list); //设置设备所有的EQ直通
            setAllChLowFilterAllpassEnableByDB(cb, output_list); //设置设备所有输出通道的低通滤波器Allpass相位角度调节开关
            setAllChLowFilterAllpassAngleByDB(cb, output_list); //设置设备所有输出通道的低通滤波器Allpass相位角度
            setAllChHighFilterAllpassEnableByDB(cb, output_list); //设置设备所有输出通道的高通滤波器Allpass相位角度调节开关
            setAllChHighFilterAllpassAngleByDB(cb, output_list); //设置设备所有输出通道的高通滤波器Allpass相位角度
        }
        setAllChDelayByDB(cb, ANALOG, output_list); //设置设备所有输出通道的延时
        setAllChVolumeByDB(cb, ANALOG, output_list); //设置设备所有输出通道的通道音量
        setAllChMuteByDB(cb, ANALOG, output_list); //设置设备所有输出通道的静音
        if (isAmplifierChannelMuteExist()) {
            setAllChAmplifierChannelMuteByDB(cb, output_list); //设置设备所有输出通道的静音
        }

        //loadLevel(cb);

        if (isHasArbitraryPhaseAngle()) {
            setAllChArbitraryPhaseAngleByDB(cb, output_list);
            setAllChArbitraryPhaseEnableByDB(cb, output_list);
        }

        return setAllChPhaseByDB(cb, ANALOG, output_list); //设置设备所有输出通道的相位
    }
}

/* 重置是否用dB值设置输入源为指定值 */
function resetConfigSourceBydB(state)
{
    ConfigSourceBydB = state;
}

