{
    return ConfigSourceBydB;
}

/* 重置是否用dB值设置输入源为指定值 */
function resetSourceMaxdB(value)
{
    SourceMaxdB = value;
}

/* 用dB值设置输入源的最大值 */
function getSourceMaxdB(routing)
{
    if (routing != null) {
        switch (routing) {
        case ANALOG:
            if (isForCDT()) {
                return 0.0;
            } else {
                if (getDeviceType() == G2_PRO && versionCmp(readDeviceVersion(), "1.0.1") == 0 && getFirmwareCode() < 10024) {
                    return 0.0; //指定型号的指定版本有问题，最大值只能达到0.0dB
                }
                return 12.0;
            }
        case DIGITAL:
            if (isHasDSDSources(getDeviceType())) {
                return 0.0;
            }
            break;
        default:
            break;
        }
    }

    return SourceMaxdB;
}

