/* 获取输出通道指定路由的数据库配置 */
function getDspBaseInputsDlcCfgData(routingIdx)
{
    if (routingIdx === ANALOG) {
        return DspBaseInputsDlcCfgData.Analog;
    } else if (routingIdx === DIGITAL) {
        return DspBaseInputsDlcCfgData.Digital;
    } else if (routingIdx === BLUETOOTH) {
        return DspBaseInputsDlcCfgData.Bluetooth;
    } else if (routingIdx === SPDIF) {
        return DspBaseInputsDlcCfgData.Spdif;
//    } else if (routingIdx === KARAOKE) {
//        return DspBaseInputsDlcCfgData.Karaoke;
    } else if (routingIdx === SOUNDCARD) {
        return DspBaseInputsDlcCfgData.SoundCard;
    } else if (routingIdx === A2B) {
        return DspBaseInputsDlcCfgData.A2B;
//    } else if (routingIdx === SURROUND) {
//        return DspBaseInputsDlcCfgData.Surround;
    } else {
        return null;
    }
}

/* 获取输入通道动态等响度调节(DLC)的使能状态 */
function getInputDLCEnable(routing)
{
    return getDspBaseInputsDlcCfgData(routing).enable ? true : false;
}

/* 设置输入通道动态等响度调节(DLC)的使能状态 */
function setInputDLCEnable(cb, routing, state)
{
    getDspBaseInputsDlcCfgData(routing).enable = state ? 1 : 0;
    return devSetInputDLCEnable(cb, routing, getDspBaseInputsDlcCfgData(routing).enable);
}

