/* 复位设备所有动态等响度调节(DLC)配置 */
function resetAllInputDlcCfg(cb)
{
    console.log("resetAllInputDlcCfg called");

    var cmdIdx = -1;
    var routingList = [];
    if (isHasDigitalRoute()) {
        routingList.push(DIGITAL);
    }
    routingList.push(ANALOG); //默认仅处理模拟路由
    if (isHasBluetoothModule()) {
        routingList.push(BLUETOOTH);
    }
    if (isVSRxGxHasSpdifRoute()) {
        routingList.push(SPDIF);
    }
    if (isHasSoundCardRoute()) {
        routingList.push(SOUNDCARD);
    }
    if (isHasA2BRoute()) {
        routingList.push(A2B);
    }

    for (var routingIdx = 0; routingIdx < routingList.length; routingIdx++) {
        getDspBaseInputsDlcCfgData(routingList[routingIdx]).enable = 0;
        devSetInputDLCEnable(cb, routingList[routingIdx], getDspBaseInputsDlcCfgData(routingList[routingIdx]).enable);

        var parm_lowShelf = getDspBaseInputsDlcCfgData(routingList[routingIdx]).lowShelf;
        parm_lowShelf.frequency = 100;
        parm_lowShelf.lowGain = 0.0;
        parm_lowShelf.highGain = 0.0;
        devSetInputDLCLowShelf(cb, routingList[routingIdx], parm_lowShelf.frequency, parm_lowShelf.lowGain, parm_lowShelf.highGain);

        var parm_highShelf = getDspBaseInputsDlcCfgData(routingList[routingIdx]).highShelf;
        parm_highShelf.frequency = 5000;
        parm_highShelf.lowGain = 0.0;
        parm_highShelf.highGain = 0.0;
        devSetInputDLCHighShelf(cb, routingList[routingIdx], parm_highShelf.frequency, parm_highShelf.lowGain, parm_highShelf.highGain);

        var parm_threshold = getDspBaseInputsDlcCfgData(routingList[routingIdx]).threshold;
        parm_threshold.lowThreshold = -50.0;
        parm_threshold.highThreshold = -10.0;
        cmdIdx = devSetInputDLCThreshold(cb, routingList[routingIdx], parm_threshold.lowThreshold, parm_threshold.highThreshold);
    }

    return cmdIdx;
}

/* 用数据库值设置设备所有动态等响度调节(DLC)配置 */
function setAllInputDlcCfgByDB(cb)
{
    var cmdIdx = -1;
    var routingList = [];
    if (isHasDigitalRoute()) {
        routingList.push(DIGITAL);
    }
    routingList.push(ANALOG); //默认仅处理模拟路由
    if (isHasBluetoothModule()) {
        routingList.push(BLUETOOTH);
    }
    if (isVSRxGxHasSpdifRoute()) {
        routingList.push(SPDIF);
    }
    if (isHasSoundCardRoute()) {
        routingList.push(SOUNDCARD);
    }
    if (isHasA2BRoute()) {
        routingList.push(A2B);
    }

    for (var routingIdx = 0; routingIdx < routingList.length; routingIdx++) {
        devSetInputDLCEnable(cb, routingList[routingIdx], getDspBaseInputsDlcCfgData(routingList[routingIdx]).enable);
        var parm_lowShelf = getDspBaseInputsDlcCfgData(routingList[routingIdx]).lowShelf;
        devSetInputDLCLowShelf(cb, routingList[routingIdx], parm_lowShelf.frequency, parm_lowShelf.lowGain, parm_lowShelf.highGain);
        var parm_highShelf = getDspBaseInputsDlcCfgData(routingList[routingIdx]).highShelf;
        devSetInputDLCHighShelf(cb, routingList[routingIdx], parm_highShelf.frequency, parm_highShelf.lowGain, parm_highShelf.highGain);
        var parm_threshold = getDspBaseInputsDlcCfgData(routingList[routingIdx]).threshold;
        cmdIdx = devSetInputDLCThreshold(cb, routingList[routingIdx], parm_threshold.lowThreshold, parm_threshold.highThreshold);
    }

    return cmdIdx;
}

function getInputDLCShelfGraphData(routingIdx)
{
    if (routingIdx === ANALOG) {
        return InputDLCShelfGraphData.Analog;
    } else if (routingIdx === DIGITAL) {
        return InputDLCShelfGraphData.Digital;
    } else if (routingIdx === BLUETOOTH) {
        return InputDLCShelfGraphData.Bluetooth;
    } else if (routingIdx === SPDIF) {
        return InputDLCShelfGraphData.Spdif;
//    } else if (routingIdx === KARAOKE) {
//        return InputDLCShelfGraphData.Karaoke;
    } else if (routingIdx === SOUNDCARD) {
        return InputDLCShelfGraphData.SoundCard;
    } else if (routingIdx === A2B) {
        return InputDLCShelfGraphData.A2B;
//    } else if (routingIdx === SURROUND) {
//        return InputDLCShelfGraphData.Surround;
    } else {
        return null;
    }
}

