function resetAmplifierChannelMuteExist(state)
{
    AmplifierChannelMuteExist = state;
}

/* 获取是否存在通道功放静音功能 */
function isAmplifierChannelMuteExist()
{
    return AmplifierChannelMuteExist;
}

/* 获取当前输出的功放分组下是否有功放被静音 */
function isAnyAmplifierChannelMute()
{
    if (isAmplifierChannelMuteExist() && getCurrentActiveGroupsFlag() === OUTPUTS_GROUPS && (getUniversalOutputsLength() == 0 || getCurrentOutputsTypeGroup() == AMP_OUTPUTS_GROUP_1 || getCurrentOutputsTypeGroup() == AMP_OUTPUTS_GROUP_2)) {
        for (var i = 0; i < getOutputsLength(); i++) {
            if ((getUniversalOutputsLength() == 0 || getCurrentOutputsTypeGroup() == AMP_OUTPUTS_GROUP_1) && isInBridgeJointChannels(i)) {
                continue;
            }
            if (getCurRoutingCfgData(getCmdLineIdxByViewIdx(i)).amp_mute) {
                return true;
            }
        }
    }

    return false;
}
