/* 获取通道功放静音 */
function getAmplifierChannelMute(idx)
{
    if ((getUniversalOutputsLength() == 0 || (idx >= getUniversalOutputsLength() || isInSharedChannels(idx))) && !isInBridgeJointChannels(idx)) {
        return getCurRoutingCfgData(idx).amp_mute;
    } else {
        return 0;
    }
}

