function setMutiChAmplifierChannelMute(cb, output_list, mute)
{
    var pairedCh;
    var parm_list = [];
    var exclude_list = [];
    var state = mute?1:0;

    for(var i=0;i<output_list.length;i++)
    {
        if ((getUniversalOutputsLength() == 0 || (output_list[i] >= getUniversalOutputsLength() || isInSharedChannels(output_list[i]))) && !isInBridgeJointChannels(output_list[i])) {
            if (exclude_list.some(function(item) { return output_list[i] === item; })) {
                continue;
            }

            getCurRoutingCfgData(output_list[i]).amp_mute=state;
            parm_list.push({key:output_list[i], val:state});

            pairedCh = getPairedBridgeJointChannel(output_list[i]);
            if (pairedCh > -1) {
                getCurRoutingCfgData(pairedCh).amp_mute=state;
                parm_list.push({key:pairedCh, val:state});
                exclude_list.push(pairedCh);
            }
        }
    }
    return devSetMutiChAmplifierChannelMute(cb, parm_list);
}

/* 用数据库值设置设备所有输出通道的功放静音 */
function setAllChAmplifierChannelMuteByDB(cb, output_list)
{
    var parm_list = [];

    if (output_list == null) {
        output_list = getAllOutputList();
    }

    for (var i = 0; i < output_list.length; i++) {
        if ((getUniversalOutputsLength() == 0 || (output_list[i] >= getUniversalOutputsLength() || isInSharedChannels(output_list[i]))) && !isInBridgeJointChannels(output_list[i])) {
            parm_list.push({key:output_list[i], val:getCurRoutingCfgData(output_list[i]).amp_mute});
        }
    }
    return devSetMutiChAmplifierChannelMute(cb, parm_list);
}

function resetAllChAmplifierChannelMute(cb, output_list)
{
    var pairedCh;
    var parm_list = [];
    var exclude_list = [];
    for(var i=0;i<output_list.length;i++)
    {
        if ((getUniversalOutputsLength() == 0 || (output_list[i] >= getUniversalOutputsLength() || isInSharedChannels(output_list[i]))) && !isInBridgeJointChannels(output_list[i])) {
            if (exclude_list.some(function(item) { return output_list[i] === item; })) {
                continue;
            }

            getCurRoutingCfgData(output_list[i]).amp_mute=1;
            parm_list.push({key:output_list[i], val:1});

            pairedCh = getPairedBridgeJointChannel(output_list[i]);
            if (pairedCh > -1) {
                getCurRoutingCfgData(pairedCh).amp_mute=1;
                parm_list.push({key:pairedCh, val:1});
                exclude_list.push(pairedCh);
            }
        }
    }
    return devSetMutiChAmplifierChannelMute(cb, parm_list);
}

